let currentTournamentLogoData = null;

/**
 * ═══════════════════════════════════════════════════════════════════════════
 * TOURNAMENT MANAGEMENT
 * ═══════════════════════════════════════════════════════════════════════════
 *
 * ROUTE: Dashboard → "Select Tournament" dropdown → New Tournament button
 *
 * FLOW:
 * 1. showTournamentForm() - Opens modal
 * 2. User fills form (name, date, location, logo)
 * 3. Form submission → Creates tournament → Saves to localStorage
 * 4. switchTournament() - Loads tournament data
 *
 * DATA STRUCTURE:
 * tournaments[] = [{
 *   id: timestamp,
 *   name: string,
 *   date: string,
 *   location: string,
 *   logo: base64 string (optional)
 * }]
 *
 * ⚠️ CRITICAL BUG: Tournament switching doesn't isolate data!
 * - All competitors, divisions, brackets are GLOBAL
 * - currentTournamentId is set but never used for data scoping
 * - Multiple tournaments will have data collisions
 *
 * 📝 TODO: Implement tournament-scoped data (prefix all keys with tournamentId)
 *
 * Last Updated: 2026-02-13
 * ═══════════════════════════════════════════════════════════════════════════
 */

/**
 * ═══════════════════════════════════════════════════════════════════════════
 * SANCTIONING BODY DEFAULTS
 * ═══════════════════════════════════════════════════════════════════════════
 *
 * Provides WKF, AAU, and custom defaults for:
 * - Corner names (AKA/SHIRO vs RED/WHITE)
 * - Corner colors (WKF uses red/blue, AAU uses red/white)
 * - Age calculation method (WKF: Dec 31st, AAU: event date)
 *
 * Last Updated: 2026-02-14
 * ═══════════════════════════════════════════════════════════════════════════
 */

function getSanctioningBodyDefaults(sanctioningBody) {
    const defaults = {
        'wkf': {
            corner1Name: 'AKA',
            corner2Name: 'SHIRO',
            corner1Color: '#ff3b30', // Red
            corner2Color: '#0a84ff', // Blue
            ageCalculationMethod: 'wkf-standard',
            ageCalculationDescription: 'Age as of December 31st of competition year'
        },
        'aau': {
            corner1Name: 'RED',
            corner2Name: 'WHITE',
            corner1Color: '#ff3b30', // Red
            corner2Color: '#ffffff', // White
            ageCalculationMethod: 'aau-standard',
            ageCalculationDescription: 'Age on day of competition'
        },
        'custom': {
            corner1Name: 'RED',
            corner2Name: 'BLUE',
            corner1Color: '#ff3b30', // Red
            corner2Color: '#0a84ff', // Blue
            ageCalculationMethod: 'registration-date',
            ageCalculationDescription: 'Custom age calculation'
        }
    };

    return defaults[sanctioningBody] || defaults['custom'];
}

// Auto-update form fields when sanctioning body changes
function updateSanctioningBodyDefaults() {
    const sanctioningBody = document.getElementById('sanctioning-body').value;

    if (!sanctioningBody) return;

    const defaults = getSanctioningBodyDefaults(sanctioningBody);

    // Auto-select age calculation method
    document.getElementById('age-calculation-method').value = defaults.ageCalculationMethod;

    // Update hint text
    const hint = document.getElementById('age-calc-hint');
    if (hint) {
        if (sanctioningBody === 'wkf') {
            hint.textContent = 'WKF uses age as of December 31st of the competition year. Example: Tournament on March 15, 2026 → age calculated as of Dec 31, 2026.';
        } else if (sanctioningBody === 'aau') {
            hint.textContent = 'AAU uses age on the day of competition. Example: Tournament on March 15, 2026 → age calculated as of March 15, 2026.';
        } else {
            hint.textContent = 'Custom tournament - select your preferred age calculation method.';
        }
    }
}

// Tournament Management
function showTournamentForm() {
    document.getElementById('tournament-modal').classList.remove('hidden');
}

function hideTournamentForm() {
    document.getElementById('tournament-modal').classList.add('hidden');
    document.getElementById('tournament-form').reset();
    currentTournamentLogoData = null;
    document.getElementById('logo-preview').classList.add('hidden');
}

function switchTournament() {
    const select = document.getElementById('active-tournament');
    currentTournamentId = select.value || null;
    if (currentTournamentId) {
        _inMemoryCompetitors = [];   // clear stale in-memory competitors on tournament switch
        _migrateUnscopedData();
        db.init();
        document.getElementById('main-nav').classList.remove('hidden');
        loadCompetitors();
        loadDashboard();
        // Reload server-side competitors/clubs when switching to a server-managed tournament.
        // _activateTournament handles the initial URL-load path; switchTournament must also refresh.
        if (_isServerTournamentId(currentTournamentId)) {
            _loadCompetitorsFromServer().then(() => {
                loadCompetitors();
                loadDashboard();
            });
        }
        _loadTeamsFromServer();

        // Reload whichever view is currently active so it shows the new tournament's data
        const activeView = document.querySelector('.view.active');
        if (activeView) {
            const viewName = activeView.id.replace(/-view$/, '');
            const viewLoaders = {
                'divisions':               () => { loadEventTypeSelector(); loadTemplateSelector(); loadDivisions(); },
                'brackets':                () => loadBrackets(),
                'schedule':                () => { displayMats(); loadMatSchedule(); },
                'events':                  () => { loadEventTypes(); loadEventTypeSelector(); },
                'clubs':                   () => loadClubs(),
                'coaches':                 () => loadCoaches(),
                'officials':               () => loadOfficials(),
                'staff':                   () => loadStaff(),
                'results':                 () => loadResults(),
                'settings':                () => loadSettings(),
                'settings-tournament-info':() => loadTournamentInfoView(),
                'settings-pricing':        () => loadPricingView(),
                'settings-certificates':   () => loadCertificatesView(),
                'settings-sponsors':       () => loadSponsorsView(),
                'settings-feedback':       () => loadFeedbackView(),
                'staging':                 () => loadStagingView(),
                'staging-settings':        () => loadStagingSettings(),
                'checkin':                 () => loadCheckinView(),
                'judge-analytics':         () => loadJudgeAnalyticsView(),
                'medical-incidents':       () => loadMedicalIncidents(),
                'scoreboard-configs':      () => loadUnifiedScoreboardConfig(),
                'academy':                 () => loadAcademyView(),
            };
            const loader = viewLoaders[viewName];
            if (loader) loader();
        }
    } else {
        document.getElementById('main-nav').classList.add('hidden');
    }

    // Update the delete danger zone label so user knows which tournament is selected
    const nameEl = document.getElementById('delete-tournament-name');
    if (nameEl) {
        if (currentTournamentId) {
            const tournaments = db.load('tournaments');
            const t = tournaments.find(t => String(t.id) === String(currentTournamentId));
            nameEl.textContent = t ? `"${t.name}"` : '';
        } else {
            nameEl.textContent = '';
        }
    }
}

function clearLogo() {
    currentTournamentLogoData = null;
    document.getElementById('logo-preview').classList.add('hidden');
    document.getElementById('tournament-logo').value = '';
}

// Load tournament logo
document.getElementById('tournament-logo')?.addEventListener('change', function(e) {
    const file = e.target.files[0];
    if (file) {
        const reader = new FileReader();
        reader.onload = function(event) {
            currentTournamentLogoData = event.target.result;
            document.getElementById('logo-preview-img').src = currentTournamentLogoData;
            document.getElementById('logo-preview').classList.remove('hidden');
        };
        reader.readAsDataURL(file);
    }
});

// Tournament form submission
document.getElementById('tournament-form')?.addEventListener('submit', (e) => {
    e.preventDefault();

    const sanctioningBody = document.getElementById('sanctioning-body').value;
    const defaults = getSanctioningBodyDefaults(sanctioningBody);

    const tournament = {
        name: document.getElementById('tournament-name').value,
        date: document.getElementById('tournament-date').value,
        location: document.getElementById('tournament-location').value,
        sanctioningBody: sanctioningBody, // NEW: Store sanctioning body
        ageCalculationMethod: document.getElementById('age-calculation-method').value,
        logo: currentTournamentLogoData || null,
        // Store corner defaults from sanctioning body
        cornerDefaults: {
            corner1Name: defaults.corner1Name,
            corner2Name: defaults.corner2Name,
            corner1Color: defaults.corner1Color,
            corner2Color: defaults.corner2Color
        },
        // Registration pricing defaults — use != null so $0 is preserved (0 || 75 would be wrong)
        pricing: {
            basePrice: (() => { const v = document.getElementById('tournament-base-price')?.value; return (v !== '' && v != null) ? parseFloat(v) : 75.00; })(),
            addOnPrice: (() => { const v = document.getElementById('tournament-addon-price')?.value; return (v !== '' && v != null) ? parseFloat(v) : 25.00; })(),
        },
        createdAt: new Date().toISOString()
    };

    // Initialize tournaments array if needed
    if (!_msGet('tournaments')) {
        _msSet('tournaments', JSON.stringify([]));
    }

    const savedTournament = db.add('tournaments', tournament);
    loadTournamentSelector();

    // Auto-select the new tournament
    document.getElementById('active-tournament').value = savedTournament.id;
    currentTournamentId = savedTournament.id;
    document.getElementById('main-nav').classList.remove('hidden');

    // Auto-generate unified scoreboard config from sanctioning body
    autoGenerateScoreboardConfig(sanctioningBody);

    const bodyName = sanctioningBody === 'wkf' ? 'WKF' : sanctioningBody === 'aau' ? 'AAU' : 'Custom';
    showMessage(`Tournament created successfully with ${bodyName} rules! Scoreboard configuration auto-generated.`);
    hideTournamentForm();
});

function _tournamentOptionText(t) {
    return `${t.name} - ${new Date(typeof t.date === 'string' && t.date.length === 10 ? t.date + 'T12:00:00' : t.date).toLocaleDateString()}`;
}

function loadTournamentSelector() {
    const tournaments = db.load('tournaments');
    const select = document.getElementById('active-tournament');
    select.innerHTML = '<option value="">Select Tournament</option>';

    tournaments.forEach(tournament => {
        const option = document.createElement('option');
        option.value = tournament.id;
        option.textContent = _tournamentOptionText(tournament);
        select.appendChild(option);
    });

    // Also pull server tournaments so API-created ones appear in the list
    fetch('/api/tournaments/director/mine', { credentials: 'include' })
        .then(r => r.ok ? r.json() : null)
        .then(data => {
            const serverList = data?.tournaments || data?.data || [];
            if (!Array.isArray(serverList)) return;
            serverList.forEach(t => {
                if (!Array.from(select.options).some(o => o.value === t.id)) {
                    const opt = document.createElement('option');
                    opt.value = t.id;
                    opt.textContent = _tournamentOptionText(t);
                    select.appendChild(opt);
                }
            });
            // If current URL has a ?tid= that is now in the list, ensure it's selected
            const tidParam = new URLSearchParams(window.location.search).get('tid');
            if (tidParam && select.value !== tidParam && Array.from(select.options).some(o => o.value === tidParam)) {
                select.value = tidParam;
            }
        })
        .catch(() => {});
}

// Load tournaments on page load
loadTournamentSelector();

// ── Auto-detect tournament from URL path or ?tid= query param ───────────────
// Supports both /director/tournaments/:id/manage and manage.html?tid=:id
(function _initFromURL() {
    const match = window.location.pathname.match(/\/director\/tournaments\/([^/]+)\/manage/);
    const tidParam = new URLSearchParams(window.location.search).get('tid');
    if (!match && !tidParam) return;

    const urlTournamentId = match ? match[1] : tidParam;

    // Helper to activate the detected tournament
    function _activateTournament(name) {
        const select = document.getElementById('active-tournament');
        // Ensure an option exists for this ID (it may already be there from localStorage)
        if (select && !Array.from(select.options).some(o => o.value === urlTournamentId)) {
            const opt = document.createElement('option');
            opt.value = urlTournamentId;
            opt.textContent = name || urlTournamentId;
            select.appendChild(opt);
        } else if (select && name) {
            // Update text if we now have the real name
            const existing = Array.from(select.options).find(o => o.value === urlTournamentId);
            if (existing && existing.textContent !== name) existing.textContent = name;
        }
        if (select) select.value = urlTournamentId;

        currentTournamentId = urlTournamentId;
        _migrateUnscopedData();
        db.init();
        document.getElementById('main-nav')?.classList.remove('hidden');
        // Defer all authenticated server calls until auth state is confirmed.
        // This prevents a flood of 401s when the page loads before Auth.init() resolves.
        _authReady.then(user => {
            if (!user) return; // not logged in — auth-gate handles the redirect
            // Initialize WebSocket for real-time bracket, competitor, and division updates
            _initWebSocket();
            // Subscribe to competitors and divisions channels immediately after connect
            if (_socket && _socket.connected && currentTournamentId) {
                _socket.emit('subscribe:competitors', { tournamentId: currentTournamentId });
                _socket.emit('subscribe:divisions', { tournamentId: currentTournamentId });
            }
            // Hydrate from server — server is source of truth for all data.
            // _hydrateEventTypesFromServer also populates divisions[eventId].templates,
            // so _loadDivisionsFromServer (which loads generated groupings) must chain after it.
            _hydrateEventTypesFromServer().then(() => {
                loadCompetitors();
                loadDashboard();
                // Load generated divisions AFTER templates are hydrated from event types
                return _loadDivisionsFromServer();
            }).then(() => {
                if (typeof loadDivisions === 'function') loadDivisions();
            });
            _loadCompetitorsFromServer().then(() => {
                loadCompetitors();
                loadDashboard(); // Refresh dashboard stats after competitors load from server
            });
            _loadPersonnelFromServer().then(() => {
                if (typeof loadOfficials === 'function') loadOfficials();
                if (typeof loadStaff === 'function') loadStaff();
                if (typeof loadCoaches === 'function') loadCoaches();
            });
            _loadTeamsFromServer();
            _loadBracketsFromServer().then(() => {
                if (typeof loadBrackets === 'function') loadBrackets();
            });
            _loadResultsFromServer().then(() => {
                if (typeof loadResults === 'function') loadResults();
            });
            // Auto-load certificate template + config from server
            loadCertificateTemplateFromServer().catch(e => console.warn('[sync] Certificate template load:', e.message));
            // Auto-load scoreboard config from server
            _loadScoreboardConfigFromServer().catch(e => console.warn('[sync] Scoreboard config load:', e.message));
            // Auto-load public site config from server
            _loadPublicSiteConfigFromServer().catch(e => console.warn('[sync] Public site config load:', e.message));
            // Auto-load staging settings from server
            _loadStagingSettingsFromServer().catch(e => console.warn('[sync] Staging settings load:', e.message));
            // Auto-load mats config from server
            _loadMatsFromServer().catch(e => console.warn('[sync] Mats load:', e.message));
            // Auto-load mat scoreboards from server
            _loadMatScoreboardsFromServer().catch(e => console.warn('[sync] Mat scoreboards load:', e.message));
            // Auto-load schedule (matSchedule + scheduleSettings) from server
            _loadScheduleFromServer().catch(e => console.warn('[sync] Schedule load:', e.message));
        });
    }

    // Try localStorage first (instant, no network)
    const localTournaments = db.load('tournaments');
    const localT = localTournaments.find(t => String(t.id) === urlTournamentId);
    if (localT) {
        _activateTournament(`${localT.name} - ${new Date(typeof localT.date === 'string' && localT.date.length === 10 ? localT.date + 'T12:00:00' : localT.date).toLocaleDateString()}`);
        return;
    }

    // Not in localStorage (server-only tournament) — activate with placeholder, then
    // fetch the real name and update the dropdown + banner.
    _activateTournament('Loading…');
    if (_isServerTournamentId(urlTournamentId)) {
        fetch(`/api/tournaments/${urlTournamentId}`, { credentials: 'include' })
            .then(r => r.ok ? r.json() : null)
            .then(data => {
                const name = data?.name || data?.tournament?.name;
                if (!name) return;
                // Update dropdown option text
                const select = document.getElementById('active-tournament');
                const opt = select && Array.from(select.options).find(o => o.value === urlTournamentId);
                if (opt) opt.textContent = name;
                // Update competitors banner
                const banner = document.getElementById('tournament-filter-banner');
                if (banner && !banner.classList.contains('hidden')) {
                    banner.textContent = `Showing competitors for: ${name}`;
                }
            })
            .catch(() => {});
    }
})();

// Migration: Assign legacy competitors to current/first tournament
function migrateLegacyCompetitors() {
    const competitors = db.load('competitors');
    const tournaments = db.load('tournaments');

    if (tournaments.length === 0) return; // No tournaments to migrate to

    let migrated = 0;
    const targetTournamentId = currentTournamentId || tournaments[0].id;

    competitors.forEach(comp => {
        if (!comp.tournamentId) {
            comp.tournamentId = targetTournamentId;
            migrated++;
        }
    });

    if (migrated > 0) {
        try {
            db.save('competitors', competitors);
        } catch (e) {
            console.warn('[migration] Could not save migrateLegacyCompetitors — quota exceeded, skipping.');
        }
    }
}

// Migration: Calculate pricing for legacy competitors that lack pricing data
function migrateLegacyPricing() {
    const competitors = db.load('competitors');
    // Skip entirely if every competitor already has both fields — avoid a needless bulk save
    const needsMigration = competitors.some(
        c => (c.events && c.events.length > 0 && !c.pricing) || !c.paymentStatus
    );
    if (!needsMigration) return;

    const eventTypes = db.load('eventTypes');
    const tournament = getCurrentTournament();
    let migrated = 0;

    competitors.forEach(comp => {
        if (comp.events && comp.events.length > 0 && !comp.pricing) {
            comp.pricing = calculatePricingBreakdown(comp.events, eventTypes, tournament);
            comp.primaryEventId = comp.events[0] || null;
            comp.paymentStatus = comp.paymentStatus || 'unpaid';
            migrated++;
        }
        // Ensure paymentStatus exists even if pricing already set
        if (!comp.paymentStatus) {
            comp.paymentStatus = 'unpaid';
            migrated++;
        }
    });

    if (migrated > 0) {
        try {
            db.save('competitors', competitors);
        } catch (e) {
            console.warn('[migration] Could not save migrateLegacyPricing — quota exceeded, skipping.');
        }
    }
}

// Run migrations on page load
migrateLegacyCompetitors();
migrateLegacyPricing();

/**
 * Auto-shrinks a stat-number element's font-size so the text always fits
 * inside its card, regardless of how long the value is.
 * Keeps max (4em) for short values and scales down proportionally for longer ones.
 */
function fitStatNumber(el) {
    if (!el) return;
    const len = el.textContent.length;
    // Hold at 4em up to 5 chars, then scale inversely with length (min 1em)
    const em = len <= 5 ? 4 : Math.max(1, 4 * (5 / len));
    el.style.fontSize = em + 'em';
}

// Dashboard
function loadDashboard() {
    const allCompetitors = db.load('competitors');
    const events = db.load('eventTypes') || [];
    const divisions = db.load('divisions');
    const matches = db.load('matches');

    // Filter by current tournament
    const competitors = currentTournamentId
        ? allCompetitors.filter(c => c.tournamentId === currentTournamentId)
        : allCompetitors;

    document.getElementById('stat-competitors').textContent = competitors.length;
    document.getElementById('stat-events').textContent = events.length;

    // Count divisions across all event types
    let totalDivisions = 0;
    Object.values(divisions).forEach(eventData => {
        if (eventData && eventData.generated) {
            // New nested structure: { criteria, generated: { divisionName: [competitors] } }
            totalDivisions += Object.keys(eventData.generated).length;
        } else if (Array.isArray(eventData)) {
            // Legacy array structure
            totalDivisions += eventData.length;
        }
    });
    document.getElementById('stat-divisions').textContent = totalDivisions;
    document.getElementById('stat-matches').textContent = matches.length;

    // Financial summary
    let totalRevenue = 0;
    let paidCount = 0;
    let unpaidCount = 0;
    let cashDueCount = 0;
    let cashDueAmount = 0;
    competitors.forEach(comp => {
        // Director-added competitors may have comp.pricing.total (old in-memory shape).
        // Stripe-registered competitors arrive with comp.amountPaid from the registrations table.
        if (comp.amountPaid)        totalRevenue += comp.amountPaid;
        else if (comp.pricing?.total) totalRevenue += comp.pricing.total;

        // paymentStatus is camelCase from the unified query; 'paid' means Stripe succeeded.
        // Director-added entries have paymentStatus='director' — count them as confirmed.
        // pay_later means cash-only tournament — track separately as "cash pending".
        const ps = comp.paymentStatus || comp.payment_status || '';
        if (ps === 'paid' || ps === 'director') paidCount++;
        else if (ps === 'pay_later') {
            cashDueCount++;
            // Estimate cash owed from pricing if amountPaid is 0
            if (!comp.amountPaid && comp.pricing?.total) cashDueAmount += comp.pricing.total;
        }
        else if (ps !== 'cancelled') unpaidCount++;
    });
    const revenueEl = document.getElementById('stat-revenue');
    if (revenueEl) {
        revenueEl.textContent = formatPrice(totalRevenue, getTournamentCurrency());
        fitStatNumber(revenueEl);
    }
    const paidEl = document.getElementById('stat-paid-count');
    if (paidEl) paidEl.textContent = paidCount;
    const unpaidEl = document.getElementById('stat-unpaid-count');
    if (unpaidEl) unpaidEl.textContent = unpaidCount;
    // Show cash-pending row only when there are pay_later registrations
    const cashDueRow = document.getElementById('stat-cash-due-row');
    if (cashDueRow) {
        cashDueRow.style.display = cashDueCount > 0 ? '' : 'none';
        const cashDueCountEl = document.getElementById('stat-cash-due-count');
        const cashDueAmountEl = document.getElementById('stat-cash-due-amount');
        if (cashDueCountEl) cashDueCountEl.textContent = cashDueCount;
        if (cashDueAmountEl) cashDueAmountEl.textContent = cashDueAmount > 0 ? formatPrice(cashDueAmount, getTournamentCurrency()) : 'TBD';
    }

    // Update readiness checklist (runs async-safe — reads only local state)
    renderReadinessChecklist();
}

// ═══════════════════════════════════════════════════════════════════════════
// TOURNAMENT READINESS CHECKLIST
// ═══════════════════════════════════════════════════════════════════════════

/**
 * Compute and render the Tournament Readiness checklist on the dashboard.
 * Called at the end of loadDashboard() so it always reflects fresh data.
 *
 * Steps checked:
 *   1. Tournament published (open for registration)
 *   2. Event types created (≥ 1)
 *   3. Competitors registered (≥ 2 real competitors)
 *   4. Divisions generated for every non-default event that has competitors
 *   5. No unpaid / unresolved registrations
 *   6. Mat schedule published
 *   7. At least one bracket created
 */
function renderReadinessChecklist() {
    const panel = document.getElementById('readiness-checklist');
    if (!panel) return; // only exists on manage.html dashboard

    const tournaments     = db.load('tournaments');
    const tournament      = tournaments.find(t => t.id === currentTournamentId);
    const eventTypes      = db.load('eventTypes') || [];
    const allCompetitors  = db.load('competitors');
    const divisions       = db.load('divisions');
    const brackets        = JSON.parse(_msGet(_scopedKey('brackets')) || '{}');

    const competitors = currentTournamentId
        ? allCompetitors.filter(c => c.tournamentId === currentTournamentId)
        : allCompetitors;

    const realCompetitors = competitors.filter(c => !c.is_test);
    const unpaidCount     = realCompetitors.filter(c => {
        const ps = c.paymentStatus || c.payment_status || '';
        return !['paid', 'director', 'waived'].includes(ps) && ps !== 'cancelled';
    }).length;

    // ── Division coverage ──────────────────────────────────────────────────
    // An event "needs" divisions if it has ≥ 1 competitor enrolled and it is
    // not the default base-registration event.
    const competingEvents = eventTypes.filter(et => !et.isDefault && realCompetitors.some(c =>
        Array.isArray(c.events) && c.events.map(String).includes(String(et.id))
    ));
    const eventsWithDivisions = competingEvents.filter(et => {
        const d = divisions[et.id];
        return d && d.generated && Object.keys(d.generated).length > 0;
    });
    const divisionsCoverage  = `${eventsWithDivisions.length}/${competingEvents.length}`;
    const divisionsOk        = competingEvents.length > 0 && eventsWithDivisions.length === competingEvents.length;

    // ── Bracket coverage ───────────────────────────────────────────────────
    // Brackets are already scoped to this tournament via _scopedKey, so count all of them.
    const bracketCount = Object.keys(brackets).length;

    // ── Check-in progress ──────────────────────────────────────────────────
    const checkedInCount = realCompetitors.filter(c => c.checkedIn || c.checked_in).length;

    // ── Build checklist items ──────────────────────────────────────────────
    const checks = [
        {
            label:   'Tournament published',
            detail:  tournament?.published ? 'Open for registration' : 'Not visible to public',
            ok:      !!tournament?.published,
            link:    null, // Settings are on the director.html tournament page, not this tab
            linkLabel: null,
        },
        {
            label:   'Event types configured',
            detail:  eventTypes.length > 0
                ? `${eventTypes.length} event type${eventTypes.length !== 1 ? 's' : ''}`
                : 'No event types created',
            ok:      eventTypes.length > 0,
            link:    'events',
            linkLabel: 'Go to Events',
        },
        (() => {
            // Division tree check — every non-default event needs a tree with ≥1 split
            const nonDefault = eventTypes.filter(et => !et.isDefault);
            if (nonDefault.length === 0) {
                return {
                    label:   'Division trees',
                    detail:  'No events created yet',
                    ok:      false,
                    link:    'events',
                    linkLabel: 'Go to Events',
                };
            }
            const missing = nonDefault.filter(et =>
                _msGet(_scopedKey(`divTreeBuilt_${et.id}`)) !== '1'
            );
            return {
                label:   'Division trees',
                detail:  missing.length === 0
                    ? `All ${nonDefault.length} event${nonDefault.length !== 1 ? 's' : ''} have division trees`
                    : missing.length === nonDefault.length
                        ? 'No division trees built yet'
                        : `${missing.length} event${missing.length !== 1 ? 's' : ''} missing: ${missing.map(e => e.name).join(', ')}`,
                ok:      missing.length === 0,
                link:    'divisions',
                linkLabel: 'Go to Divisions',
            };
        })(),
        {
            label:   'Competitors registered',
            detail:  realCompetitors.length >= 2
                ? `${realCompetitors.length} competitor${realCompetitors.length !== 1 ? 's' : ''} registered`
                : realCompetitors.length === 1
                    ? '1 competitor — need at least 2'
                    : 'No competitors registered',
            ok:      realCompetitors.length >= 2,
            link:    'competitors',
            linkLabel: 'Go to Competitors',
        },
        {
            label:   'Divisions generated',
            detail:  competingEvents.length === 0
                ? 'No events with competitors yet'
                : divisionsOk
                    ? `All ${competingEvents.length} event${competingEvents.length !== 1 ? 's' : ''} have divisions`
                    : `${divisionsCoverage} events have divisions`,
            ok:      divisionsOk,
            link:    'divisions',
            linkLabel: 'Go to Divisions',
        },
        {
            label:   'Payments resolved',
            detail:  unpaidCount === 0
                ? 'All competitors paid or waived'
                : `${unpaidCount} competitor${unpaidCount !== 1 ? 's' : ''} with unresolved payment`,
            ok:      unpaidCount === 0,
            link:    'competitors',
            linkLabel: 'View Competitors',
        },
        {
            label:   'Schedule published',
            detail:  window._schedulePublished ? 'Schedule is live' : 'Schedule not yet published',
            ok:      !!window._schedulePublished,
            link:    'schedule',
            linkLabel: 'Go to Schedule',
        },
        {
            label:   'Brackets created',
            detail:  bracketCount > 0
                ? `${bracketCount} bracket${bracketCount !== 1 ? 's' : ''} created`
                : 'No brackets created yet',
            ok:      bracketCount > 0,
            link:    'bracket',
            linkLabel: 'Go to Brackets',
        },
        (() => {
            const certTemplate = JSON.parse(_msGet(_scopedKey('certificateTemplate')) || 'null');
            const certConfig   = JSON.parse(_msGet(_scopedKey('certificateConfig'))   || 'null');
            const hasTemplate  = !!(certTemplate?.data || certTemplate?.dataUrl);
            const enabledTags  = certConfig?.tags
                ? Object.values(certConfig.tags).filter(t => t.enabled).length : 0;
            return {
                label:     'Certificate template',
                detail:    !hasTemplate
                    ? 'No certificate template uploaded'
                    : enabledTags === 0
                        ? 'Template uploaded — merge tags not yet configured'
                        : `Template ready, ${enabledTags} tag${enabledTags !== 1 ? 's' : ''} configured`,
                ok:        hasTemplate && enabledTags > 0,
                link:      'settings-certificates',
                linkLabel: 'Go to Certificates',
            };
        })(),
    ];

    const passedCount = checks.filter(c => c.ok).length;
    const pct         = Math.round((passedCount / checks.length) * 100);

    // ── Render progress bar ────────────────────────────────────────────────
    const bar   = document.getElementById('readiness-bar');
    const score = document.getElementById('readiness-score');
    if (bar)   bar.style.width = `${pct}%`;
    if (bar)   bar.style.background = pct === 100 ? '#22c55e' : pct >= 57 ? '#f59e0b' : '#ef4444';
    if (score) score.textContent = `${passedCount} / ${checks.length} complete`;

    // ── Render item rows ───────────────────────────────────────────────────
    panel.innerHTML = checks.map(c => {
        const icon     = c.ok
            ? `<span style="color:#22c55e;font-size:16px;flex-shrink:0;">✓</span>`
            : `<span style="color:#ef4444;font-size:16px;flex-shrink:0;">✕</span>`;
        const linkHtml = (!c.ok && c.link)
            ? `<button class="btn btn-small btn-secondary" style="margin-left:auto;flex-shrink:0;"
                       onclick="navigateTo('${c.link}')">${c.linkLabel}</button>`
            : '';
        return `
            <div style="display:flex;align-items:center;gap:10px;padding:8px 10px;border-radius:8px;background:var(--bg-secondary);">
                ${icon}
                <div style="flex:1;min-width:0;">
                    <div style="font-size:13px;font-weight:600;${c.ok ? '' : 'color:var(--text-primary);'}">${c.label}</div>
                    <div style="font-size:12px;color:var(--text-secondary);">${c.detail}</div>
                </div>
                ${linkHtml}
            </div>`;
    }).join('');
}

// ═══════════════════════════════════════════════════════════════════════════
// MEDAL COUNT SYSTEM
// ═══════════════════════════════════════════════════════════════════════════
//
// Estimates how many gold, silver, and bronze medals are needed based on
// division data. Works in two modes:
//   Mode 1 (Pre-generation): Simulates division building from templates
//   Mode 2 (Post-generation): Counts from actual generated divisions
// Automatically detects which mode to use per event.

/**
 * Pure medal math: returns medal counts for a given number of competitors.
 */
function getMedalsForCount(competitorCount) {
    if (competitorCount <= 1) return { gold: 0, silver: 0, bronze: 0 };
    if (competitorCount === 2) return { gold: 1, silver: 1, bronze: 0 };
    if (competitorCount === 3) return { gold: 1, silver: 1, bronze: 1 };
    return { gold: 1, silver: 1, bronze: 2 };
}

/**
 * Calculates medal counts across all events.
 * Returns { totals: {gold, silver, bronze}, events: [ {name, gold, silver, bronze, isTeam, teamSize, mode} ] }
 */
function calculateMedalCounts() {
    const divisions = db.load('divisions');
    const events = db.load('eventTypes') || [];
    const allCompetitors = db.load('competitors');
    const competitors = currentTournamentId
        ? allCompetitors.filter(c => c.tournamentId === currentTournamentId)
        : allCompetitors;

    // Get tournament settings for age calculation
    const tournaments = db.load('tournaments');
    const currentTournament = tournaments.find(t => t.id === currentTournamentId);
    const ageMethod = currentTournament?.ageCalculationMethod || 'aau-standard';
    const eventDate = currentTournament?.date || new Date().toISOString();

    const result = {
        totals: { gold: 0, silver: 0, bronze: 0 },
        events: []
    };

    events.forEach(event => {
        if (event.isDefault) return; // Skip base registration fee events

        const eventId = event.id;
        const eventData = divisions[eventId];
        const isTeam = event.teamSize > 1;
        const multiplier = isTeam ? event.teamSize : 1;

        let eventGold = 0;
        let eventSilver = 0;
        let eventBronze = 0;
        let mode = 'none';

        if (eventData && eventData.generated && Object.keys(eventData.generated).length > 0) {
            // MODE 2: Post-generation — use actual generated divisions
            mode = 'actual';
            Object.values(eventData.generated).forEach(compArray => {
                const count = Array.isArray(compArray) ? compArray.length : 0;
                const medals = getMedalsForCount(count);
                eventGold += medals.gold;
                eventSilver += medals.silver;
                eventBronze += medals.bronze;
            });
        } else if (eventData && eventData.templates && eventData.templates.length > 0) {
            // MODE 1: Pre-generation — simulate from templates
            mode = 'estimated';

            // Get competitors registered for this event
            // Use string comparison — event IDs may be stored as numbers (director/CSV) or strings (registrations)
            const eventCompetitors = competitors.filter(c =>
                c.events && c.events.some(id => String(id) === String(eventId))
            );

            if (eventCompetitors.length > 0) {
                // Prepare competitors with calculated age for buildDivisions()
                const compsWithAge = eventCompetitors.map(comp => ({
                    ...comp,
                    age: comp.dateOfBirth
                        ? calculateAge(comp.dateOfBirth, ageMethod, eventDate)
                        : (comp.age != null ? comp.age : 0)
                }));

                eventData.templates.forEach(template => {
                    if (!template.criteria || template.criteria.length === 0) {
                        // No criteria = one division with all event competitors
                        const medals = getMedalsForCount(compsWithAge.length);
                        eventGold += medals.gold;
                        eventSilver += medals.silver;
                        eventBronze += medals.bronze;
                    } else {
                        // Reuse buildDivisions() to simulate the exact same splits
                        const simulated = buildDivisions(compsWithAge, template.criteria);
                        Object.values(simulated).forEach(compArray => {
                            const count = Array.isArray(compArray) ? compArray.length : 0;
                            const medals = getMedalsForCount(count);
                            eventGold += medals.gold;
                            eventSilver += medals.silver;
                            eventBronze += medals.bronze;
                        });
                    }
                });
            }
        }

        // Apply team multiplier
        eventGold *= multiplier;
        eventSilver *= multiplier;
        eventBronze *= multiplier;

        // Add to totals
        result.totals.gold += eventGold;
        result.totals.silver += eventSilver;
        result.totals.bronze += eventBronze;

        // Add per-event data (only if event has division config)
        if (mode !== 'none') {
            result.events.push({
                name: event.name,
                gold: eventGold,
                silver: eventSilver,
                bronze: eventBronze,
                total: eventGold + eventSilver + eventBronze,
                isTeam: isTeam,
                teamSize: event.teamSize,
                mode: mode
            });
        }
    });

    return result;
}

/**
 * Renders the medal count panel on the dashboard.
 */
function updateMedalCountDisplay() {
    const data = calculateMedalCounts();
    const grandTotal = data.totals.gold + data.totals.silver + data.totals.bronze;

    // Update totals
    document.getElementById('medal-total').textContent = grandTotal;
    document.getElementById('medal-gold').textContent = data.totals.gold;
    document.getElementById('medal-silver').textContent = data.totals.silver;
    document.getElementById('medal-bronze').textContent = data.totals.bronze;

    // Build per-event breakdown
    const container = document.getElementById('medal-event-breakdown');

    if (data.events.length === 0) {
        container.innerHTML = '<p class="medal-no-data">Add event types with division templates to see medal estimates.</p>';
        return;
    }

    let html = '<h3>Per-Event Breakdown</h3>';

    data.events.forEach(evt => {
        const teamTag = evt.isTeam
            ? `<span class="medal-event-tag team">Team &times;${evt.teamSize}</span>`
            : '';
        const modeTag = evt.mode === 'estimated'
            ? '<span class="medal-event-tag estimated">Estimated</span>'
            : '<span class="medal-event-tag actual">Actual</span>';

        html += `
            <div class="medal-event-row">
                <div class="medal-event-info">
                    <span class="medal-event-name">${evt.name}</span>
                    ${teamTag}
                    ${modeTag}
                </div>
                <div class="medal-event-counts">
                    <span class="gold" title="Gold">&#x1F947; ${evt.gold}</span>
                    <span class="silver" title="Silver">&#x1F948; ${evt.silver}</span>
                    <span class="bronze" title="Bronze">&#x1F949; ${evt.bronze}</span>
                    <span class="event-total" title="Total">&bull; ${evt.total}</span>
                </div>
            </div>`;
    });

    container.innerHTML = html;
}

