/**
 * ═══════════════════════════════════════════════════════════════════════════
 * COMPETITOR REGISTRATION & MANAGEMENT
 * ═══════════════════════════════════════════════════════════════════════════
 *
 * PURPOSE: Handle competitor registration with multi-event support and DOB-based age
 *
 * WORKFLOW:
 * 1. Click "Add Competitor" button
 * 2. showCompetitorForm() - Opens form, loads dojos and events
 * 3. User enters competitor info including Date of Birth
 * 4. calculateAge() shows real-time age preview (registration vs event)
 * 5. User selects one or more events to register for
 * 6. Form submission validates and saves to competitors table
 * 7. loadCompetitors() displays all competitors with calculated ages
 *
 * KEY FEATURES (2026-02-13):
 * - Date of Birth instead of age (stores DOB, calculates age dynamically)
 * - Multi-event registration (checkboxes for multiple events)
 * - Real-time age preview (shows age at registration AND event date)
 * - Dojo selection with "Add New Dojo" option
 * - Dojo logo upload when adding new dojo
 * - Photo upload with preview
 * - Event pricing display
 *
 * DATA STRUCTURE (Competitor):
 * {
 *   id: 123,
 *   firstName: "John",
 *   lastName: "Doe",
 *   dateOfBirth: "2014-01-05",        // ISO date string (NEW)
 *   weight: 45.5,
 *   rank: "Green Belt",
 *   experience: 3.5,
 *   gender: "Male",
 *   club: "Tokyo Dojo",
 *   clubLogo: "data:image/png...",    // Base64
 *   photo: "data:image/png...",       // Base64
 *   events: [1, 3, 5],                // Array of event IDs (NEW)
 *   registrationDate: "2026-02-13T..."
 * }
 *
 * AGE CALCULATION:
 * - Age is CALCULATED from dateOfBirth, not stored
 * - Calculation method set at tournament level:
 *   - "event-date": Age on tournament date (standard)
 *   - "registration-date": Age when registered
 * - calculateAge(dob, referenceDate) handles leap years, birth month/day
 * - Legacy support: Old competitors with 'age' field still work
 *
 * MULTI-EVENT REGISTRATION:
 * - loadEventCheckboxes() populates event options with prices
 * - Competitors can select multiple events
 * - Validation requires at least one event
 * - Events stored as array of IDs: [1, 3, 5]
 * - Display shows event names in table
 *
 * DOJO INTEGRATION:
 * - loadClubDropdown() loads from clubs table
 * - "+ Add New Dojo" option appears at bottom
 * - When selected, shows:
 *   - New dojo name input
 *   - Dojo logo upload (optional)
 * - New dojo auto-saved when competitor registered
 * - Dojo logo cached in competitor.clubLogo
 *
 * ✅ FEATURES:
 * 1. ✅ DOB-based age calculation (replaces static age)
 * 2. ✅ Multi-event registration with pricing
 * 3. ✅ Real-time age preview in form
 * 4. ✅ Dynamic age display in table (respects tournament setting)
 * 5. ✅ Dojo management integration
 * 6. ✅ Photo upload with preview
 * 7. ✅ Legacy support for old data
 *
 * ⚠️ KNOWN ISSUES:
 * 1. No validation for future DOB
 * 2. No min/max age constraints
 * 3. Photo size not limited (can exceed localStorage)
 *
 * 📝 TODO:
 * - Add DOB validation (must be in past)
 * - Add age range warnings (e.g., <4 or >100)
 * - Add photo compression before save
 * - Add bulk import from CSV
 *
 * Last Updated: 2026-02-13
 * ═══════════════════════════════════════════════════════════════════════════
 */

// ── Registration Fields (director form) ─────────────────────────────────────

async function _loadRegistrationFieldsForDirector(tournamentId) {
    try {
        const res = await fetch(`/api/tournaments/${tournamentId}/registration-fields`, { credentials: 'include' });
        if (!res.ok) return null;
        return await res.json();
    } catch (e) { return null; }
}

/**
 * Apply registration field options to the director competitor form.
 * Populates rank select, replaces experience input with select if needed,
 * and shows/hides the weight field.
 */
function _applyRegistrationFieldsToDirectorForm(fields) {
    if (!fields) return;

    // Populate rank dropdown
    const rankSel = document.getElementById('rank');
    if (rankSel && fields.showBeltRank && fields.beltRankOptions.length) {
        rankSel.innerHTML = '<option value="">Select Rank</option>' +
            fields.beltRankOptions.map(o => `<option value="${o}">${o}</option>`).join('');
    }

    // Populate or replace experience field
    const expEl = document.getElementById('experience');
    if (expEl) {
        const expGroup = expEl.closest('.form-group');
        if (fields.showExperienceLevel && fields.experienceLevelOptions.length) {
            if (expEl.tagName === 'INPUT' && expEl.type === 'number') {
                const sel = document.createElement('select');
                sel.id = 'experience';
                sel.name = expEl.name || 'experience';
                sel.required = expEl.required;
                sel.innerHTML = '<option value="">Select Level</option>' +
                    fields.experienceLevelOptions.map(o => `<option value="${o}">${o}</option>`).join('');
                expEl.replaceWith(sel);
                const label = expGroup?.querySelector('label');
                if (label) label.textContent = 'Experience Level *';
            }
            expGroup?.classList.remove('hidden');
        } else {
            expGroup?.classList.add('hidden');
        }
    }

    // Show/hide weight field; update unit label
    const weightEl = document.getElementById('weight');
    if (weightEl) {
        const weightGroup = weightEl.closest('.form-group');
        if (weightGroup) {
            fields.showWeight ? weightGroup.classList.remove('hidden') : weightGroup.classList.add('hidden');
        }
        const unitLabel = document.getElementById('weight-label-unit');
        if (unitLabel && fields.weightUnit) unitLabel.textContent = `(${fields.weightUnit})`;
    }

    // Show/hide gender field
    const genderEl = document.getElementById('gender');
    if (genderEl) {
        const genderGroup = genderEl.closest('.form-group');
        if (genderGroup) {
            fields.showGender !== false ? genderGroup.classList.remove('hidden') : genderGroup.classList.add('hidden');
        }
    }
}

// Competitor Form
function showCompetitorForm() {
    // If not in edit mode, reset to add mode
    if (!editingCompetitorId) {
        editingCompetitorId = null;
        const formTitle = document.querySelector('#competitor-form-container h3');
        if (formTitle) formTitle.textContent = 'Competitor Registration';
    }
    document.getElementById('competitor-form-container').classList.remove('hidden');
    setupDirectorAcademyAutocomplete();
    loadEventCheckboxes();

    // Load registration fields (use cache if available)
    if (_registrationFields) {
        _applyRegistrationFieldsToDirectorForm(_registrationFields);
    } else if (currentTournamentId) {
        _loadRegistrationFieldsForDirector(currentTournamentId).then(fields => {
            if (fields) {
                _registrationFields = fields;
                _applyRegistrationFieldsToDirectorForm(fields);
            }
        });
    }
}

/**
 * Calculate age from date of birth based on sanctioning body rules
 * @param {string} dateOfBirth - ISO date string (YYYY-MM-DD)
 * @param {string} method - 'wkf-standard', 'aau-standard', or 'registration-date'
 * @param {string} eventDate - ISO date string of the tournament/event
 * @returns {number} calculated age
 */
function calculateAge(dateOfBirth, method = 'aau-standard', eventDate = new Date()) {
    // Guard: date-only "YYYY-MM-DD" strings → local noon to avoid timezone shift
    const safeParse = (d) => (typeof d === 'string' && d.length === 10) ? new Date(d + 'T12:00:00') : new Date(d);
    const dob = safeParse(dateOfBirth);

    if (method === 'wkf-standard') {
        // WKF Rule: Age as of December 31st of the competition year
        const competitionYear = safeParse(eventDate).getFullYear();
        const dec31 = new Date(competitionYear, 11, 31); // Dec 31st of competition year
        let age = dec31.getFullYear() - dob.getFullYear();
        const monthDiff = dec31.getMonth() - dob.getMonth();

        if (monthDiff < 0 || (monthDiff === 0 && dec31.getDate() < dob.getDate())) {
            age--;
        }

        return age;
    } else if (method === 'aau-standard') {
        // AAU Rule: Age on day of competition
        const ref = safeParse(eventDate);
        let age = ref.getFullYear() - dob.getFullYear();
        const monthDiff = ref.getMonth() - dob.getMonth();

        if (monthDiff < 0 || (monthDiff === 0 && ref.getDate() < dob.getDate())) {
            age--;
        }

        return age;
    } else {
        // registration-date: Age right now (legacy behavior)
        const ref = new Date();
        let age = ref.getFullYear() - dob.getFullYear();
        const monthDiff = ref.getMonth() - dob.getMonth();

        if (monthDiff < 0 || (monthDiff === 0 && ref.getDate() < dob.getDate())) {
            age--;
        }

        return age;
    }
}

/**
 * Helper: Get display-friendly age from a competitor object.
 * Handles both new schema (dateOfBirth) and legacy schema (age).
 */
function getDisplayAge(comp) {
    if (!comp) return '-';
    if (comp.dateOfBirth) {
        const age = calculateAge(comp.dateOfBirth);
        // Guard against invalid/nonsensical ages
        if (isNaN(age) || age <= 0 || age > 120) return '-';
        return age;
    }
    return comp.age != null && comp.age > 0 ? comp.age : '-';
}

// Show age preview when DOB is entered
document.getElementById('dateOfBirth')?.addEventListener('change', function(e) {
    const dob = e.target.value;
    const ageDisplay = document.getElementById('age-display');

    if (dob && ageDisplay) {
        // Get current tournament
        const tournaments = db.load('tournaments');
        const currentTournament = tournaments.find(t => t.id === currentTournamentId);

        if (currentTournament) {
            const method = currentTournament.ageCalculationMethod || 'aau-standard';
            const ageAtRegistration = calculateAge(dob, 'registration-date', new Date());
            const ageAtEvent = calculateAge(dob, method, currentTournament.date);

            const methodLabel = method === 'wkf-standard'
                ? 'WKF (Dec 31st)'
                : method === 'aau-standard'
                    ? 'AAU (Event date)'
                    : 'Event date';

            ageDisplay.textContent = `Age now: ${ageAtRegistration} | Age for competition (${methodLabel}): ${ageAtEvent}`;
        } else {
            const currentAge = calculateAge(dob, 'registration-date', new Date());
            ageDisplay.textContent = `Current age: ${currentAge}`;
        }
    }
});

// Ordered array tracking event selection order — index 0 = primary (base price)
let selectedEventOrder = [];

function loadEventCheckboxes(preselectedEvents = []) {
    const eventTypes = db.load('eventTypes');
    const container = document.getElementById('event-checkboxes');

    if (!container) return;

    if (eventTypes.length === 0) {
        container.innerHTML = '<p style="color: var(--text-secondary); font-size: 14px;">No events available. Please create events first.</p>';
        return;
    }

    container.innerHTML = '';

    const defaultEvent = eventTypes.find(event => event.isDefault);

    // Initialize selection order
    if (preselectedEvents.length > 0) {
        selectedEventOrder = [...preselectedEvents];
    } else {
        // Auto-select default event as primary
        selectedEventOrder = defaultEvent ? [defaultEvent.id] : [];
    }

    // Render ALL events as checkboxes (including default, which starts pre-checked)
    eventTypes.forEach(event => {
        const checkboxDiv = document.createElement('div');
        checkboxDiv.id = `event-row-${event.id}`;
        checkboxDiv.style.cssText = 'display: flex; align-items: center; gap: 8px; padding: 10px 12px; background: var(--bg-primary); border-radius: 8px; transition: border-color 0.2s;';

        const teamSize = event.teamSize || 1;
        const teamLabel = teamSize > 1 ? ` (Team of ${teamSize})` : '';
        const isChecked = selectedEventOrder.includes(event.id);

        // Prerequisite label
        let prereqHint = '';
        if (event.prerequisiteEventId) {
            const prereqEv = eventTypes.find(e => e.id == event.prerequisiteEventId);
            if (prereqEv) {
                prereqHint = `<span style="display:block; font-size:11px; color:var(--accent); opacity:0.85; margin-top:2px;">Requires: ${prereqEv.name}</span>`;
            }
        }

        checkboxDiv.innerHTML = `
            <input
                type="checkbox"
                id="event-${event.id}"
                name="events"
                value="${event.id}"
                data-team-size="${teamSize}"
                ${isChecked ? 'checked' : ''}
                onchange="updateEventOrder('${event.id}')"
                style="width: 18px; height: 18px; cursor: pointer; flex-shrink: 0;"
            >
            <label for="event-${event.id}" style="cursor: pointer; flex: 1; font-size: 14px;">
                <strong>${event.name}</strong>${teamLabel}${prereqHint}
            </label>
            <span id="event-badge-${event.id}" style="padding: 2px 8px; border-radius: 4px; font-size: 11px; font-weight: 700; white-space: nowrap;"></span>
        `;

        container.appendChild(checkboxDiv);
    });

    // Add price summary container
    const summaryDiv = document.createElement('div');
    summaryDiv.id = 'price-summary';
    summaryDiv.style.cssText = 'margin-top: 16px; padding: 16px; background: var(--bg-primary); border-radius: 10px; border: 1px solid var(--glass-border);';
    summaryDiv.innerHTML = `
        <div id="price-breakdown"></div>
        <div id="price-total" style="margin-top: 12px; padding-top: 12px; border-top: 1px solid var(--glass-border); font-size: 16px; font-weight: 700; color: var(--accent);"></div>
    `;
    container.appendChild(summaryDiv);

    updateEventBadges();
    updatePriceSummary();
}

function updateEventOrder(eventId) {
    const checkbox = document.getElementById(`event-${eventId}`);
    if (checkbox && checkbox.checked) {
        if (!selectedEventOrder.includes(eventId)) {
            selectedEventOrder.push(eventId);
        }
    } else {
        selectedEventOrder = selectedEventOrder.filter(id => id !== eventId);
    }
    updateEventBadges();
    updatePriceSummary();
    handleEventSelection(); // preserve existing team event logic
}

function updateEventBadges() {
    const eventTypes = db.load('eventTypes');
    const tournament = getCurrentTournament();

    eventTypes.forEach(event => {
        const badge = document.getElementById(`event-badge-${event.id}`);
        const row = document.getElementById(`event-row-${event.id}`);
        if (!badge) return;

        const orderIndex = selectedEventOrder.indexOf(event.id);
        if (orderIndex === -1) {
            badge.textContent = '';
            badge.style.background = 'transparent';
            badge.style.color = 'transparent';
            if (row) row.style.border = '1px solid transparent';
        } else if (orderIndex === 0) {
            const price = getEventPrice(event, false, tournament);
            badge.textContent = `PRIMARY — ${formatPrice(price, getTournamentCurrency())}`;
            badge.style.background = 'var(--accent)';
            badge.style.color = '#fff';
            if (row) row.style.border = '1px solid var(--accent)';
        } else {
            const price = getEventPrice(event, true, tournament);
            badge.textContent = `ADD-ON — ${formatPrice(price, getTournamentCurrency())}`;
            badge.style.background = 'rgba(255,255,255,0.1)';
            badge.style.color = 'var(--text-secondary)';
            if (row) row.style.border = '1px solid var(--glass-border)';
        }
    });
}

function updatePriceSummary() {
    const eventTypes = db.load('eventTypes');
    const tournament = getCurrentTournament();
    const breakdownEl = document.getElementById('price-breakdown');
    const totalEl = document.getElementById('price-total');

    if (!breakdownEl || !totalEl) return;

    if (selectedEventOrder.length === 0) {
        breakdownEl.innerHTML = '<p style="color: var(--text-secondary); font-size: 13px;">No events selected. Please select at least one event.</p>';
        totalEl.textContent = '';
        return;
    }

    const { breakdown, total } = calculatePricingBreakdown(selectedEventOrder, eventTypes, tournament);

    // Calculate discount amount
    let discountAmount = 0;
    let discountLine = '';
    if (_activeDiscount) {
        const d = _activeDiscount;
        if (d.scope === 'event' && d.event_id) {
            // Discount applies only to a specific event
            const eventItem = breakdown.find(item => String(item.eventId) === String(d.event_id));
            if (eventItem) {
                discountAmount = d.discount_type === 'percentage'
                    ? eventItem.price * (d.discount_value / 100)
                    : Math.min(d.discount_value, eventItem.price);
            }
        } else {
            // Discount applies to full total
            discountAmount = d.discount_type === 'percentage'
                ? total * (d.discount_value / 100)
                : Math.min(d.discount_value, total);
        }
        discountAmount = Math.round(discountAmount * 100) / 100;
        const label = d.discount_type === 'percentage'
            ? `${d.discount_value}% off`
            : `$${parseFloat(d.discount_value).toFixed(2)} off`;
        discountLine = `
            <div style="display:flex; justify-content:space-between; padding:4px 0; font-size:14px; color:#22c55e;">
                <span>🏷 Discount (${_escapeHtml(d.code)} — ${label})</span>
                <span style="font-weight:600;">−$${discountAmount.toFixed(2)}</span>
            </div>
        `;
    }

    const finalTotal = Math.max(0, total - discountAmount);

    breakdownEl.innerHTML = breakdown.map(item => `
        <div style="display: flex; justify-content: space-between; padding: 4px 0; font-size: 14px;">
            <span>
                ${item.type === 'primary' ? '✦ ' : '  '}
                ${item.eventName}
                <span style="color: var(--text-secondary); font-size: 12px;">(${item.type === 'primary' ? 'Primary' : 'Add-on'})</span>
            </span>
            <span style="font-weight: 600;">${formatPrice(item.price, getTournamentCurrency())}</span>
        </div>
    `).join('') + discountLine;

    totalEl.innerHTML = discountAmount > 0
        ? `<span style="text-decoration:line-through; opacity:0.5; font-size:14px;">$${total.toFixed(2)}</span>&nbsp; Total: $${finalTotal.toFixed(2)}`
        : `Total: $${total.toFixed(2)}`;
}

// ── Registration form discount code ──────────────────────────────────────────

async function applyDiscountCode() {
    const codeInput = document.getElementById('discount-code-input');
    const infoEl    = document.getElementById('discount-code-info');
    const removeBtn = document.getElementById('discount-remove-btn');
    const code = codeInput?.value.trim().toUpperCase();

    if (!code) { showToast('Enter a discount code first', 'error'); return; }
    if (!currentTournamentId) { showToast('No tournament selected', 'error'); return; }

    try {
        const res = await fetch(`/api/tournaments/${currentTournamentId}/discount-codes/validate`, {
            method: 'POST', credentials: 'include',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ code }),
        });
        if (!res.ok) {
            const d = await res.json();
            if (infoEl) infoEl.innerHTML = `<span style="color:#ef4444;">✗ ${d.error || 'Invalid code'}</span>`;
            _activeDiscount = null;
            updatePriceSummary();
            return;
        }
        const d = await res.json();
        _activeDiscount = d;
        const discLabel = d.discount_type === 'percentage'
            ? `${d.discount_value}% off`
            : `$${parseFloat(d.discount_value).toFixed(2)} off`;
        const scopeLabel = d.scope === 'event' && d.event_name
            ? ` on ${d.event_name}`
            : ' your total';
        if (infoEl) infoEl.innerHTML = `<span style="color:#22c55e; font-weight:600;">✓ ${code} — ${discLabel}${scopeLabel} applied</span>`;
        if (removeBtn) removeBtn.style.display = '';
        if (codeInput) codeInput.disabled = true;
        updatePriceSummary();
    } catch(e) {
        if (infoEl) infoEl.innerHTML = `<span style="color:#ef4444;">✗ Could not validate code</span>`;
    }
}

function removeDiscountCode() {
    _activeDiscount = null;
    const codeInput = document.getElementById('discount-code-input');
    const infoEl    = document.getElementById('discount-code-info');
    const removeBtn = document.getElementById('discount-remove-btn');
    if (codeInput) { codeInput.value = ''; codeInput.disabled = false; }
    if (infoEl) infoEl.innerHTML = '';
    if (removeBtn) removeBtn.style.display = 'none';
    updatePriceSummary();
}

function handleEventSelection() {
    const checkboxes = document.querySelectorAll('input[name="events"]:checked');
    const teamSection = document.getElementById('team-registration-section');

    let hasTeamEvent = false;
    const eventTypes = db.load('eventTypes');

    // 1. Detect team events
    checkboxes.forEach(checkbox => {
        const teamSize = parseInt(checkbox.dataset.teamSize);
        if (teamSize > 1) hasTeamEvent = true;
    });

    if (teamSection) {
        if (hasTeamEvent) {
            teamSection.classList.remove('hidden');
            // Reset autocomplete state when section re-appears
            const input = document.getElementById('team-name-input');
            if (input && !input.value) _selectedTeamData = null;
        } else {
            teamSection.classList.add('hidden');
            _selectedTeamData = null;
        }
    }

    // 2. Enforce prerequisites — if an event with a prerequisiteEventId is selected,
    //    auto-check the required event and lock it
    const allCheckboxes = document.querySelectorAll('input[name="events"]');

    // First pass: collect IDs of currently-selected events
    const selectedIds = new Set();
    checkboxes.forEach(cb => selectedIds.add(cb.value));

    // Second pass: for each selected event, auto-select its prerequisite
    let addedPrereq = false;
    checkboxes.forEach(cb => {
        const ev = eventTypes.find(e => e.id === cb.value);
        if (ev && ev.prerequisiteEventId) {
            const prereqCb = document.querySelector(`input[name="events"][value="${ev.prerequisiteEventId}"]`);
            if (prereqCb && !prereqCb.checked) {
                prereqCb.checked = true;
                selectedIds.add(ev.prerequisiteEventId);
                addedPrereq = true;
                // Keep selectedEventOrder in sync — insert prereq before the requiring event
                if (!selectedEventOrder.includes(ev.prerequisiteEventId)) {
                    const insertIdx = selectedEventOrder.indexOf(cb.value);
                    if (insertIdx >= 0) {
                        selectedEventOrder.splice(insertIdx, 0, ev.prerequisiteEventId);
                    } else {
                        selectedEventOrder.unshift(ev.prerequisiteEventId);
                    }
                }
            }
        }
    });

    // Third pass: disable/lock prerequisite checkboxes that are required by a selected event
    allCheckboxes.forEach(cb => {
        const requiredBy = [...document.querySelectorAll('input[name="events"]:checked')].some(selCb => {
            const selEv = eventTypes.find(e => e.id === selCb.value);
            return selEv && selEv.prerequisiteEventId === cb.value;
        });
        cb.disabled = requiredBy;
        // Label is a sibling inside the row div, not a parent — use the row ID
        const row = document.getElementById(`event-row-${cb.value}`);
        const label = row?.querySelector('label');
        if (label) {
            let lockBadge = label.querySelector('.prereq-lock');
            if (requiredBy) {
                if (!lockBadge) {
                    lockBadge = document.createElement('span');
                    lockBadge.className = 'prereq-lock';
                    lockBadge.style.cssText = 'font-size:0.7rem; color:var(--accent); margin-left:6px; opacity:0.8;';
                    lockBadge.textContent = '(required)';
                    label.appendChild(lockBadge);
                }
            } else {
                if (lockBadge) lockBadge.remove();
            }
        }
    });

    if (addedPrereq) {
        showToast('A required event was automatically added to your selection.', 'info');
    }

    updateEventBadges?.();
    updatePriceSummary?.();
}

// ─── Active discount code applied in the registration form ────────────────────
let _activeDiscount = null; // { id, code, discount_type, discount_value, scope, event_id }

// ─── Team name search / autocomplete (replaces old team-code flow) ────────────
let _selectedTeamData = null; // { code, name, memberCount, isNew }

function _escapeHtml(str) {
    return String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

/* ── Currency & Weight helpers ───────────────────────── */
function getCurrencySymbol(code) {
    const c = (code || 'USD').toUpperCase();
    try {
        const formatted = new Intl.NumberFormat('en-US', { style: 'currency', currency: c, minimumFractionDigits: 0 }).format(0);
        return formatted.replace(/[\d,.\s]+/, '').trim();
    } catch (e) {
        const map = { USD:'$', MXN:'MX$', EUR:'€', GBP:'£', JPY:'¥', BRL:'R$', CAD:'CA$', AUD:'A$', ARS:'$', COP:'$' };
        return map[c] || '$';
    }
}

function formatPrice(amount, currencyCode) {
    const num = parseFloat(amount);
    const code = (currencyCode || 'USD').toUpperCase();
    try {
        return new Intl.NumberFormat('en-US', { style: 'currency', currency: code }).format(isNaN(num) ? 0 : num);
    } catch (e) {
        const sym = getCurrencySymbol(code);
        if (isNaN(num)) return `${sym}0`;
        return `${sym}${num.toFixed(code === 'JPY' ? 0 : 2)}`;
    }
}

function getTournamentWeightUnit() {
    if (!currentTournamentId) return 'kg';
    const tournaments = db.load('tournaments');
    const t = tournaments.find(t => String(t.id) === String(currentTournamentId));
    return t?.weight_unit || t?.weightUnit || 'kg';
}

/**
 * Tab-key handler for judge score inputs.
 * Pressing Tab in a judge field moves focus to the next field rather than
 * concatenating a tab character into the current input value.
 *
 * @param {KeyboardEvent} e      - the keydown event
 * @param {string}        prefix - field id prefix ('rl-judge' or 'judge')
 * @param {number}        idx    - current judge index (0-based)
 */
function _judgeTabHandler(e, prefix, idx) {
    if (e.key !== 'Tab') return;
    e.preventDefault();
    const next = document.getElementById(`${prefix}-${idx + 1}-score`);
    if (next) {
        next.focus();
        next.select();
    } else {
        // Last field — move to the Submit & Next button
        const submitBtn = document.querySelector(
            '#operator-scoreboard-content .btn-primary[onclick*="submit"],' +
            '#operator-scoreboard-content .btn-primary[onclick*="Submit"]'
        );
        if (submitBtn) submitBtn.focus();
    }
}

/**
 * Format a weight value for display: appends the tournament weight unit, or
 * returns 'N/A' when the value is null / undefined / empty string.
 */
function fmtWeight(w) {
    if (w == null || w === '') return 'N/A';
    return `${w}${getTournamentWeightUnit()}`;
}

/**
 * Format a competitor's age for display.
 * Returns "Xage yrs" when age is known, or "N/A" when date of birth is missing.
 */
function fmtAge(comp) {
    const age = getDisplayAge(comp);
    return age === '-' ? 'N/A' : `${age} yrs`;
}

/**
 * Normalise a competitor weight value to a target unit.
 * competitor.weight is always stored in the tournament's weight_unit.
 * Division-tree weight ranges may be in a different unit (e.g. after a
 * "relabel only" switch), so we must convert before comparing.
 *
 * @param {number} weight      - raw value from competitor record
 * @param {string} fromUnit    - unit the value is stored in ('kg'|'lbs')
 * @param {string} toUnit      - unit the ranges are expressed in
 * @returns {number}           - converted value (or original if units match)
 */
function _normaliseWeightForComparison(weight, fromUnit, toUnit) {
    if (!weight || fromUnit === toUnit) return weight;
    return fromUnit === 'kg'
        ? weight * 2.20462   // kg → lbs
        : weight * 0.453592; // lbs → kg
}

function getTournamentCurrency() {
    if (!currentTournamentId) return 'USD';
    const tournaments = db.load('tournaments');
    const t = tournaments.find(t => String(t.id) === String(currentTournamentId));
    return t?.currency || 'USD';
}

async function searchTeams(query) {
    const suggestionsDiv = document.getElementById('team-suggestions');
    const infoDiv       = document.getElementById('team-selection-info');
    _selectedTeamData   = null;
    if (infoDiv) infoDiv.classList.add('hidden');

    if (!query || query.trim().length < 1) {
        if (suggestionsDiv) suggestionsDiv.style.display = 'none';
        return;
    }

    // Find the team event currently selected
    const checkboxes = document.querySelectorAll('input[name="events"]:checked');
    let teamEventId = null;
    const eventTypes = db.load('eventTypes');
    checkboxes.forEach(cb => {
        const ev = eventTypes.find(e => e.id === cb.value);
        if (ev && ev.teamSize > 1) teamEventId = cb.value;
    });

    if (!teamEventId || !currentTournamentId) {
        if (suggestionsDiv) suggestionsDiv.style.display = 'none';
        return;
    }

    try {
        const res = await fetch(
            `/api/tournaments/${currentTournamentId}/teams/public?eventId=${teamEventId}&name=${encodeURIComponent(query)}`,
            { credentials: 'include' }
        );
        if (!res.ok) { if (suggestionsDiv) suggestionsDiv.style.display = 'none'; return; }
        const data = await res.json();

        const teamEvent = eventTypes.find(e => e.id === teamEventId);
        const maxSize = teamEvent?.teamSize || 2;

        // Only show teams that aren't full
        const joinable = (data.teams || []).filter(t => t.memberCount < maxSize);

        if (!suggestionsDiv) return;
        suggestionsDiv.innerHTML = '';

        joinable.forEach(t => {
            const div = document.createElement('div');
            div.style.cssText = 'padding:10px 14px; cursor:pointer; border-bottom:1px solid var(--glass-border); display:flex; justify-content:space-between; align-items:center;';
            div.onmousedown = (e) => { e.preventDefault(); selectExistingTeam(t, maxSize); };
            div.onmouseover = () => div.style.background = 'rgba(255,255,255,0.08)';
            div.onmouseout  = () => div.style.background = '';
            div.innerHTML = `
                <span><strong>${_escapeHtml(t.name)}</strong></span>
                <span style="font-size:0.8rem; color:var(--text-secondary);">${t.memberCount}/${maxSize} members</span>
            `;
            suggestionsDiv.appendChild(div);
        });

        // Always offer "Create new team"
        const trimmed = query.trim();
        const createDiv = document.createElement('div');
        createDiv.style.cssText = 'padding:10px 14px; cursor:pointer; display:flex; align-items:center; gap:8px; color:var(--accent); font-weight:600;';
        createDiv.onmousedown = (e) => { e.preventDefault(); confirmNewTeam(trimmed); };
        createDiv.onmouseover = () => createDiv.style.background = 'rgba(255,255,255,0.08)';
        createDiv.onmouseout  = () => createDiv.style.background = '';
        createDiv.textContent = `+ Create "${trimmed}" as new team`;
        suggestionsDiv.appendChild(createDiv);

        suggestionsDiv.style.display = 'block';
    } catch(e) {
        if (suggestionsDiv) suggestionsDiv.style.display = 'none';
    }
}

function selectExistingTeam(teamData, maxSize) {
    const input = document.getElementById('team-name-input');
    const suggestionsDiv = document.getElementById('team-suggestions');
    const infoDiv = document.getElementById('team-selection-info');
    if (input) input.value = teamData.name;
    if (suggestionsDiv) suggestionsDiv.style.display = 'none';
    _selectedTeamData = { code: teamData.code, id: teamData.id, name: teamData.name, memberCount: teamData.memberCount, isNew: false };
    if (infoDiv) {
        infoDiv.classList.remove('hidden');
        infoDiv.innerHTML = `
            <span style="color:#22c55e; font-weight:600;">✓ Joining existing team</span><br>
            <strong>${_escapeHtml(teamData.name)}</strong> — ${teamData.memberCount + 1}/${maxSize} members (including you)
            <br><span style="color:var(--text-secondary); font-size:0.8rem;">No payment required to join an existing team</span>
        `;
    }
}

function confirmNewTeam(name) {
    const input = document.getElementById('team-name-input');
    const suggestionsDiv = document.getElementById('team-suggestions');
    const infoDiv = document.getElementById('team-selection-info');
    if (input) input.value = name;
    if (suggestionsDiv) suggestionsDiv.style.display = 'none';
    _selectedTeamData = { code: null, name: name, isNew: true };
    if (infoDiv) {
        infoDiv.classList.remove('hidden');
        infoDiv.innerHTML = `
            <span style="color:var(--accent); font-weight:600;">+ Creating new team</span><br>
            <strong>${_escapeHtml(name)}</strong> — You will be the team captain.
            <br><span style="color:var(--text-secondary); font-size:0.8rem;">Teammates search by team name to join you — no code sharing needed.</span>
        `;
    }
}

function hideTeamSuggestions() {
    // Slight delay so onmousedown fires before blur hides the dropdown
    setTimeout(() => {
        const s = document.getElementById('team-suggestions');
        if (s) s.style.display = 'none';
        // If user blurred without selecting, treat typed value as new team name
        const input = document.getElementById('team-name-input');
        if (input && input.value.trim() && !_selectedTeamData) {
            confirmNewTeam(input.value.trim());
        }
    }, 200);
}

function generateTeamCode() {
    // Internal — generates a unique 6-character code (still used for backend storage)
    const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
    let code = 'TEAM-';
    for (let i = 0; i < 6; i++) {
        code += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    return code;
}

