// Competitor Registration
document.getElementById('competitor-form').addEventListener('submit', async (e) => {
    e.preventDefault();

    // Ensure tournament is selected
    if (!ensureTournamentSelected()) {
        return;
    }

    // Validate required fields (form uses novalidate — we handle validation here).
    // Only check fields that are visible — some fields (weight, experience) are hidden
    // by the tournament's registration field settings and must be skipped when not shown.
    const _isVisible = (id) => {
        const el = document.getElementById(id);
        if (!el) return false;
        const group = el.closest('.form-group');
        return !group || !group.classList.contains('hidden');
    };
    const _val = (id) => (document.getElementById(id)?.value || '').trim();
    const missingFields = [];
    if (!_val('firstName'))    missingFields.push('First Name');
    if (!_val('lastName'))     missingFields.push('Last Name');
    if (!_val('dateOfBirth'))  missingFields.push('Date of Birth');
    if (!_val('comp-email'))   missingFields.push('Email');
    if (missingFields.length > 0) {
        showMessage(`Please fill in: ${missingFields.join(', ')}`, 'error');
        const firstMissing = ['firstName','lastName','dateOfBirth','weight','rank','gender'].find(id => _isVisible(id) && !_val(id));
        if (firstMissing) document.getElementById(firstMissing)?.focus();
        return;
    }

    const clubName = _val('club');
    const _clubAcademyId = document.getElementById('club-academy-id')?.value || null;
    let clubLogo = null;

    if (clubName) {
        const clubs = db.load('clubs');
        const existingClub = clubs.find(c => c.name === clubName);
        if (!existingClub) {
            db.add('clubs', { name: clubName, logo: currentNewClubLogoData || null, country: '', createdAt: new Date().toISOString() });
            _syncClubsToServer().catch(e => console.warn('[clubs] competitor-form sync failed:', e.message));
        } else if (currentNewClubLogoData) {
            existingClub.logo = currentNewClubLogoData;
            db.save('clubs', clubs);
            _syncClubsToServer().catch(e => console.warn('[clubs] competitor-form sync failed:', e.message));
        }
        clubLogo = currentNewClubLogoData || getClubLogo(clubName);
    }

    // Use the ordered selection array maintained by loadEventCheckboxes/updateEventOrder
    const eventTypes = db.load('eventTypes');

    // Validate at least one event selected
    if (selectedEventOrder.length === 0) {
        showMessage('Please select at least one event to register for.', 'error');
        return;
    }

    // Build selected events from the ordered array
    const selectedEvents = [...selectedEventOrder];

    // Handle team registration (new name-search flow — no team codes shown to users)
    let teamCode = null;
    let teamName = null;
    let teamEventId = null; // declared here so ADD mode block can use it for new-team creation
    const teamSection = document.getElementById('team-registration-section');

    if (teamSection && !teamSection.classList.contains('hidden')) {
        // Resolve team data — _selectedTeamData is set by selectExistingTeam / confirmNewTeam / hideTeamSuggestions
        const teamNameInput = document.getElementById('team-name-input')?.value.trim();
        if (!teamNameInput) {
            showMessage('Please enter a team name', 'error');
            return;
        }

        // If user typed but never clicked a suggestion, treat as new team
        if (!_selectedTeamData) {
            _selectedTeamData = { code: null, name: teamNameInput, isNew: true };
        }

        // Find the team event in the registration
        teamEventId = selectedEvents.find(eventId => {
            const ev = eventTypes.find(e => e.id === eventId);
            return ev && (ev.teamSize > 1 || ev.team_size > 1);
        });

        if (_selectedTeamData.isNew) {
            // ── Creating a new team ──
            // Team is created on the server inside the ADD mode block below so we
            // have the competitor's data to set as the first member. No local write.
            teamName = _selectedTeamData.name;
            // teamCode stays null here — will be set from server response
        } else {
            // ── Joining an existing team ──
            teamCode = _selectedTeamData.code;
            teamName = _selectedTeamData.name;

            if (!teamCode) {
                showMessage('Invalid team selection. Please search and select a team.', 'error');
                return;
            }
            // Server validates capacity atomically when we POST the member
        }
    }

    const dateOfBirth = document.getElementById('dateOfBirth').value;

    // Reject future dates of birth — a negative age breaks division auto-assignment.
    if (dateOfBirth) {
        const dobDate = new Date(dateOfBirth + 'T00:00:00');
        const today = new Date();
        today.setHours(0, 0, 0, 0);
        if (dobDate > today) {
            showMessage('Date of birth cannot be in the future.', 'error');
            document.getElementById('dateOfBirth').focus();
            return;
        }
    }

    const tournament = getCurrentTournament();

    const competitorFields = {
        firstName: document.getElementById('firstName').value,
        lastName: document.getElementById('lastName').value,
        dateOfBirth: dateOfBirth,
        weight: parseFloat(document.getElementById('weight').value),
        rank: document.getElementById('rank').value,
        experience: (() => { const el = document.getElementById('experience'); if (!el) return null; if (el.tagName === 'SELECT') return el.value || null; const v = parseFloat(el.value); return isNaN(v) ? null : v; })(),
        gender: document.getElementById('gender').value,
        email: _val('comp-email') || null,
        phone: _val('comp-phone') || null,
        club: clubName,
        clubLogo: clubLogo,
        academyId: _clubAcademyId || null,
        photo: currentPhotoData || null,
        events: selectedEvents,
        primaryEventId: selectedEvents[0] || null,
        pricing: calculatePricingBreakdown(selectedEvents, eventTypes, tournament),
        paymentStatus: document.getElementById('payment-status')?.value || 'unpaid',
        teamCode: teamCode,
        teamName: teamName,
        discountCodeId:   _activeDiscount?.id   || null,
        discountCode:     _activeDiscount?.code  || null,
        discountAmount:   _activeDiscount ? (() => {
            const { breakdown, total } = calculatePricingBreakdown(selectedEvents, eventTypes, tournament);
            const d = _activeDiscount;
            let amt = 0;
            if (d.scope === 'event' && d.event_id) {
                const item = breakdown.find(b => String(b.eventId) === String(d.event_id));
                if (item) amt = d.discount_type === 'percentage' ? item.price * (d.discount_value / 100) : Math.min(d.discount_value, item.price);
            } else {
                amt = d.discount_type === 'percentage' ? total * (d.discount_value / 100) : Math.min(d.discount_value, total);
            }
            return Math.round(amt * 100) / 100;
        })() : 0,
    };

    if (editingCompetitorId) {
        // ═══ EDIT MODE — update existing competitor (mirrors club edit pattern) ═══
        const allCompetitors = db.load('competitors');
        const compIndex = allCompetitors.findIndex(c => c.id === editingCompetitorId);

        if (compIndex === -1) {
            showMessage('Competitor not found', 'error');
            return;
        }

        const oldCompetitor = { ...allCompetitors[compIndex] };

        // Preserve existing payment status if not changed via dropdown
        if (!document.getElementById('payment-status')) {
            competitorFields.paymentStatus = oldCompetitor.paymentStatus || 'unpaid';
        }

        // Update using spread — preserve id, registrationDate, tournamentId
        allCompetitors[compIndex] = {
            ...allCompetitors[compIndex],
            ...competitorFields,
            updatedAt: new Date().toISOString()
        };

        const updatedCompetitor = allCompetitors[compIndex];

        // Per-record PUT to server — immediate DB write
        setSyncIndicator('syncing');
        const putRes = await fetch(`/api/tournaments/${currentTournamentId}/competitors/${editingCompetitorId}`, {
            method: 'PUT',
            credentials: 'include',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ competitor: { ...updatedCompetitor } }),
        });
        if (putRes.status === 401) { showMessage('Session expired. Please reload.', 'error'); return; }
        if (!putRes.ok) { showMessage('Could not save competitor — please try again.', 'error'); return; }
        const { competitor: savedComp } = await putRes.json();
        // Update local cache with server-confirmed data
        const freshAll = db.load('competitors');
        const freshIdx = freshAll.findIndex(c => String(c.id) === String(editingCompetitorId));
        if (freshIdx !== -1) { freshAll[freshIdx] = { ...freshAll[freshIdx], ...savedComp }; db.save('competitors', freshAll); }
        setSyncIndicator('ok');

        // Update competitor data embedded in brackets (they store full objects, not IDs)
        updateCompetitorInBrackets(editingCompetitorId, savedComp);

        showMessage('Competitor updated successfully!', 'success');
        // Server auto-assign handles division re-assignment — no client-side call needed

        editingCompetitorId = null;
    } else {
        // ═══ ADD MODE — create new competitor via per-record POST ═══

        // ── Duplicate guard ──────────────────────────────────────────────────
        const _existingAll = db.load('competitors') || [];
        const _dup = _existingAll.find(c =>
            c.firstName?.toLowerCase()  === competitorFields.firstName.toLowerCase()  &&
            c.lastName?.toLowerCase()   === competitorFields.lastName.toLowerCase()   &&
            c.dateOfBirth               === competitorFields.dateOfBirth
        );
        if (_dup) {
            showMessage(
                `${competitorFields.firstName} ${competitorFields.lastName} (DOB ${competitorFields.dateOfBirth}) is already registered. Use Edit to make changes.`,
                'error'
            );
            return;
        }
        // ────────────────────────────────────────────────────────────────────

        const competitor = {
            ...competitorFields,
            registrationDate: new Date().toISOString(),
            tournamentId: currentTournamentId
        };

        // Per-record POST to server — immediate DB write with server-assigned UUID
        setSyncIndicator('syncing');
        const postRes = await fetch(`/api/tournaments/${currentTournamentId}/competitors`, {
            method: 'POST',
            credentials: 'include',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ competitor }),
        });
        if (postRes.status === 401) { showMessage('Session expired. Please reload.', 'error'); return; }
        if (!postRes.ok) { showMessage('Could not save competitor — please check your connection.', 'error'); return; }
        const { competitor: savedComp } = await postRes.json();
        // Update local cache — skip if WebSocket already added this record (race condition)
        if (!_inMemoryCompetitors.find(c => String(c.id) === String(savedComp.id))) {
            _inMemoryCompetitors.push(savedComp);
        }
        competitor.id = savedComp.id; // Update the local reference for team code assignment below
        db.save('competitors', _inMemoryCompetitors);
        setSyncIndicator('ok');

        const competitorId = savedComp.id;

        // ── API-first team handling — no local cache writes, no full-replace sync ──
        if (_selectedTeamData?.isNew && teamName && teamEventId) {
            // New team: POST to server first to get the authoritative team_code.
            // The competitor's contact info becomes the first member entry.
            const newTeamRes = await fetch(`/api/tournaments/${currentTournamentId}/teams`, {
                method: 'POST',
                credentials: 'include',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    event_id: teamEventId,
                    team_name: teamName,
                    members: [{
                        name: `${competitorFields.firstName} ${competitorFields.lastName}`.trim(),
                        first_name: competitorFields.firstName,
                        last_name: competitorFields.lastName,
                        email: competitorFields.email || null,
                        user_id: null,
                        is_registrant: true,
                    }],
                }),
            });
            if (newTeamRes.status === 409) {
                showMessage(
                    `A team named "${teamName}" already exists for this event. ` +
                    `Search for it and select it to join instead.`,
                    'error'
                );
                // Competitor was already saved — show partial success, then reload
                await _loadCompetitorsFromServer();
                loadCompetitors(true);
            } else if (!newTeamRes.ok) {
                const errData = await newTeamRes.json().catch(() => ({}));
                console.warn('[teams] Failed to create team:', errData.error);
                showMessage(
                    `Competitor saved, but team "${teamName}" could not be created: ` +
                    (errData.error || 'unknown error'),
                    'error'
                );
            } else {
                const { team: serverTeam } = await newTeamRes.json();
                teamCode = serverTeam.team_code;
                // Back-patch the competitor record with the server-assigned team code
                await fetch(`/api/tournaments/${currentTournamentId}/competitors/${competitorId}`, {
                    method: 'PUT',
                    credentials: 'include',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ competitor: { ...savedComp, teamCode, teamName } }),
                }).catch(e => console.warn('[teams] Failed to update competitor team code:', e.message));
            }

        } else if (!_selectedTeamData?.isNew && teamCode && _selectedTeamData?.id) {
            // Existing team: atomically append this member using PostgreSQL || operator.
            // No read-modify-write — safe for concurrent registrations.
            const memberAddRes = await fetch(
                `/api/tournaments/${currentTournamentId}/teams/${_selectedTeamData.id}/members`,
                {
                    method: 'POST',
                    credentials: 'include',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        member: {
                            name: `${competitorFields.firstName} ${competitorFields.lastName}`.trim(),
                            first_name: competitorFields.firstName,
                            last_name: competitorFields.lastName,
                            email: competitorFields.email || null,
                            user_id: null,
                        },
                    }),
                }
            );
            if (!memberAddRes.ok) {
                console.warn('[teams] Failed to add member to existing team');
            }
        }

        // Refresh teams tab from server (single source of truth)
        if (teamCode || _selectedTeamData?.isNew) {
            _loadTeamsFromServer().catch(() => {});
        }

        // Server handles auto-division assignment — autoUpdateBrackets still runs client-side
        try {
            autoUpdateBracketsAfterRegistration(savedComp);
        } catch (error) {
            console.error('Auto-bracket update failed:', error);
        }

        // Show success message — team info if applicable
        const _hadTeamIntent = teamName && (teamCode || _selectedTeamData?.isNew);
        if (_hadTeamIntent) {
            if (_selectedTeamData?.isNew) {
                showMessage(`Competitor registered! Team "${teamName}" created. Teammates can join by searching for "${teamName}" during their registration.`, 'success');
                showToast(`Team "${teamName}" created — teammates search by name to join`, 'success');
            } else {
                showMessage(`Competitor registered and joined team "${teamName}"!`, 'success');
            }
        } else {
            showMessage('Competitor registered successfully!');
        }
    }

    hideCompetitorForm();
    // Sync clubs once, then reload both views
    syncCompetitorClubsToTable();
    loadCompetitors(true);
    loadClubs(true);
    loadDashboard();
    currentPhotoData = null;
});

// Update competitor data embedded in all brackets
function updateCompetitorInBrackets(competitorId, updatedCompetitor) {
    const brackets = JSON.parse(_msGet(_scopedKey('brackets')) || '{}');
    let changed = false;

    // Fields to copy into embedded competitor objects
    const fieldsToUpdate = ['firstName', 'lastName', 'dateOfBirth', 'weight', 'rank',
                            'experience', 'gender', 'club', 'clubLogo', 'photo', 'events'];

    function updateCompObj(comp) {
        if (!comp || comp.id !== competitorId) return false;
        let updated = false;
        fieldsToUpdate.forEach(field => {
            if (comp[field] !== updatedCompetitor[field]) {
                comp[field] = updatedCompetitor[field];
                updated = true;
            }
        });
        return updated;
    }

    for (const bracketId in brackets) {
        const bracket = brackets[bracketId];

        if (bracket.type === 'single-elimination' || bracket.type === 'round-robin' || bracket.type === 'repechage') {
            [bracket.matches, bracket.repechageA, bracket.repechageB].forEach(arr => {
                (arr || []).forEach(match => {
                    if (updateCompObj(match.redCorner)) changed = true;
                    if (updateCompObj(match.blueCorner)) changed = true;
                    if (updateCompObj(match.winner)) changed = true;
                });
            });
            // Also update competitors array if it exists
            (bracket.competitors || []).forEach((comp, idx) => {
                if (comp && comp.id === competitorId) {
                    fieldsToUpdate.forEach(f => { bracket.competitors[idx][f] = updatedCompetitor[f]; });
                    changed = true;
                }
            });
        } else if (bracket.type === 'double-elimination') {
            (bracket.winners || []).forEach(match => {
                if (updateCompObj(match.redCorner)) changed = true;
                if (updateCompObj(match.blueCorner)) changed = true;
                if (updateCompObj(match.winner)) changed = true;
            });
            (bracket.losers || []).forEach(match => {
                if (updateCompObj(match.redCorner)) changed = true;
                if (updateCompObj(match.blueCorner)) changed = true;
                if (updateCompObj(match.winner)) changed = true;
            });
            if (bracket.finals) {
                if (updateCompObj(bracket.finals.redCorner)) changed = true;
                if (updateCompObj(bracket.finals.blueCorner)) changed = true;
                if (updateCompObj(bracket.finals.winner)) changed = true;
            }
            (bracket.competitors || []).forEach((comp, idx) => {
                if (comp && comp.id === competitorId) {
                    fieldsToUpdate.forEach(f => { bracket.competitors[idx][f] = updatedCompetitor[f]; });
                    changed = true;
                }
            });
        } else if (bracket.type === 'pool-play') {
            (bracket.pools || []).forEach(pool => {
                (pool.competitors || []).forEach((comp, idx) => {
                    if (comp && comp.id === competitorId) {
                        fieldsToUpdate.forEach(f => { pool.competitors[idx][f] = updatedCompetitor[f]; });
                        changed = true;
                    }
                });
                (pool.matches || []).forEach(match => {
                    if (updateCompObj(match.redCorner)) changed = true;
                    if (updateCompObj(match.blueCorner)) changed = true;
                    if (updateCompObj(match.winner)) changed = true;
                });
            });
        } else if (bracket.type === 'ranking-list') {
            (bracket.entries || []).forEach(entry => {
                if (updateCompObj(entry.competitor)) changed = true;
            });
            (bracket.competitors || []).forEach((comp, idx) => {
                if (comp && comp.id === competitorId) {
                    fieldsToUpdate.forEach(f => { bracket.competitors[idx][f] = updatedCompetitor[f]; });
                    changed = true;
                }
            });
        } else if (bracket.type === 'kata-flags' || bracket.type === 'kata-points') {
            (bracket.rounds || []).forEach(round => {
                (round.performances || []).forEach(perf => {
                    if (updateCompObj(perf.competitor)) changed = true;
                });
            });
            (bracket.competitors || []).forEach((comp, idx) => {
                if (comp && comp.id === competitorId) {
                    fieldsToUpdate.forEach(f => { bracket.competitors[idx][f] = updatedCompetitor[f]; });
                    changed = true;
                }
            });
        }
    }

    if (changed) {
        saveBrackets(brackets);
    }
}

/**
 * ═══════════════════════════════════════════════════════════════════════════
 * AUTO-DIVISION GENERATION SYSTEM
 * ═══════════════════════════════════════════════════════════════════════════
 *
 * PURPOSE: Automatically assign competitors to divisions and generate brackets
 *
 * FLOW:
 * 1. Competitor registers for event (e.g., "Kata Competition")
 * 2. Find all templates for that event
 * 3. Match competitor to templates based on criteria (age, gender, etc.)
 * 4. Validate: 0 matches = error, 1 match = assign, 2+ matches = overlap error
 * 5. Create/update division based on template
 * 6. Auto-generate bracket for division
 *
 * ADDED: 2026-02-14
 * ═══════════════════════════════════════════════════════════════════════════
 */

function autoAssignToDivisions(competitor, competitorId) {

    const eventTypes = db.load('eventTypes');
    const freshDivisions = db.load('divisions');

    // Find all events (including the default/primary event) that have division templates configured
    const eventsWithTemplates = Object.keys(freshDivisions).filter(eventId => {
        const event = eventTypes.find(e => String(e.id) === String(eventId));
        return event && freshDivisions[eventId]?.templates?.length > 0;
    });

    if (eventsWithTemplates.length === 0) {
        return;
    }

    // Load all tournament competitors (including the newly saved one) and calculate ages.
    // This mirrors exactly what the "Generate Divisions" button does so division names
    // are always consistent — both use buildDivisions() with range.label joining.
    const allCompetitors = db.load('competitors');
    const competitors = currentTournamentId
        ? allCompetitors.filter(c => c.tournamentId === currentTournamentId)
        : allCompetitors;

    const tournaments = db.load('tournaments');
    const currentTournament = tournaments.find(t => t.id === currentTournamentId);
    const ageCalculationMethod = currentTournament?.ageCalculationMethod || 'aau-standard';
    const eventDate = currentTournament?.date || new Date();

    const competitorsWithAge = competitors.map(comp => ({
        ...comp,
        age: comp.dateOfBirth ? calculateAge(comp.dateOfBirth, ageCalculationMethod, eventDate) : (comp.age || 0)
    }));

    // Regenerate divisions for every event with templates using the same
    // buildDivisions() logic as the manual Generate button
    eventsWithTemplates.forEach(eventId => {
        const event = eventTypes.find(e => String(e.id) === String(eventId));
        const eventData = freshDivisions[eventId];

        // Only pass competitors registered for this specific event
        // Use string comparison — IDs may be numbers (CSV) or strings (registrations)
        const eventCompetitors = competitorsWithAge.filter(c =>
            c.events && c.events.some(id => String(id) === String(eventId))
        );

        const generatedDivisions = {};
        eventData.templates.forEach(template => {
            const result = buildDivisions(eventCompetitors, template.criteria);
            Object.assign(generatedDivisions, result);
        });

        freshDivisions[eventId] = {
            templates: eventData.templates,
            generated: generatedDivisions,
            updatedAt: new Date().toISOString()
        };
    });

    _msSet(_scopedKey('divisions'), JSON.stringify(freshDivisions));
    // Immediately persist to server — no debounce to eliminate the race window
    // where a concurrent page load could overwrite these newly generated divisions.
    _syncDivisionsToServer().catch(e => console.warn('[divisions] auto-assign sync failed:', e.message));
}

/**
 * Returns true if any match in the bracket has already been scored or is in progress.
 * Covers all bracket types: single/double-elimination, repechage, round-robin,
 * pool-play, ranking-list, kata-flags, and kata-points.
 */
function bracketHasScoredMatches(bracket) {
    // Flat match arrays (single-elim, repechage, double-elim, round-robin)
    const flatMatches = [
        ...(bracket.matches    || []),
        ...(bracket.winners    || []),
        ...(bracket.losers     || []),
        ...(bracket.repechageA || []),
        ...(bracket.repechageB || []),
    ];
    if (bracket.finals) flatMatches.push(bracket.finals);
    if (bracket.reset)  flatMatches.push(bracket.reset);
    if (flatMatches.some(m => m && (m.status === 'completed' || m.status === 'in-progress'))) return true;
    // Pool play
    for (const pool of (bracket.pools || []))
        if ((pool.matches || []).some(m => m.status === 'completed')) return true;
    // Ranking list
    if ((bracket.entries || []).some(e => e.status === 'scored')) return true;
    // Kata rounds (array for kata-flags / kata-points bracket types)
    if (Array.isArray(bracket.rounds))
        for (const round of bracket.rounds)
            if ((round.performances || []).some(p => p.completed)) return true;
    return false;
}

/**
 * Rebuilds a bracket's match structure using the existing bracket's stored settings
 * (type, scoreboard config, seeding method, mat assignment, etc.) with a fresh
 * competitor list. Returns the new bracket — caller saves it.
 */
function regenerateBracketFromSettings(existing, freshCompetitors) {
    const type    = existing.type;
    const name    = existing.divisionName || existing.division;
    const eventId = existing.eventId;
    const seeded  = seedCompetitors([...freshCompetitors], existing.seedingMethod || 'random');

    let newBracket = null;
    if      (type === 'single-elimination')  newBracket = generateSingleEliminationBracket(seeded, name, eventId);
    else if (type === 'double-elimination')  newBracket = generateDoubleEliminationBracket(seeded, name, eventId);
    else if (type === 'repechage')           newBracket = generateRepechageBracket(seeded, name, eventId);
    else if (type === 'round-robin')         newBracket = generateRoundRobinBracket(seeded, name, eventId);
    else if (type === 'pool-play')           newBracket = generatePoolPlayBracket(seeded, name, eventId);
    else if (type === 'ranking-list')        newBracket = generateRankingListBracket(seeded, name, eventId);
    else if (type === 'kata-flags')          newBracket = generateKataFlagsBracket(seeded, name, eventId);
    else if (type === 'aau-kata-flags')      newBracket = generateAAUKataFlagsBracket(seeded, name, eventId);
    else if (type === 'kata-points')         newBracket = generateKataPointsBracket(seeded, name, eventId);
    if (!newBracket) return null;

    // Carry over all original settings
    newBracket.scoreboardConfigId = existing.scoreboardConfigId;
    newBracket.scoreboardConfig   = existing.scoreboardConfig;
    newBracket.matchDuration      = existing.matchDuration;
    newBracket.timing             = calculateBracketTiming(newBracket, existing.scoreboardConfig);
    newBracket.seedingMethod      = existing.seedingMethod;
    newBracket.matAssignment      = existing.matAssignment;
    return newBracket;
}

/**
 * After a competitor is registered and divisions are updated, find every bracket
 * whose division now contains this competitor and auto-regenerate it (if no matches
 * have been scored). If a bracket's tournament has already started, just warn.
 */
function autoUpdateBracketsAfterRegistration(competitor) {
    const competitorId = competitor.id;
    if (!competitorId) return;

    const allDivisions = JSON.parse(_msGet(_scopedKey('divisions')) || '{}');
    const brackets     = JSON.parse(_msGet(_scopedKey('brackets')) || '{}');
    if (Object.keys(brackets).length === 0) return;

    // Build the set of "eventId::divisionName" keys this competitor now belongs to
    const competitorDivisions = new Set();
    Object.entries(allDivisions).forEach(([eventId, eventData]) => {
        Object.entries(eventData.generated || {}).forEach(([divName, comps]) => {
            if ((comps || []).some(c => c.id === competitorId))
                competitorDivisions.add(`${eventId}::${divName}`);
        });
    });
    if (competitorDivisions.size === 0) return;

    const updatedNames = [];
    const lockedNames  = [];

    const updatedKeys = [];
    Object.entries(brackets).forEach(([key, bracket]) => {
        const divName = bracket.divisionName || bracket.division;
        const eventId = String(bracket.eventId);
        if (!competitorDivisions.has(`${eventId}::${divName}`)) return;

        // Idempotency guard: skip if competitor is already in the bracket
        const bracketCompetitors = [
            ...(bracket.competitors || []),
            ...(bracket.matches || []).flatMap(m => [m.redCorner, m.blueCorner]),
        ].filter(Boolean);
        if (bracketCompetitors.some(c => c.id === competitorId)) return;

        if (bracketHasScoredMatches(bracket)) {
            lockedNames.push(divName);
            return;
        }

        const freshCompetitors = allDivisions[eventId]?.generated?.[divName] || [];
        if (freshCompetitors.length < 2) return;

        const newBracket = regenerateBracketFromSettings(bracket, freshCompetitors);
        if (!newBracket) return;

        brackets[key] = newBracket;
        updatedKeys.push(key);
        updatedNames.push(divName);
    });

    if (updatedNames.length > 0) {
        saveBrackets(brackets, updatedKeys);
        _debouncedSync('brackets', _syncBracketsToServer, 2000);
        showToast(`📋 Bracket${updatedNames.length > 1 ? 's' : ''} updated: ${updatedNames.join(', ')}`, 'success');
    }
    if (lockedNames.length > 0) {
        showToast(`⚠️ Matches in progress — bracket not updated: ${lockedNames.join(', ')}`, 'warning');
    }
}

/**
 * After a competitor is approved, find any unstarted brackets in their divisions
 * and regenerate them — using only approved competitors so pending ones stay out.
 */
function _autoReshuffleBracketsForCompetitor(competitor) {
    const competitorId = competitor.id;
    if (!competitorId) return;

    const allDivisions = JSON.parse(_msGet(_scopedKey('divisions')) || '{}');
    const brackets     = JSON.parse(_msGet(_scopedKey('brackets')) || '{}');
    if (Object.keys(brackets).length === 0) return;

    // Find which divisions this competitor belongs to
    const competitorDivisions = new Set();
    Object.entries(allDivisions).forEach(([eventId, eventData]) => {
        Object.entries(eventData.generated || {}).forEach(([divName, comps]) => {
            if (divName === '__unassigned__') return;
            if ((comps || []).some(c => String(c.id) === String(competitorId)))
                competitorDivisions.add(`${eventId}::${divName}`);
        });
    });
    if (competitorDivisions.size === 0) return;

    const updatedNames = [];
    const updatedKeys2 = [];
    const lockedNames  = [];

    Object.entries(brackets).forEach(([key, bracket]) => {
        const divName = bracket.divisionName || bracket.division;
        const eventId = String(bracket.eventId);
        if (!competitorDivisions.has(`${eventId}::${divName}`)) return;

        if (bracketHasScoredMatches(bracket)) {
            lockedNames.push(divName);
            return;
        }

        // Only approved competitors go into brackets
        const allDivComps = allDivisions[eventId]?.generated?.[divName] || [];
        const approvedComps = allDivComps.filter(c => c.approved !== false);
        if (approvedComps.length < 2) return;

        const newBracket = regenerateBracketFromSettings(bracket, approvedComps);
        if (!newBracket) return;

        brackets[key] = newBracket;
        updatedKeys2.push(key);
        updatedNames.push(divName);
    });

    if (updatedNames.length > 0) {
        saveBrackets(brackets, updatedKeys2);
        _debouncedSync('brackets', _syncBracketsToServer, 2000);
        showToast(`Bracket${updatedNames.length > 1 ? 's' : ''} updated: ${updatedNames.join(', ')}`, 'success');
    }
    if (lockedNames.length > 0) {
        showToast(`Division already started — bracket not updated: ${lockedNames.join(', ')}`, 'warning');
    }
}

function findMatchingTemplate(eventId, competitor, competitorAge) {
    const divisions = db.load('divisions');
    const eventData = divisions[eventId];

    if (!eventData || !eventData.templates || eventData.templates.length === 0) {
        return null;
    }

    const matchingTemplates = [];

    eventData.templates.forEach(template => {
        if (competitorMatchesTemplate(competitor, competitorAge, template)) {
            matchingTemplates.push(template);
        }
    });

    // Validate: must match exactly 1 template
    if (matchingTemplates.length === 0) {
        return null; // No match
    } else if (matchingTemplates.length > 1) {
        // Template overlap error
        const templateNames = matchingTemplates.map(t => t.name).join('", "');
        throw new Error(`Template overlap detected: Competitor matches multiple templates ("${templateNames}"). Please fix template criteria to avoid overlaps.`);
    }

    return matchingTemplates[0];
}

function competitorMatchesTemplate(competitor, competitorAge, template) {
    // Check if competitor matches ALL criteria in the template
    if (!template.criteria || template.criteria.length === 0) {
        return true; // No criteria = matches all
    }

    for (const criterion of template.criteria) {
        if (!competitorMatchesCriterion(competitor, competitorAge, criterion)) {
            return false; // Failed one criterion
        }
    }

    return true; // Matches all criteria
}

/**
 * Resolve the effective max age for a range.
 * "Under N" labels (e.g. "Under 13") mean age < N; imported templates
 * sometimes store max = N rather than N-1, causing off-by-one placements.
 */
function _ageRangeMax(range) {
    const m = /^under\s+(\d+)$/i.exec(range.label || '');
    return m ? Math.min(range.max, Number(m[1]) - 1) : range.max;
}

/**
 * Strip external-system event code prefixes from a division name.
 * Smoothcomp and similar platforms prefix division names with codes like
 * "KB-U10E1 - " or "KM-12E3 - ".  These are meaningless to tournament staff
 * and should not be displayed in the operator UI.
 *
 * Pattern matched: one or more uppercase-letter/digit segments separated by
 * hyphens, followed by " - " (space-dash-space).
 * Examples:
 *   "KB-U10E1 - Male 8-9 yrs Beginner"  →  "Male 8-9 yrs Beginner"
 *   "KM-12E3 - Female Under 11 Advanced" →  "Female Under 11 Advanced"
 *   "Regular Division Name"              →  "Regular Division Name" (unchanged)
 */
function stripDivisionCodePrefix(name) {
    if (!name) return name;
    return name.replace(/^[A-Z0-9]+(?:-[A-Z0-9]+)+\s+-\s+/i, '');
}

function competitorMatchesCriterion(competitor, competitorAge, criterion) {
    switch (criterion.type) {
        case 'age':
            // Check if competitor's age falls within ANY of the age ranges
            return criterion.ranges.some(range =>
                competitorAge >= range.min && competitorAge <= _ageRangeMax(range)
            );

        case 'gender':
            // Check if competitor's gender matches ANY of the gender options
            return criterion.ranges.some(range =>
                competitor.gender === range.value
            );

        case 'weight': {
            // competitor.weight is in the tournament's unit; ranges may be in a
            // different unit if the tree was relabelled without recalculating.
            const compW = _normaliseWeightForComparison(
                competitor.weight,
                getTournamentWeightUnit(),
                criterion.weightUnit || getTournamentWeightUnit()
            );
            return criterion.ranges.some(range =>
                compW >= range.min && compW <= range.max
            );
        }

        case 'rank':
            return criterion.ranges.some(range =>
                competitor.rank === range.value
            );

        case 'experience':
            return criterion.ranges.some(range =>
                typeof competitor.experience === 'string'
                    ? (competitor.experience || '').toLowerCase() === (range.label || '').toLowerCase()
                    : competitor.experience >= range.min && competitor.experience <= range.max
            );

        default:
            return true; // Unknown criterion type, assume match
    }
}

function assignToDivisionAndGenerateBracket(competitor, competitorId, eventId, template, competitorAge) {

    // Build division name from template criteria
    const divisionName = buildDivisionNameFromTemplate(competitor, competitorAge, template);

    // Get or create division
    const divisions = db.load('divisions');
    if (!divisions[eventId]) {
        divisions[eventId] = { templates: [], generated: {} };
    }

    if (!divisions[eventId].generated) {
        divisions[eventId].generated = {};
    }

    // Get existing division or create new one
    if (!divisions[eventId].generated[divisionName]) {
        divisions[eventId].generated[divisionName] = [];
    }

    // Add competitor to division (avoid duplicates)
    const divisionCompetitors = divisions[eventId].generated[divisionName];
    if (!divisionCompetitors.find(c => c.id === competitorId)) {
        divisionCompetitors.push(competitor);
    }

    // Save updated divisions
    _msSet(_scopedKey('divisions'), JSON.stringify(divisions));
}

// Build a division name automatically from a competitor's own attributes,
// used when no template is configured for an event.
function buildAutoSingleDivisionName(competitor, age) {
    const parts = [];

    // Age bucket
    if (age < 8)        parts.push('Tiny (≤7)');
    else if (age <= 11) parts.push('Kids (8-11)');
    else if (age <= 14) parts.push('Cadets (12-14)');
    else if (age <= 17) parts.push('Juniors (15-17)');
    else if (age <= 35) parts.push('Adults (18-35)');
    else                parts.push('Masters (36+)');

    // Gender
    if (competitor.gender) parts.push(competitor.gender);

    // Rank group
    const rank = (competitor.rank || '').toLowerCase();
    const rankIdx = RANK_ORDER.indexOf(rank);
    if (rankIdx === -1)     parts.push(competitor.rank || 'Unknown Rank');
    else if (rankIdx <= 9)  parts.push('Kyu');
    else                    parts.push('Dan');

    return parts.join(' | ');
}

function buildDivisionNameFromTemplate(competitor, competitorAge, template) {
    const parts = [template.name];

    template.criteria.forEach(criterion => {
        switch (criterion.type) {
            case 'age':
                const ageRange = criterion.ranges.find(r =>
                    competitorAge >= r.min && competitorAge <= _ageRangeMax(r)
                );
                if (ageRange) {
                    parts.push(ageRange.label);
                } else {
                    // Competitor age doesn't match any range - add placeholder
                    parts.push(`Age ${competitorAge}`);
                    console.warn(`Competitor ${competitor.firstName} ${competitor.lastName} age ${competitorAge} doesn't match any age range`);
                }
                break;

            case 'gender':
                const genderRange = criterion.ranges.find(r => r.value === competitor.gender);
                if (genderRange) {
                    parts.push(genderRange.label || competitor.gender);
                } else if (competitor.gender) {
                    parts.push(competitor.gender);
                } else {
                    parts.push('Gender Unknown');
                    console.warn(`Competitor ${competitor.firstName} ${competitor.lastName} has no gender specified`);
                }
                break;

            case 'weight': {
                const compW2 = _normaliseWeightForComparison(
                    competitor.weight,
                    getTournamentWeightUnit(),
                    criterion.weightUnit || getTournamentWeightUnit()
                );
                const weightRange = criterion.ranges.find(r =>
                    compW2 >= r.min && compW2 <= r.max
                );
                if (weightRange) {
                    parts.push(weightRange.label);
                } else {
                    // Competitor weight doesn't match any range
                    parts.push(`${competitor.weight || '?'}${getTournamentWeightUnit()}`);
                    console.warn(`Competitor ${competitor.firstName} ${competitor.lastName} weight ${competitor.weight}${getTournamentWeightUnit()} doesn't match any weight range`);
                }
                break;
            }

            case 'rank':
                const rankRange = criterion.ranges.find(r => r.value === competitor.rank);
                if (rankRange) {
                    parts.push(rankRange.label || competitor.rank);
                } else if (competitor.rank) {
                    parts.push(competitor.rank);
                } else {
                    parts.push('Rank Unknown');
                    console.warn(`Competitor ${competitor.firstName} ${competitor.lastName} has no rank specified`);
                }
                break;

            case 'experience':
                const expRange = criterion.ranges.find(r =>
                    typeof competitor.experience === 'string'
                        ? (competitor.experience || '').toLowerCase() === (r.label || '').toLowerCase()
                        : competitor.experience >= r.min && competitor.experience <= r.max
                );
                if (expRange) {
                    parts.push(expRange.label);
                } else {
                    parts.push(typeof competitor.experience === 'string' ? competitor.experience : `${competitor.experience || 0} yrs exp`);
                    console.warn(`Competitor ${competitor.firstName} ${competitor.lastName} experience "${competitor.experience}" doesn't match any experience range`);
                }
                break;
        }
    });

    return parts.join(' | ');
}

function autoGenerateBracket(eventId, divisionName, competitors, template) {

    // Deduplicate competitors by ID
    const seenIds = new Set();
    competitors = competitors.filter(c => {
        if (!c || !c.id) return false;
        if (seenIds.has(c.id)) return false;
        seenIds.add(c.id);
        return true;
    });

    if (competitors.length === 0) {
        return;
    }

    // Get scoreboard config
    const scoreboardConfigs = db.load('scoreboardConfigs');
    const scoreboardConfig = scoreboardConfigs.find(c => c.id === parseInt(template.scoreboardType));

    if (!scoreboardConfig) {
        console.error('Scoreboard config not found:', template.scoreboardType);
        return;
    }

    // Create bracket
    const bracketId = `${eventId}_${divisionName.replace(/[^a-zA-Z0-9]/g, '_')}_${generateUniqueId()}`;

    // Determine bracket type: use template setting, or infer from scoreboard type
    let bracketType = template.bracketType;
    if (!bracketType) {
        const baseType = scoreboardConfig.baseType;
        if (baseType === 'kata-points' || baseType === 'kobudo') {
            bracketType = 'pool-play';
        } else {
            bracketType = 'single-elimination';
        }
    }

    const bracket = {
        id: bracketId,
        divisionName: divisionName,
        eventId: eventId,
        type: bracketType,
        scoreboardType: scoreboardConfig.baseType,
        scoreboardConfig: scoreboardConfig,
        competitors: competitors,
        matches: [],
        createdAt: new Date().toISOString(),
        locked: false // Bracket is unlocked initially
    };

    // Generate matches based on bracket type
    generateMatchesForBracket(bracket);

    // Save bracket
    const brackets = JSON.parse(_msGet(_scopedKey('brackets')) || '{}');

    // Remove ALL existing brackets for this division (use filter, not find, to clear duplicates)
    const existingBracketKeys = Object.keys(brackets).filter(key =>
        (brackets[key].divisionName === divisionName || brackets[key].division === divisionName) &&
        String(brackets[key].eventId) === String(eventId)
    );
    for (const existingBracketKey of existingBracketKeys) {
        if (brackets[existingBracketKey].locked) {
            throw new Error(`Division "${divisionName}" bracket is locked (match in progress). Cannot add new competitors.`);
        }
        delete brackets[existingBracketKey];
    }

    brackets[bracketId] = bracket;
    saveBrackets(brackets);

}

function generateMatchesForBracket(bracket) {
    const competitors = bracket.competitors;

    if (bracket.type === 'round-robin') {
        // Round-robin: every competitor faces every other competitor
        const matches = [];
        let matchId = 1;
        for (let i = 0; i < competitors.length; i++) {
            for (let j = i + 1; j < competitors.length; j++) {
                matches.push({
                    id: matchId++,
                    round: 1,
                    redCorner: competitors[i],
                    blueCorner: competitors[j],
                    winner: null,
                    status: 'pending'
                });
            }
        }
        bracket.matches = matches;
        bracket.rounds = competitors.length - 1;

    } else if (bracket.type === 'round-robin-pools') {
        // Round Robin + Elimination: pool phase then single-elimination final
        // Phase 1 is identical to pool-play; advancersPerPool and eliminationRounds
        // are resolved after pool play completes (placeholder finals slots here).
        bracket.type = 'round-robin-pools'; // keep marker
        // Fall through to pool-play logic by duplicating it
        const rrpCompetitors = competitors;
        const rrpTotal = rrpCompetitors.length;
        let rrpNumPools = 1;
        if (rrpTotal > 12) rrpNumPools = 4;
        else if (rrpTotal > 8) rrpNumPools = 3;
        else if (rrpTotal > 5) rrpNumPools = 2;
        const rrpPools = Array.from({ length: rrpNumPools }, () => []);
        let rrpIdx = 0, rrpDir = 1;
        rrpCompetitors.forEach(c => {
            rrpPools[rrpIdx].push(c);
            rrpIdx += rrpDir;
            if (rrpIdx >= rrpNumPools || rrpIdx < 0) { rrpDir *= -1; rrpIdx += rrpDir; }
        });
        bracket.pools = [];
        bracket.matches = [];
        let rrpMatchId = 1;
        rrpPools.forEach((poolComps, pi) => {
            const poolMatches = [];
            for (let i = 0; i < poolComps.length; i++) {
                for (let j = i + 1; j < poolComps.length; j++) {
                    const m = { id: `pool${pi+1}_match${rrpMatchId++}`, redCorner: poolComps[i], blueCorner: poolComps[j], winner: null, score1: null, score2: null, status: 'pending' };
                    poolMatches.push(m); bracket.matches.push(m);
                }
            }
            bracket.pools.push({ poolNumber: pi+1, poolName: String.fromCharCode(65+pi), competitors: poolComps, matches: poolMatches, standings: poolComps.map(c => ({ competitor: c, wins: 0, losses: 0, points: 0, rank: null })) });
        });
        // Elimination phase placeholder — populated once pool standings are finalized
        bracket.eliminationBracket = null;
        bracket.advancersPerPool = 2;
        bracket.rounds = 1;

    } else if (bracket.type === 'pool-play') {
        // Pool play: divide into pools, round-robin within each pool
        const totalCompetitors = competitors.length;
        let numPools = 1;
        if (totalCompetitors > 12) numPools = 4;
        else if (totalCompetitors > 8) numPools = 3;
        else if (totalCompetitors > 5) numPools = 2;

        // Snake draft to balance pools
        const pools = Array.from({ length: numPools }, () => []);
        let poolIndex = 0;
        let direction = 1;
        competitors.forEach(competitor => {
            pools[poolIndex].push(competitor);
            poolIndex += direction;
            if (poolIndex >= numPools || poolIndex < 0) {
                direction *= -1;
                poolIndex += direction;
            }
        });

        // Generate round-robin matches within each pool
        bracket.pools = [];
        bracket.matches = []; // Keep a flat list too for compatibility
        let globalMatchId = 1;

        pools.forEach((poolCompetitors, poolIdx) => {
            const poolMatches = [];
            for (let i = 0; i < poolCompetitors.length; i++) {
                for (let j = i + 1; j < poolCompetitors.length; j++) {
                    const match = {
                        id: `pool${poolIdx + 1}_match${globalMatchId++}`,
                        redCorner: poolCompetitors[i],
                        blueCorner: poolCompetitors[j],
                        winner: null,
                        score1: null,
                        score2: null,
                        status: 'pending'
                    };
                    poolMatches.push(match);
                    bracket.matches.push(match);
                }
            }

            bracket.pools.push({
                poolNumber: poolIdx + 1,
                poolName: String.fromCharCode(65 + poolIdx),
                competitors: poolCompetitors,
                matches: poolMatches,
                standings: poolCompetitors.map(c => ({
                    competitor: c,
                    wins: 0,
                    losses: 0,
                    points: 0,
                    rank: null
                }))
            });
        });

        bracket.finals = [];
        bracket.rounds = 1;

    } else if (bracket.type === 'ranking-list') {
        // Ranking list: no matches, just entries for individual scoring
        bracket.entries = competitors.map((comp, idx) => ({
            competitor: comp,
            performanceOrder: idx + 1,
            score: null,
            rank: null,
            status: 'pending'
        }));
        bracket.matches = [];
        bracket.rounds = 0;

    } else {
        // Single-elimination: use buildBracketSlots so all byes land in round 1.
        // The naive i+=2 loop spread byes across multiple rounds (e.g. 5 competitors
        // gave 1 bye in round 1 + 1 bye in round 2 instead of 3 byes all in round 1).
        const slots = buildBracketSlots(competitors);
        const matches = [];
        for (let i = 0; i < slots.length; i += 2) {
            const red  = slots[i];
            const blue = slots[i + 1];
            if (red === null && blue === null) continue; // phantom slot — skip
            if (blue === null || red === null) {
                // One real competitor, one empty slot → bye
                const real = red ?? blue;
                matches.push({
                    id: matches.length + 1,
                    round: 1,
                    redCorner: real,
                    blueCorner: null,
                    winner: real,
                    status: 'bye'
                });
            } else {
                matches.push({
                    id: matches.length + 1,
                    round: 1,
                    redCorner: red,
                    blueCorner: blue,
                    winner: null,
                    status: 'pending'
                });
            }
        }
        bracket.matches = matches;
        bracket.rounds = Math.ceil(Math.log2(Math.max(competitors.length, 1)));
    }
}

/**
 * BRACKET LOCKING MECHANISM
 *
 * PURPOSE: Lock brackets once competition starts to prevent regeneration
 *
 * WHEN TO LOCK:
 * - Automatically when first match starts (status changes from 'pending' to 'in-progress')
 * - Manually via "Lock Bracket" button
 *
 * WHEN LOCKED:
 * - Cannot regenerate bracket (new registrations rejected for that division)
 * - Cannot delete bracket
 * - Can still update match results
 */

function lockBracket(bracketId) {
    const brackets = JSON.parse(_msGet(_scopedKey('brackets')) || '{}');
    const bracket = brackets[bracketId];

    if (!bracket) {
        showMessage('Bracket not found', 'error');
        return;
    }

    if (bracket.locked) {
        showMessage('Bracket is already locked', 'warning');
        return;
    }

    const confirm = window.confirm(
        `Lock bracket for "${bracket.divisionName}"?\n\n` +
        `Once locked:\n` +
        `✗ Cannot regenerate bracket\n` +
        `✗ Cannot add new competitors\n` +
        `✗ Cannot delete bracket\n\n` +
        `Matches can still be scored.`
    );

    if (!confirm) return;

    bracket.locked = true;
    bracket.lockedAt = new Date().toISOString();
    saveBrackets(brackets);
    _debouncedSync('brackets', _syncBracketsToServer, 2000);

    loadBrackets();
    showMessage(`Bracket locked for "${bracket.divisionName}"`, 'success');
}

function unlockBracket(bracketId) {
    const brackets = JSON.parse(_msGet(_scopedKey('brackets')) || '{}');
    const bracket = brackets[bracketId];

    if (!bracket) {
        showMessage('Bracket not found', 'error');
        return;
    }

    if (!bracket.locked) {
        showMessage('Bracket is not locked', 'warning');
        return;
    }

    const confirm = window.confirm(
        `Unlock bracket for "${bracket.divisionName}"?\n\n` +
        `⚠️ WARNING: This will allow:\n` +
        `• New competitors to be added (bracket will regenerate)\n` +
        `• Bracket to be deleted\n\n` +
        `Only unlock if you need to make changes before competition starts.`
    );

    if (!confirm) return;

    bracket.locked = false;
    delete bracket.lockedAt;
    saveBrackets(brackets);
    _debouncedSync('brackets', _syncBracketsToServer, 2000);

    loadBrackets();
    showMessage(`Bracket unlocked for "${bracket.divisionName}"`, 'success');
}

function autoLockBracketOnMatchStart(bracketId) {
    // Called when a match status changes from 'pending' to 'in-progress'
    const brackets = JSON.parse(_msGet(_scopedKey('brackets')) || '{}');
    const bracket = brackets[bracketId];

    if (!bracket || bracket.locked) return;


    bracket.locked = true;
    bracket.lockedAt = new Date().toISOString();
    bracket.autoLocked = true; // Flag to indicate it was auto-locked
    saveBrackets(brackets);
}

function loadCompetitors(skipSync = false) {
    // Sync clubs first to ensure clubs table is up to date (unless already synced)
    if (!skipSync) {
        syncCompetitorClubsToTable();
    }

    const allCompetitors = db.load('competitors');
    const eventTypes = db.load('eventTypes');
    const tournaments = db.load('tournaments');
    const tbody = document.getElementById('competitors-tbody');

    if (!tbody) return; // Element doesn't exist on this page

    tbody.innerHTML = '';

    // Filter competitors by current tournament
    const competitors = currentTournamentId
        ? allCompetitors.filter(c => c.tournamentId === currentTournamentId)
        : allCompetitors; // Show all if no tournament selected (legacy support)

    // Show tournament filter status
    if (currentTournamentId) {
        const filterBanner = document.getElementById('tournament-filter-banner');
        if (filterBanner) {
            const currentTournamentLocal = tournaments.find(t => t.id === currentTournamentId);
            // Fallback: if tournament isn't in localStorage (server-only record), read name from dropdown
            const tournamentName = currentTournamentLocal?.name ||
                (() => {
                    const sel = document.getElementById('active-tournament');
                    return sel?.selectedOptions?.[0]?.textContent?.trim() || currentTournamentId;
                })();
            filterBanner.textContent = `Showing competitors for: ${tournamentName}`;
            filterBanner.classList.remove('hidden');
        }
    }

    // Get current tournament for age calculation
    const currentTournament = tournaments.find(t => t.id === currentTournamentId);
    const ageCalculationMethod = currentTournament?.ageCalculationMethod || 'aau-standard';
    const eventDate = currentTournament?.date || new Date();

    competitors.forEach(comp => {
        const tr = document.createElement('tr');
        const photoHtml = comp.photo
            ? `<img src="${comp.photo}" class="table-photo" alt="${comp.firstName}">`
            : '<div style="width: 40px; height: 40px; background: var(--glass-bg); border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 12px;">No Photo</div>';

        // Calculate age based on tournament settings
        let ageDisplay = '-';
        if (comp.dateOfBirth) {
            const age = calculateAge(comp.dateOfBirth, ageCalculationMethod, eventDate);
            ageDisplay = age.toString();
        } else if (comp.age) {
            // Legacy support for old competitors with age field
            ageDisplay = comp.age.toString();
        }

        // Get event names for this competitor
        // Use loose string comparison — event IDs may be stored as numbers (director/CSV)
        // or strings (registration path) depending on how they were created.
        let eventsHtml = '-';
        if (comp.events && comp.events.length > 0) {
            const eventNames = comp.events.map(eventId => {
                const event = eventTypes.find(e => String(e.id) === String(eventId));
                return event ? event.name : null;
            }).filter(Boolean);
            if (eventNames.length > 0) eventsHtml = eventNames.join('<br>');
        }

        // Compute pricing on the fly if not stored (e.g. pay-later registrations or director-added)
        let pricingTotal = comp.pricing?.total ?? null;
        if (pricingTotal == null && comp.events?.length > 0) {
            const _et = db.load('eventTypes');
            const _t  = getCurrentTournament();
            pricingTotal = calculatePricingBreakdown(comp.events, _et, _t)?.total ?? null;
        }
        // Last-resort fallback for pay-later competitors added without event data:
        // show the tournament base price so the director knows how much to collect.
        if (pricingTotal == null && (comp.paymentStatus === 'pay_later' || comp.payment_status === 'pay_later')) {
            const _t = getCurrentTournament();
            const base = _t?.pricing?.basePrice ?? _t?.base_event_price;
            if (base != null) pricingTotal = parseFloat(base) || 0;
        }
        const totalDue = pricingTotal != null ? formatPrice(pricingTotal, getTournamentCurrency()) : '-';
        const paymentBadge = getPaymentStatusBadge(comp.paymentStatus || 'unpaid');

        const testBadge = comp.is_test
            ? `<span style="background:rgba(245,158,11,0.2);color:#f59e0b;border-radius:4px;padding:1px 5px;font-size:10px;font-weight:700;margin-right:5px;vertical-align:middle;">TEST</span>`
            : '';

        // Approval status — director-managed competitors AND pay-later public
        // registrations both need an explicit approve step to flow into brackets.
        const isDirectorManaged = comp.source !== 'registration';
        const isPayLaterReg = comp.source === 'registration' && comp.paymentStatus === 'pay_later';
        const needsApprovalUI = isDirectorManaged || isPayLaterReg;
        // Pay-later registrations are auto-approved in the DB, but we track whether
        // the director has explicitly confirmed them via comp.directorApproved.
        const isApproved = isPayLaterReg
            ? comp.directorApproved === true
            : (comp.approved === true || comp.source === 'registration');
        const isBracketLocked = comp.bracket_placed === true && !comp.is_test;

        let approvalCell = '-';
        if (needsApprovalUI) {
            if (isApproved) {
                const lockIcon = isBracketLocked ? ' 🔒' : '';
                const unapproveBtn = isBracketLocked
                    ? `<button class="btn btn-small btn-secondary" disabled title="Competitor is in a bracket — delete the bracket first">Approved${lockIcon}</button>`
                    : `<button class="btn btn-small btn-secondary" onclick="unapproveCompetitor('${comp.id}')">Approved ✓</button>`;
                approvalCell = unapproveBtn;
            } else {
                approvalCell = `<button class="btn btn-small btn-primary" onclick="approveCompetitor('${comp.id}')">Approve</button>`;
            }
        }

        tr.innerHTML = `
            <td>${photoHtml}</td>
            <td>${testBadge}${_escapeHtml(comp.firstName)} ${_escapeHtml(comp.lastName)}</td>
            <td>${ageDisplay}</td>
            <td>${_escapeHtml(comp.gender || '-')}</td>
            <td>${comp.weight ? comp.weight + ' ' + getTournamentWeightUnit() : '-'}</td>
            <td>${_escapeHtml(comp.rank || '-')}</td>
            <td>${_escapeHtml(comp.club || '-')}</td>
            <td style="font-size: 12px;">${eventsHtml}</td>
            <td style="font-size: 13px; font-weight: 600;">${totalDue}</td>
            <td style="cursor: pointer;" onclick="togglePaymentStatus(${comp.id})">${paymentBadge}</td>
            <td>${approvalCell}</td>
            <td>
                ${(comp.source !== 'registration' && !comp.is_test) ? `<button class="btn btn-small" onclick="editCompetitor('${comp.id}')">Edit</button>` : ''}
                <button class="btn btn-small btn-danger" onclick="deleteCompetitor('${comp.id}')">Delete</button>
            </td>
        `;
        tbody.appendChild(tr);
    });

    // Update competitor selects for scoreboard
    updateCompetitorSelects();
}

async function deleteCompetitor(id) {
    if (!currentTournamentId) return;
    const competitors = db.load('competitors');
    const comp = competitors.find(c => String(c.id) === String(id));
    const name = comp ? `${comp.firstName} ${comp.lastName}` : 'this competitor';
    if (!await showConfirm(
        `Delete <strong>${_escapeHtml(name)}</strong>?<br><br>This will permanently remove the competitor from the tournament.`,
        { confirmText: 'Delete', danger: true }
    )) return;
    const res = await fetch(`/api/tournaments/${currentTournamentId}/competitors/${id}`, {
        method: 'DELETE',
        credentials: 'include',
    });
    if (res.status === 401) { showMessage('Session expired. Please reload.', 'error'); return; }
    if (!res.ok) { showMessage('Could not delete competitor.', 'error'); return; }
    // Capture events before removing from cache
    const deletedEvents = comp?.events || [];
    // Update local cache
    db.save('competitors', db.load('competitors').filter(c => String(c.id) !== String(id)));
    loadCompetitors(true);
    loadDashboard();
    // Remove from divisions and heal any brackets that referenced this competitor
    if (deletedEvents.length) _silentlyRegenerateDivisionsForEvents(deletedEvents);
    _removeCompetitorFromBrackets(id);
    showMessage('Competitor deleted successfully!');
}

/**
 * After a competitor is deleted, find every bracket they appear in and either:
 *  - Fully regenerate the bracket (if no scored matches exist), or
 *  - Surgically remove them from bracket.competitors and replace their corner
 *    slot in any still-pending matches with null (bye).
 * Must be called AFTER _silentlyRegenerateDivisionsForEvents so the fresh
 * division lists no longer include the deleted competitor.
 */
function _removeCompetitorFromBrackets(deletedId) {
    const sid = String(deletedId);
    const brackets = JSON.parse(_msGet(_scopedKey('brackets')) || '{}');
    const allDivisions = JSON.parse(_msGet(_scopedKey('divisions')) || '{}');
    let changed = false;

    Object.entries(brackets).forEach(([key, bracket]) => {
        // Check if this competitor appears anywhere in the bracket
        const inCompetitors = (bracket.competitors || []).some(c => String(c.id) === sid);
        const allMatchSlots = [
            ...(bracket.matches || []),
            ...(bracket.winners || []),
            ...(bracket.losers || []),
            ...(bracket.repechageA || []),
            ...(bracket.repechageB || []),
            ...((bracket.pools || []).flatMap(p => p.matches || [])),
            bracket.finals,
            bracket.thirdPlace,
        ].filter(Boolean);
        const inMatches = allMatchSlots.some(m =>
            String(m.redCorner?.id) === sid || String(m.blueCorner?.id) === sid ||
            String(m.winner?.id) === sid
        );
        if (!inCompetitors && !inMatches) return;

        if (!bracketHasScoredMatches(bracket)) {
            // Safe to fully regenerate — use the freshly-updated division list
            const eventId = String(bracket.eventId);
            const divName  = bracket.divisionName || bracket.division;
            const freshComps = allDivisions[eventId]?.generated?.[divName] || [];
            if (freshComps.length < 2) {
                // Division now has < 2 competitors — remove the entire bracket
                delete brackets[key];
            } else {
                const newBracket = regenerateBracketFromSettings(bracket, freshComps);
                if (newBracket) brackets[key] = newBracket;
            }
        } else {
            // Bracket has scored matches — surgical removal only
            // 1. Remove from competitors roster
            bracket.competitors = (bracket.competitors || []).filter(c => String(c.id) !== sid);
            // 2. In pending matches, replace their corner with null (bye)
            const healMatch = m => {
                if (!m || m.status !== 'pending') return;
                if (String(m.redCorner?.id) === sid)  m.redCorner  = null;
                if (String(m.blueCorner?.id) === sid) m.blueCorner = null;
            };
            (bracket.matches || []).forEach(healMatch);
            (bracket.winners || []).forEach(healMatch);
            (bracket.losers  || []).forEach(healMatch);
            (bracket.repechageA || []).forEach(healMatch);
            (bracket.repechageB || []).forEach(healMatch);
            (bracket.pools || []).forEach(p => (p.matches || []).forEach(healMatch));
            healMatch(bracket.finals);
            healMatch(bracket.reset);
            healMatch(bracket.thirdPlace);
        }
        changed = true;
    });

    if (!changed) return;
    _msSet(_scopedKey('brackets'), JSON.stringify(brackets));
    saveBrackets(brackets);
    if (typeof renderBrackets === 'function') renderBrackets();
}

/**
 * Silently re-run division generation for a specific set of event IDs.
 * Called after approve/unapprove so the competitor immediately appears (or
 * disappears) in their division slots without the director having to manually
 * close/reopen the division tree modal.
 *
 * Mirrors generateDivisions() logic but takes an explicit eventId list,
 * skips UI toasts, and does not require the hidden event selector to be set.
 */
function _silentlyRegenerateDivisionsForEvents(eventIds) {
    if (!eventIds || eventIds.length === 0) return;
    if (!currentTournamentId) return;

    // If the division tree modal is still open, flush live templates from the
    // in-memory builder instances into localStorage first.  Without this, the
    // templates are only written on Save & Close, so approvals made while the
    // modal is open would silently find no templates and place no one.
    eventIds.forEach(eid => {
        const liveBuilder = window._dtbRegistry && window._dtbRegistry[eid];
        if (!liveBuilder) return;
        const liveTemplates = liveBuilder.toCriteriaTemplates();
        if (liveTemplates.length === 0) return;
        const snapshot = JSON.parse(_msGet(_scopedKey('divisions')) || '{}');
        if (!snapshot[eid]) snapshot[eid] = { generated: {} };
        snapshot[eid].templates = liveTemplates;
        _msSet(_scopedKey('divisions'), JSON.stringify(snapshot));
    });

    const allDivisions = JSON.parse(_msGet(_scopedKey('divisions')) || '{}');
    const allCompetitors = db.load('competitors');
    const competitors = allCompetitors.filter(c =>
        c.tournamentId === currentTournamentId && c.approved !== false
    );

    const tournaments = db.load('tournaments');
    const currentTournament = tournaments.find(t => t.id === currentTournamentId);
    const ageCalculationMethod = currentTournament?.ageCalculationMethod || 'aau-standard';
    const eventDate = currentTournament?.date || new Date();

    const competitorsWithAge = competitors.map(comp => ({
        ...comp,
        age: comp.dateOfBirth ? calculateAge(comp.dateOfBirth, ageCalculationMethod, eventDate) : (comp.age || 0),
    }));

    let anyChanged = false;
    eventIds.forEach(eventId => {
        const eventData = allDivisions[eventId];
        if (!eventData || !eventData.templates || eventData.templates.length === 0) return;

        // Tree-style templates only — legacy templates are unchanged
        const isTree = typeof eventData.templates[0]?.id === 'string'
                    && typeof eventData.templates[0]?.name === 'string';
        if (!isTree) return;

        const generatedDivisions = {};
        eventData.templates.forEach(template => {
            generatedDivisions[template.name] = [];
            if (!template.criteria || template.criteria.length === 0) return;
            generatedDivisions[template.name] = competitorsWithAge.filter(comp =>
                template.criteria.every(c => _matchesLeafCriterion(comp, c))
            );
        });

        allDivisions[eventId] = {
            ...eventData,
            generated: generatedDivisions,
            updatedAt: new Date().toISOString(),
        };
        anyChanged = true;
    });

    if (!anyChanged) return;
    _msSet(_scopedKey('divisions'), JSON.stringify(allDivisions));
    // Immediately sync — eliminates the race window where concurrent approvals
    // could overwrite each other's division regenerations.
    _syncDivisionsToServer().catch(e => console.warn('[divisions] regen sync failed:', e.message));
    // Refresh UI components that display division data
    if (typeof loadEventTypeCards === 'function') {
        try { loadEventTypeCards(); } catch (_) {}
    }
    if (typeof loadDivisionsView === 'function') {
        try { loadDivisionsView(); } catch (_) {}
    }
}

/**
 * Approve a director-added competitor so they flow into divisions.
 * Deducts 1 credit for real competitors; free for test competitors.
 * Hard-blocks with a "buy credits" message if the director has insufficient credits.
 */
async function approveCompetitor(id) {
    if (!currentTournamentId) return;
    const res = await fetch(`/api/tournaments/${currentTournamentId}/competitors/${id}/approve`, {
        method: 'PATCH',
        credentials: 'include',
    });
    if (res.status === 401) { showMessage('Session expired. Please reload.', 'error'); return; }
    if (res.status === 402) {
        const data = await res.json().catch(() => ({}));
        showMessage(
            `Not enough credits to approve this competitor (balance: ${data.balance ?? 0}). ` +
            `Purchase credits from the Credits section.`,
            'error'
        );
        return;
    }
    if (res.status === 409) {
        const data = await res.json().catch(() => ({}));
        if (data.code === 'DIVISION_STARTED') {
            showMessage(
                `Cannot approve: the division "<strong>${_escapeHtml(data.divisionName || '')}</strong>" has already started. ` +
                `Reset the bracket first to approve new competitors.`,
                'error'
            );
        } else {
            showMessage(data.error || 'Could not approve competitor.', 'error');
        }
        return;
    }
    if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        showMessage(data.error || 'Could not approve competitor.', 'error');
        return;
    }
    const data = await res.json();
    // Update local cache
    const all = db.load('competitors');
    const idx = all.findIndex(c => String(c.id) === String(id));
    if (idx !== -1) {
        all[idx].approved = true;
        // For pay-later registrations track director confirmation separately
        if (all[idx].source === 'registration') all[idx].directorApproved = true;
        db.save('competitors', all);
    }
    loadCompetitors(true);
    loadDashboard();
    // Server auto-assign broadcast will update divisions; also reload locally
    const approvedComp = all[idx];
    if (approvedComp?.events?.length) {
        // After a short delay to let the server broadcast arrive, update brackets
        setTimeout(() => {
            _loadDivisionsFromServer().then(() => {
                // Now reshuffle any unstarted brackets in this competitor's divisions
                // using only approved competitors so pending ones stay out of brackets
                _autoReshuffleBracketsForCompetitor(approvedComp);
                if (typeof loadDivisionsView === 'function') loadDivisionsView();
            });
        }, 500);
    }
    if (data.newCreditBalance !== undefined) {
        showMessage(`Competitor approved. Credit balance: ${data.newCreditBalance}`, 'success');
        _refreshCreditBadge(data.newCreditBalance);
    } else {
        showMessage('Competitor approved.', 'success');
    }
}

/**
 * Unapprove a competitor, removing them from divisions.
 * Refunds 1 credit for real competitors — unless they are bracket-placed
 * (then the server blocks with 403 and the button should already be disabled).
 */
async function unapproveCompetitor(id) {
    if (!currentTournamentId) return;
    const competitors = db.load('competitors');
    const comp = competitors.find(c => String(c.id) === String(id));
    const name = comp ? `${comp.firstName} ${comp.lastName}` : 'this competitor';
    const isReal = comp && !comp.is_test;
    const confirmMsg = isReal
        ? `Unapprove <strong>${_escapeHtml(name)}</strong>?<br><br>They will be removed from all divisions and 1 credit will be refunded.`
        : `Unapprove test competitor <strong>${_escapeHtml(name)}</strong>? They will be removed from all divisions.`;
    if (!await showConfirm(confirmMsg, { confirmText: 'Unapprove', danger: true })) return;

    const res = await fetch(`/api/tournaments/${currentTournamentId}/competitors/${id}/approve`, {
        method: 'DELETE',
        credentials: 'include',
    });
    if (res.status === 401) { showMessage('Session expired. Please reload.', 'error'); return; }
    if (res.status === 403) {
        const data = await res.json().catch(() => ({}));
        if (data.code === 'BRACKET_LOCKED') {
            showMessage('This competitor is in a bracket. Delete the bracket first to unapprove them.', 'error');
        } else {
            showMessage(data.error || 'Not authorized.', 'error');
        }
        return;
    }
    if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        showMessage(data.error || 'Could not unapprove competitor.', 'error');
        return;
    }
    const data = await res.json();
    // Update local cache
    const all = db.load('competitors');
    const idx = all.findIndex(c => String(c.id) === String(id));
    const unapprovedComp = idx !== -1 ? { ...all[idx] } : null;
    if (idx !== -1) { all[idx].approved = false; db.save('competitors', all); }
    loadCompetitors(true);
    loadDashboard();
    // Re-generate divisions so the unapproved competitor is immediately removed
    // from their division slots (credit was refunded — slot should be freed).
    if (unapprovedComp?.events?.length) {
        _silentlyRegenerateDivisionsForEvents(unapprovedComp.events);
    }
    if (data.newCreditBalance !== undefined) {
        showMessage(`Competitor unapproved. Credit refunded — balance: ${data.newCreditBalance}`, 'success');
        _refreshCreditBadge(data.newCreditBalance);
    } else {
        showMessage('Competitor unapproved.', 'success');
    }
}

/**
 * Update the credit balance badge in the nav (if present).
 * Called after approve/unapprove so the director sees their live balance
 * without needing a page reload.
 */
function _refreshCreditBadge(newBalance) {
    const badge = document.getElementById('navbar-credit-count');
    if (badge) badge.textContent = newBalance;
}

// Edit competitor — follows exact same pattern as editClub()
window.editCompetitor = function(id) {
    const competitors = db.load('competitors');
    const comp = competitors.find(c => String(c.id) === String(id));

    if (!comp) {
        showMessage('Competitor not found', 'error');
        return;
    }

    // Set edit mode
    editingCompetitorId = id;

    // Show the form first (loads club dropdown + event checkboxes)
    showCompetitorForm();

    // Pre-populate form fields
    document.getElementById('firstName').value = comp.firstName || '';
    document.getElementById('lastName').value = comp.lastName || '';
    document.getElementById('dateOfBirth').value = comp.dateOfBirth || '';
    document.getElementById('weight').value = comp.weight ?? '';
    document.getElementById('rank').value = comp.rank || '';
    document.getElementById('experience').value = comp.experience ?? '';
    document.getElementById('gender').value = comp.gender || '';

    // Trigger age display update
    const dobInput = document.getElementById('dateOfBirth');
    if (dobInput) dobInput.dispatchEvent(new Event('change'));

    // Set email/phone
    const emailInput = document.getElementById('comp-email');
    if (emailInput) emailInput.value = comp.email || '';
    const phoneInput = document.getElementById('comp-phone');
    if (phoneInput) phoneInput.value = comp.phone || '';

    // Set club text input
    const clubInput = document.getElementById('club');
    if (clubInput && comp.club) clubInput.value = comp.club;
    const clubAcadIdInput = document.getElementById('club-academy-id');
    if (clubAcadIdInput) clubAcadIdInput.value = comp.academyId || '';

    // Reload event checkboxes with saved ordered selection
    selectedEventOrder = comp.events ? [...comp.events] : [];
    loadEventCheckboxes(comp.events || []);

    // Pre-populate payment status
    const paymentStatusEl = document.getElementById('payment-status');
    if (paymentStatusEl) paymentStatusEl.value = comp.paymentStatus || 'unpaid';

    // Handle team fields (new name-search UI)
    if (comp.teamCode || comp.teamName) {
        const teamSection = document.getElementById('team-registration-section');
        if (teamSection && !teamSection.classList.contains('hidden')) {
            const nameInput = document.getElementById('team-name-input');
            if (nameInput && comp.teamName) {
                nameInput.value = comp.teamName;
                _selectedTeamData = { code: comp.teamCode || null, name: comp.teamName, isNew: false };
            }
        }
    }

    // Handle photo
    if (comp.photo) {
        currentPhotoData = comp.photo;
        const previewImg = document.getElementById('photo-preview-img');
        const previewContainer = document.getElementById('photo-preview');
        if (previewImg) previewImg.src = comp.photo;
        if (previewContainer) previewContainer.classList.remove('hidden');
    } else {
        currentPhotoData = null;
        document.getElementById('photo-preview')?.classList.add('hidden');
    }

    // Update form title to "Edit Competitor"
    const formTitle = document.querySelector('#competitor-form-container h3');
    if (formTitle) formTitle.textContent = 'Edit Competitor';

    // Scroll form into view
    document.getElementById('competitor-form-container')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
};

// ─────────────────────────────────────────────────────────────────────────────
// CSV BULK IMPORT
// ─────────────────────────────────────────────────────────────────────────────

/** Rows parsed & validated from the most recent CSV file selection. */
let _csvImportRows = [];

/** Download a blank template CSV so directors know the expected column names. */
function downloadCSVTemplate() {
    const weightUnit  = getTournamentWeightUnit();        // 'kg' or 'lbs'
    const exampleWt   = weightUnit === 'lbs' ? '72' : '32.5';

    // Pull real event names from the current tournament so the Events column
    // shows what values are actually valid.
    const eventTypes  = db.load('eventTypes') || [];
    const eventNames  = eventTypes.map(e => e.name).join(' | ');
    const exampleEvt  = eventTypes.length > 0 ? eventTypes[0].name : 'Kumite';

    // Instruction rows start with # so spreadsheet apps can show them as comments
    // while the importer (which strips blank/# lines) can safely ignore them.
    const notes = [
        '# ── Competitor Import Template ──────────────────────────────────────────────',
        '# Required columns : firstName, lastName, dateOfBirth, gender, club',
        '# Optional columns : weight, rank, experience, events, paymentStatus',
        `# weight           : number in ${weightUnit} (e.g. ${exampleWt})`,
        '# dateOfBirth      : YYYY-MM-DD format (e.g. 2010-03-15)',
        '# gender           : Male or Female',
        '# experience       : years of training as a whole number (e.g. 3)',
        '# paymentStatus    : paid | unpaid | waived   (default: unpaid)',
        eventNames
            ? `# events           : one or more event names separated by ;  Valid values: ${eventNames}`
            : '# events           : one or more event names separated by ;',
        '# ────────────────────────────────────────────────────────────────────────────',
    ].join('\n');

    const headers = [
        'firstName', 'lastName', 'dateOfBirth', 'gender',
        `weight (${weightUnit})`, 'rank', 'experience (yrs)', 'club',
        'events', 'paymentStatus',
    ];

    const example = [
        'Jane', 'Doe', '2010-03-15', 'Female',
        exampleWt, '3rd Kyu', '2', 'Sunrise Dojo',
        exampleEvt, 'unpaid',
    ];

    // Quote any field that contains a comma
    const csvRow = row => row.map(v => String(v).includes(',') ? `"${v}"` : v).join(',');

    const csv = [notes, csvRow(headers), csvRow(example)].join('\n');
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url  = URL.createObjectURL(blob);
    const a    = document.createElement('a');
    a.href     = url;
    a.download = 'competitor-import-template.csv';
    a.click();
    URL.revokeObjectURL(url);
}

/** Open the OS file picker to choose a CSV file. */
function triggerCSVImport() {
    if (!currentTournamentId) {
        showMessage('Please select a tournament first.', 'error');
        return;
    }
    document.getElementById('csv-import-file')?.click();
}

// Wire up file input → parse + preview
document.getElementById('csv-import-file')?.addEventListener('change', function (e) {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => parseAndPreviewCSV(ev.target.result);
    reader.readAsText(file);
    // Reset so the same file can be re-chosen after a cancel
    e.target.value = '';
});

/**
 * Parse a single CSV line, respecting double-quoted fields that may contain commas.
 * @param {string} line
 * @returns {string[]}
 */
function _parseCSVLine(line) {
    const result = [];
    let current = '';
    let inQuotes = false;
    for (let i = 0; i < line.length; i++) {
        const ch = line[i];
        if (ch === '"') {
            if (inQuotes && line[i + 1] === '"') { current += '"'; i++; }
            else { inQuotes = !inQuotes; }
        } else if (ch === ',' && !inQuotes) {
            result.push(current.trim());
            current = '';
        } else {
            current += ch;
        }
    }
    result.push(current.trim());
    return result;
}

/**
 * Parse raw CSV text, validate every data row, and open the preview modal.
 * @param {string} text - Full contents of the uploaded CSV file.
 */
function parseAndPreviewCSV(text) {
    // Strip blank lines and comment lines (lines starting with #) so that
    // our template's instruction block doesn't break the parse.
    const lines = text.split(/\r?\n/).filter(l => l.trim() && !l.trim().startsWith('#'));
    if (lines.length < 2) {
        showMessage('CSV file must have a header row and at least one data row.', 'error');
        return;
    }

    // Normalise header names: lowercase, strip spaces
    // Normalise: lowercase, strip spaces, strip parenthetical unit hints like "(kg)" or "(yrs)"
    const headers = _parseCSVLine(lines[0]).map(h =>
        h.toLowerCase().replace(/\s*\([^)]*\)/g, '').replace(/\s+/g, '')
    );

    const requiredCols = ['firstname', 'lastname', 'dateofbirth', 'gender', 'club'];
    const missing = requiredCols.filter(c => !headers.includes(c));
    if (missing.length > 0) {
        showMessage(`CSV is missing required columns: ${missing.join(', ')}`, 'error');
        return;
    }

    const existingCompetitors = db.load('competitors');
    const eventTypes           = db.load('eventTypes');
    const validPaymentStatuses = ['unpaid', 'paid', 'partial', 'pay_later', 'waived'];

    _csvImportRows = [];

    for (let i = 1; i < lines.length; i++) {
        const values = _parseCSVLine(lines[i]);
        const row    = {};
        headers.forEach((h, idx) => { row[h] = (values[idx] || '').trim(); });

        const errors   = [];
        const warnings = [];

        // ── Required field presence ──
        if (!row.firstname)    errors.push('First name required');
        if (!row.lastname)     errors.push('Last name required');
        if (!row.dateofbirth)  errors.push('Date of birth required');
        if (!row.gender)       errors.push('Gender required');
        if (!row.club)         errors.push('Club / Dojo required');

        // ── Date of birth validation ──
        if (row.dateofbirth) {
            const dob   = new Date(row.dateofbirth + 'T00:00:00');
            const today = new Date();
            today.setHours(0, 0, 0, 0);
            if (isNaN(dob.getTime())) {
                errors.push('Invalid date of birth — use YYYY-MM-DD');
            } else if (dob > today) {
                errors.push('Date of birth cannot be in the future');
            }
        }

        // ── Gender validation ──
        if (row.gender && !['male', 'female'].includes(row.gender.toLowerCase())) {
            errors.push('Gender must be "Male" or "Female"');
        }

        // ── Numeric field validation ──
        if (row.weight     && isNaN(parseFloat(row.weight)))     errors.push('Weight must be a number');
        // Experience can be a numeric value (years) or a label string (e.g. "Beginner")

        // ── Payment status ──
        const psRaw = (row.paymentstatus || '').toLowerCase();
        if (psRaw && !validPaymentStatuses.includes(psRaw)) {
            warnings.push(`Unknown payment status "${row.paymentstatus}" — will default to unpaid`);
        }

        // ── Event name matching ──
        // Events column supports pipe or semicolon as delimiter in addition to comma
        const rawEvents     = row.events || '';
        const matchedEventIds = [];
        const unmatchedEvents = [];
        if (rawEvents) {
            rawEvents.split(/[;|,]/).map(e => e.trim()).filter(Boolean).forEach(evName => {
                const match = eventTypes.find(et =>
                    et.name.toLowerCase() === evName.toLowerCase() ||
                    et.name.toLowerCase().includes(evName.toLowerCase())
                );
                if (match) { matchedEventIds.push(match.id); }
                else       { unmatchedEvents.push(evName); }
            });
        }
        if (unmatchedEvents.length > 0) {
            warnings.push(`Event(s) not found: ${unmatchedEvents.join(', ')}`);
        }

        // ── Duplicate detection ──
        if (row.firstname && row.lastname && row.dateofbirth) {
            const isDuplicate = existingCompetitors.some(c =>
                c.firstName?.toLowerCase() === row.firstname.toLowerCase() &&
                c.lastName?.toLowerCase()  === row.lastname.toLowerCase()  &&
                c.dateOfBirth === row.dateofbirth
            );
            if (isDuplicate) {
                errors.push('Already registered — a competitor with this name and DOB exists. Delete the duplicate first or use Edit to update them.');
            }
        }

        // Normalise gender casing (Male / Female)
        const genderNorm = row.gender
            ? row.gender.charAt(0).toUpperCase() + row.gender.slice(1).toLowerCase()
            : '';

        _csvImportRows.push({
            rowNum:        i,
            firstName:     row.firstname,
            lastName:      row.lastname,
            dateOfBirth:   row.dateofbirth,
            gender:        genderNorm,
            weight:        row.weight     ? parseFloat(row.weight)     : null,
            rank:          row.rank       || null,
            experience:    row.experience ? (isNaN(parseFloat(row.experience)) ? row.experience : parseFloat(row.experience)) : null,
            club:          row.club,
            events:        matchedEventIds,
            paymentStatus: validPaymentStatuses.includes(psRaw) ? psRaw : 'unpaid',
            errors,
            warnings,
            // Auto-exclude rows with hard errors; director can uncheck valid rows too
            skip: errors.length > 0,
        });
    }

    _renderCSVPreviewModal();
}

/** Render (or re-render) the preview table inside the CSV import modal. */
function _renderCSVPreviewModal() {
    const validCount = _csvImportRows.filter(r => r.errors.length === 0).length;
    const errorCount = _csvImportRows.filter(r => r.errors.length > 0).length;
    const warnCount  = _csvImportRows.filter(r => r.errors.length === 0 && r.warnings.length > 0).length;
    const eventTypes = db.load('eventTypes');

    const rows = _csvImportRows.map((r, idx) => {
        const hasErrors   = r.errors.length > 0;
        const hasWarnings = r.warnings.length > 0;
        const rowClass    = hasErrors ? 'csv-row-error' : hasWarnings ? 'csv-row-warn' : 'csv-row-ok';

        const issues = [
            ...r.errors.map(e   => `<span style="color:#ef4444">✕ ${_escapeHtml(e)}</span>`),
            ...r.warnings.map(w => `<span style="color:#f59e0b">⚠ ${_escapeHtml(w)}</span>`),
        ].join('<br>');

        const eventNames = r.events.map(id => {
            const ev = eventTypes.find(e => e.id === id);
            return ev ? _escapeHtml(ev.name) : String(id);
        }).join(', ') || '-';

        const checkboxDisabled = hasErrors ? 'disabled title="Fix errors to enable import"' : '';

        return `
            <tr class="${rowClass}" data-idx="${idx}">
                <td style="text-align:center;">
                    <input type="checkbox" ${r.skip ? '' : 'checked'} ${checkboxDisabled}
                           onchange="_csvToggleRow(${idx}, this.checked)">
                </td>
                <td>${r.rowNum}</td>
                <td>${_escapeHtml(r.firstName)} ${_escapeHtml(r.lastName)}</td>
                <td>${r.dateOfBirth || '-'}</td>
                <td>${r.gender || '-'}</td>
                <td>${r.weight != null ? r.weight : '-'}</td>
                <td>${_escapeHtml(r.rank || '-')}</td>
                <td>${_escapeHtml(r.club)}</td>
                <td style="font-size:12px;">${eventNames}</td>
                <td style="font-size:11px;line-height:1.6;">${issues || '<span style="color:var(--green)">✓ OK</span>'}</td>
            </tr>`;
    }).join('');

    document.getElementById('csv-import-summary').innerHTML =
        `<strong>${validCount}</strong> valid &nbsp;·&nbsp; ` +
        `<strong style="color:#f59e0b">${warnCount}</strong> with warnings &nbsp;·&nbsp; ` +
        `<strong style="color:#ef4444">${errorCount}</strong> with errors`;

    document.getElementById('csv-import-tbody').innerHTML = rows;
    document.getElementById('csv-import-confirm-btn').disabled = validCount === 0;
    document.getElementById('csv-import-progress').classList.add('hidden');
    document.getElementById('csv-import-modal').classList.remove('hidden');
}

/**
 * Toggle whether a CSV row will be included in the import.
 * Called by the checkbox in each preview row.
 */
function _csvToggleRow(idx, checked) {
    if (_csvImportRows[idx]) _csvImportRows[idx].skip = !checked;
}

/**
 * POST each selected row to the server, one at a time, showing live progress.
 * On completion, refreshes the competitors list and closes the modal.
 */
async function executeCSVImport() {
    if (!currentTournamentId) return;

    const toImport = _csvImportRows.filter(r => !r.skip && r.errors.length === 0);
    if (toImport.length === 0) {
        showMessage('No valid rows selected for import.', 'error');
        return;
    }

    const confirmBtn = document.getElementById('csv-import-confirm-btn');
    const progressEl = document.getElementById('csv-import-progress');
    confirmBtn.disabled = true;
    progressEl.textContent = `Importing 0 / ${toImport.length}…`;
    progressEl.classList.remove('hidden');

    const tournament = getCurrentTournament();
    const eventTypes = db.load('eventTypes');
    let imported = 0;
    let failed   = 0;

    for (const row of toImport) {
        const pricing = calculatePricingBreakdown(row.events, eventTypes, tournament);

        const competitorData = {
            firstName:      row.firstName,
            lastName:       row.lastName,
            dateOfBirth:    row.dateOfBirth,
            gender:         row.gender,
            weight:         row.weight,
            rank:           row.rank,
            experience:     row.experience,
            club:           row.club,
            events:         row.events,
            primaryEventId: row.events[0] || null,
            pricing,
            paymentStatus:  row.paymentStatus,
        };

        try {
            const res = await fetch(`/api/tournaments/${currentTournamentId}/competitors`, {
                method:  'POST',
                headers: { 'Content-Type': 'application/json' },
                credentials: 'include',
                body: JSON.stringify({ competitor: competitorData, is_test: false }),
            });
            if (res.ok) {
                const { competitor: created } = await res.json();
                const all = db.load('competitors');
                all.push(created);
                db.save('competitors', all);
                imported++;
            } else {
                failed++;
            }
        } catch {
            failed++;
        }

        progressEl.textContent = `Importing ${imported + failed} / ${toImport.length}…`;
    }

    const succeeded = imported > 0;
    progressEl.textContent = `Done — ${imported} imported${failed > 0 ? `, ${failed} failed` : ''}.`;

    if (succeeded) {
        loadCompetitors(true);
        loadDashboard();
        showMessage(
            `Imported ${imported} competitor${imported !== 1 ? 's' : ''} successfully` +
            (failed > 0 ? ` (${failed} row${failed !== 1 ? 's' : ''} failed)` : '') + '.',
            'success'
        );
        setTimeout(() => closeCSVImportModal(), 2500);
    } else {
        showMessage('Import failed — no competitors were added. Check the server logs.', 'error');
        confirmBtn.disabled = false;
    }
}

/** Hide and reset the CSV import modal. */
function closeCSVImportModal() {
    document.getElementById('csv-import-modal')?.classList.add('hidden');
    _csvImportRows = [];
}

