// Load division preset into the criteria builder
function loadDivisionPreset() {
    const selector = document.getElementById('preset-selector');
    const presetKey = selector.value;

    if (!presetKey || !DIVISION_PRESETS[presetKey]) {
        return;
    }

    const preset = DIVISION_PRESETS[presetKey];

    // Confirm with user before clearing existing criteria
    const criteriaList = document.getElementById('criteria-list');
    if (criteriaList.children.length > 0) {
        if (!confirm('Loading a preset will clear any existing criteria. Continue?')) {
            selector.value = ''; // Reset selector
            return;
        }
    }

    // Set template name if empty
    const templateNameInput = document.getElementById('template-name');
    if (!templateNameInput.value) {
        templateNameInput.value = preset.name;
    }

    // Clear existing criteria
    criteriaList.innerHTML = '';
    criteriaCounter = 0;

    // Load criteria from preset
    preset.criteria.forEach(criterion => {
        addCriteria();

        const criteriaItem = document.querySelector(`[data-index="${criteriaCounter}"]`);
        if (!criteriaItem) return;

        const typeSelect = criteriaItem.querySelector('.criteria-type-select');
        typeSelect.value = criterion.type;
        updateCriteriaRanges(criteriaCounter);

        const rangesContainer = document.getElementById(`ranges-${criteriaCounter}`);

        // For gender, uncheck all then check only the preset's gender(s)
        if (criterion.type === 'gender') {
            rangesContainer.querySelectorAll('input[type="checkbox"]').forEach(cb => cb.checked = false);
            criterion.ranges.forEach(range => {
                const checkbox = rangesContainer.querySelector(`input[value="${range.value}"]`);
                if (checkbox) checkbox.checked = true;
            });
        }
        // For age, weight, experience, rank - add custom ranges
        else {
            // Clear default ranges first
            rangesContainer.innerHTML = '';

            criterion.ranges.forEach(range => {
                addRange(criteriaCounter, criterion.type);
                const rangeItems = rangesContainer.querySelectorAll('.range-item');
                const lastRange = rangeItems[rangeItems.length - 1];
                const inputs = lastRange.querySelectorAll('input');

                if (criterion.type === 'rank') {
                    // Rank uses single value field
                    if (inputs.length >= 1) {
                        inputs[0].value = range.value || '';
                    }
                } else {
                    // Age, weight, experience use min/max/label
                    if (inputs.length >= 3) {
                        inputs[0].value = range.min !== undefined ? range.min : '';
                        inputs[1].value = range.max !== undefined ? range.max : '';
                        inputs[2].value = range.label || '';
                    }
                }
            });
        }
    });

    // Reset selector after loading
    selector.value = '';

    // Show success message
    showToast(`Loaded preset: ${preset.name} — customize as needed before saving`, 'success');
}

// Global variable to track current template being edited
let currentTemplateId = null;

// Division Size Validation
function validateDivisionSizes(divisions, template) {
    const divisionNames = Object.keys(divisions);
    const warnings = [];
    const info = [];

    // Define thresholds based on bracket type
    // Generic size thresholds (bracket type is chosen later, at bracket generation stage)
    const minViable = 2;
    const minRecommended = 3;
    const maxRecommended = 32;

    // Check each division
    divisionNames.forEach(divisionName => {
        const competitors = divisions[divisionName];
        const count = competitors.length;

        if (count === 0) {
            info.push(`• "${divisionName}": No competitors (will be hidden by default)`);
        } else if (count === 1) {
            warnings.push(`• "${divisionName}": Only 1 competitor - cannot run bracket (needs at least ${minViable})`);
        } else if (count < minRecommended) {
            warnings.push(`• "${divisionName}": ${count} competitors - viable but small (recommended: ${minRecommended}+ for better competition)`);
        } else if (count > maxRecommended) {
            warnings.push(`• "${divisionName}": ${count} competitors - very large division (may require extended time, recommended: ${maxRecommended} or fewer)`);
        } else {
            info.push(`• "${divisionName}": ${count} competitors ✓`);
        }
    });

    // Display summary
    const totalDivisions = divisionNames.length;
    const emptyDivisions = divisionNames.filter(name => divisions[name].length === 0).length;
    const viableDivisions = divisionNames.filter(name => divisions[name].length >= minViable).length;


    // Show user feedback if there are warnings
    if (warnings.length > 0) {
        const warningMessage = [
            `⚠️ Division Size Warnings (${warnings.length} issue${warnings.length !== 1 ? 's' : ''}):`,
            '',
            ...warnings,
            '',
            `✓ Viable divisions: ${viableDivisions}/${totalDivisions}`,
            '',
            'You can still proceed, but consider:',
            '• Combining small divisions',
            '• Adjusting criteria ranges',
            '• Using presets (WKF/AAU) for standard categories'
        ].join('\n');

        showToast(`Division size warnings: ${warnings.length} issue(s). ${viableDivisions}/${totalDivisions} viable. Consider combining small divisions.`, 'warning', 6000);
    } else if (viableDivisions > 0) {
        showMessage(`✓ ${viableDivisions} viable division${viableDivisions !== 1 ? 's' : ''} generated successfully!`, 'success');
    }
}

// Division Builder Functions
function showDivisionBuilder(templateId = null, eventId = null) {
    if (eventId) _currentBuilderEventId = eventId;

    const builder = document.getElementById('division-builder');
    const builderTitle = document.getElementById('builder-title');

    if (!builder) return;

    // Clear form
    document.getElementById('template-name').value = '';
    document.getElementById('template-match-duration').value = '';
    const _btEl = document.getElementById('template-bracket-type');
    if (_btEl) _btEl.value = '';

    // Clear criteria
    const criteriaList = document.getElementById('criteria-list');
    criteriaList.innerHTML = '';
    criteriaCounter = 0;

    if (templateId) {
        // Editing existing template
        currentTemplateId = templateId;
        builderTitle.textContent = 'Edit Division Template';
        loadTemplateForEditing(templateId);
    } else {
        // Creating new template
        currentTemplateId = null;
        builderTitle.textContent = 'New Division Template';
    }

    builder.style.display = '';    // clear any inline display:none from hideDivisionBuilder
    builder.classList.remove('hidden');

    // When opened from the Events tab, show as a floating modal overlay.
    // The builder lives inside #divisions-view which has display:none on other tabs —
    // position:fixed cannot escape a display:none ancestor, so we physically move the
    // builder element to <body> while the modal is open, then return it on close.
    if (_currentBuilderEventId) {
        builder.classList.add('division-builder-modal');

        // Insert a placeholder so we know where to return the builder on close
        if (!document.getElementById('division-builder-placeholder')) {
            const placeholder = document.createElement('div');
            placeholder.id = 'division-builder-placeholder';
            placeholder.style.display = 'none';
            builder.parentElement.insertBefore(placeholder, builder);
        }
        document.body.appendChild(builder); // reparent to body — position:fixed now works

        let backdrop = document.getElementById('division-builder-backdrop');
        if (!backdrop) {
            backdrop = document.createElement('div');
            backdrop.id = 'division-builder-backdrop';
            backdrop.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.65);z-index:999;';
            backdrop.onclick = hideDivisionBuilder;
            document.body.appendChild(backdrop);
        }
        backdrop.style.display = 'block';
    }
}

function loadTemplateForEditing(templateId) {
    const eventSelector = document.getElementById('division-event-selector');
    // When opened from Events tab, _currentBuilderEventId is set; Divisions tab uses selector
    const eventId = _currentBuilderEventId || eventSelector?.value;
    if (!eventId) return;

    const allDivisions = db.load('divisions');
    const eventData = allDivisions[eventId];

    if (!eventData || !eventData.templates) return;

    const template = eventData.templates.find(t => String(t.id) === String(templateId));
    if (!template) return;

    // Populate template fields
    document.getElementById('template-name').value = template.name || '';
    document.getElementById('template-match-duration').value = template.matchDuration ? (template.matchDuration / 60) : '';
    const btEl = document.getElementById('template-bracket-type');
    if (btEl) btEl.value = template.bracketType || '';

    // Load criteria
    if (template.criteria && template.criteria.length > 0) {
        template.criteria.forEach((criterion) => {
            addCriteria();

            const criteriaItem = document.querySelector(`[data-index="${criteriaCounter}"]`);
            const typeSelect = criteriaItem.querySelector('.criteria-type-select');

            typeSelect.value = criterion.type;
            updateCriteriaRanges(criteriaCounter);

            // Populate ranges
            const rangesContainer = document.getElementById(`ranges-${criteriaCounter}`);

            if (criterion.type === 'gender') {
                // Uncheck all first, then restore saved selections
                rangesContainer.querySelectorAll('input[type="checkbox"]').forEach(cb => cb.checked = false);
                criterion.ranges.forEach(range => {
                    const val = range.value;
                    // Match case-insensitively: presets use lowercase ('male'), form uses Title case ('Male')
                    const capitalized = val.charAt(0).toUpperCase() + val.slice(1).toLowerCase();
                    const checkbox = rangesContainer.querySelector(`input[value="${val}"]`)
                        || rangesContainer.querySelector(`input[value="${capitalized}"]`);
                    if (checkbox) checkbox.checked = true;
                });
                return;
            }

            if (criterion.type === 'rank') {
                // Populate Kyu/Dan range selectors from saved rankMin/rankMax
                criterion.ranges.forEach((range, i) => {
                    if (i === 0) {
                        // First range was already created by updateCriteriaRanges
                        const firstItem = rangesContainer.querySelector('.rank-range-item');
                        if (firstItem) {
                            const minSel = firstItem.querySelector('.rank-min-select');
                            const maxSel = firstItem.querySelector('.rank-max-select');
                            const labelInp = firstItem.querySelector('.rank-label');
                            if (minSel) minSel.value = range.rankMin || '10th kyu';
                            if (maxSel) maxSel.value = range.rankMax || '1st kyu';
                            if (labelInp) labelInp.value = range.label || '';
                        }
                    } else {
                        addRankRange(criteriaCounter, range.rankMin, range.rankMax, range.label);
                    }
                });
                return;
            }

            if (criterion.type === 'belt') {
                // Populate belt color range selectors from saved beltMin/beltMax
                criterion.ranges.forEach((range, i) => {
                    if (i === 0) {
                        // First range was already created by updateCriteriaRanges
                        const firstItem = rangesContainer.querySelector('.belt-range-item');
                        if (firstItem) {
                            const minSel = firstItem.querySelector('.belt-min-select');
                            const maxSel = firstItem.querySelector('.belt-max-select');
                            const labelInp = firstItem.querySelector('.belt-label');
                            if (minSel) minSel.value = range.beltMin || 'white';
                            if (maxSel) maxSel.value = range.beltMax || 'black';
                            if (labelInp) labelInp.value = range.label || '';
                        }
                    } else {
                        addBeltRange(criteriaCounter, range.beltMin, range.beltMax, range.label);
                    }
                });
                return;
            }

            criterion.ranges.forEach(range => {
                addRange(criteriaCounter, criterion.type);
                const rangeItems = rangesContainer.querySelectorAll('.range-item');
                const lastRange = rangeItems[rangeItems.length - 1];
                const inputs = lastRange.querySelectorAll('input');

                if (inputs.length >= 3) {
                    inputs[0].value = range.min;
                    inputs[1].value = range.max;
                    inputs[2].value = range.label;
                }
            });
        });
    }
}

function loadTemplatesList() {
    const eventSelector = document.getElementById('division-event-selector');
    const eventId = eventSelector?.value;
    const container = document.getElementById('templates-list');

    if (!container || !eventId) return;

    const allDivisions = db.load('divisions');
    const eventData = allDivisions[eventId];

    if (!eventData || !eventData.templates || eventData.templates.length === 0) {
        container.innerHTML = '<p class="hint">No templates created yet. Click "New Template" to get started.</p>';
        return;
    }

    container.innerHTML = '';

    eventData.templates.forEach(template => {
        const templateCard = document.createElement('div');
        templateCard.className = 'event-card';
        templateCard.style.cssText = 'margin-bottom: 12px;';

        // Summarize criteria types
        const criteriaTypes = (template.criteria || []).map(c => c.type).join(', ') || 'None';
        const durationInfo = template.matchDuration
            ? `<div class="event-detail"><strong>Match Duration:</strong> ${template.matchDuration / 60} min</div>`
            : '';

        templateCard.innerHTML = `
            <h4>${template.name}</h4>
            <div class="event-detail"><strong>Criteria:</strong> ${criteriaTypes}</div>
            ${durationInfo}
            <div class="event-actions">
                <button class="btn btn-small btn-secondary" onclick="showDivisionBuilder(${template.id})">Edit</button>
                <button class="btn btn-small btn-danger" onclick="deleteTemplate(${template.id})">Delete</button>
            </div>
        `;

        container.appendChild(templateCard);
    });
}

function loadExistingCriteria() {
    const eventSelector = document.getElementById('division-event-selector');
    const eventId = eventSelector?.value;

    if (!eventId) return;

    const allDivisions = db.load('divisions');
    const eventData = allDivisions[eventId];

    if (!eventData || !eventData.criteria || eventData.criteria.length === 0) {
        // No existing criteria, start fresh
        return;
    }

    // Clear existing criteria in the builder
    const criteriaList = document.getElementById('criteria-list');
    criteriaList.innerHTML = '';
    criteriaCounter = 0;

    // Load each criterion from saved data
    eventData.criteria.forEach((criterion, idx) => {
        addCriteria(); // Creates the UI structure

        // Get the newly created criteria item
        const criteriaItem = document.querySelector(`[data-index="${criteriaCounter}"]`);
        const typeSelect = criteriaItem.querySelector('.criteria-type-select');
        const scoreboardTypeSelect = criteriaItem.querySelector('.criteria-scoreboard-type-select');
        const bracketTypeSelect = criteriaItem.querySelector('.criteria-bracket-type-select');

        // Set the criteria type
        typeSelect.value = criterion.type;

        // Set the scoreboard type if it exists
        if (scoreboardTypeSelect && criterion.scoreboardType) {
            scoreboardTypeSelect.value = criterion.scoreboardType;
        }

        // Set the bracket type if it exists
        if (bracketTypeSelect && criterion.bracketType) {
            bracketTypeSelect.value = criterion.bracketType;
        }

        // Trigger range UI update
        updateCriteriaRanges(criteriaCounter);

        // Populate ranges
        const rangesContainer = document.getElementById(`ranges-${criteriaCounter}`);

        if (criterion.type === 'gender') {
            return;
        }

        if (criterion.type === 'rank') {
            criterion.ranges.forEach((range, i) => {
                if (i === 0) {
                    const firstItem = rangesContainer.querySelector('.rank-range-item');
                    if (firstItem) {
                        const minSel = firstItem.querySelector('.rank-min-select');
                        const maxSel = firstItem.querySelector('.rank-max-select');
                        const labelInp = firstItem.querySelector('.rank-label');
                        if (minSel) minSel.value = range.rankMin || '10th kyu';
                        if (maxSel) maxSel.value = range.rankMax || '1st kyu';
                        if (labelInp) labelInp.value = range.label || '';
                    }
                } else {
                    addRankRange(criteriaCounter, range.rankMin, range.rankMax, range.label);
                }
            });
            return;
        }

        // For age, weight, experience - populate the range inputs
        criterion.ranges.forEach(range => {
            addRange(criteriaCounter, criterion.type);

            // Get the last added range item (the one we just created)
            const rangeItems = rangesContainer.querySelectorAll('.range-item');
            const lastRange = rangeItems[rangeItems.length - 1];
            const inputs = lastRange.querySelectorAll('input');

            if (inputs.length >= 3) {
                inputs[0].value = range.min;
                inputs[1].value = range.max;
                inputs[2].value = range.label;
            }
        });
    });

    showMessage('Loaded existing criteria for editing', 'success');
}

function hideDivisionBuilder() {
    const builder = document.getElementById('division-builder');
    if (builder) {
        // If the builder was reparented to <body> for the modal, move it back
        const placeholder = document.getElementById('division-builder-placeholder');
        if (placeholder) {
            placeholder.parentElement.insertBefore(builder, placeholder);
            placeholder.remove();
        }
        builder.style.display = 'none';          // explicit: beats position:fixed !important
        builder.classList.add('hidden');
        builder.classList.remove('division-builder-modal');
    }
    const backdrop = document.getElementById('division-builder-backdrop');
    if (backdrop) backdrop.style.display = 'none';
    _currentBuilderEventId = null;
    currentTemplateId = null;
}

function deleteTemplate(templateId) {
    const eventSelector = document.getElementById('division-event-selector');
    const eventId = eventSelector?.value;

    if (!eventId) return;

    const divisions = db.load('divisions');
    const eventData = divisions[eventId];

    if (!eventData || !eventData.templates) return;

    const template = eventData.templates.find(t => String(t.id) === String(templateId));
    if (!template) return;

    if (confirm(`Are you sure you want to delete the template "${template.name}"?\n\nThis will not affect already generated divisions.`)) {
        eventData.templates = eventData.templates.filter(t => String(t.id) !== String(templateId));
        _msSet(_scopedKey('divisions'), JSON.stringify(divisions));
        loadTemplatesList();
        showMessage('Template deleted successfully!');
    }
}

function saveDivisionTemplate() {
    if (!ensureTournamentSelected()) return;

    const eventSelector = document.getElementById('division-event-selector');
    // Accept eventId from the Events-tab context (_currentBuilderEventId) or the Divisions-tab selector
    const eventId = _currentBuilderEventId || eventSelector?.value;
    if (!eventId) {
        showMessage('Please select an event type first', 'error');
        return;
    }

    // Get template-level settings
    const templateName = document.getElementById('template-name').value.trim();

    if (!templateName) {
        showMessage('Please enter a template name', 'error');
        return;
    }

    // Get criteria from the criteria builder
    const criteriaElements = document.querySelectorAll('.criteria-item');
    const criteria = [];

    criteriaElements.forEach(item => {
        const typeSelect = item.querySelector('[id^="criteria-type-"]');
        if (!typeSelect || !typeSelect.value) return;

        const criteriaType = typeSelect.value;
        const criteriaObj = { type: criteriaType, ranges: [] };

        // Handle gender criteria — read which boxes are checked
        if (criteriaType === 'gender') {
            const rangesContainer = item.querySelector('[id^="ranges-"]');
            const genderRanges = [];
            if (rangesContainer) {
                rangesContainer.querySelectorAll('input[type="checkbox"]:checked').forEach(cb => {
                    genderRanges.push({ value: cb.value, label: cb.value });
                });
            }
            if (genderRanges.length === 0) {
                // Fall back to both if nothing checked (shouldn't happen)
                genderRanges.push({ value: 'Male', label: 'Male' }, { value: 'Female', label: 'Female' });
            }
            criteriaObj.ranges = genderRanges;
            criteria.push(criteriaObj);
            return;
        }

        // Handle rank criteria — read Kyu/Dan ranges from the UI
        if (criteriaType === 'rank') {
            item.querySelectorAll('.rank-range-item').forEach(rangeItem => {
                const minSel   = rangeItem.querySelector('.rank-min-select');
                const maxSel   = rangeItem.querySelector('.rank-max-select');
                const labelInp = rangeItem.querySelector('.rank-label');
                if (minSel && maxSel && minSel.value && maxSel.value) {
                    criteriaObj.ranges.push({
                        rankMin: minSel.value,
                        rankMax: maxSel.value,
                        label: labelInp?.value.trim() || `${minSel.value} – ${maxSel.value}`
                    });
                }
            });
            if (criteriaObj.ranges.length > 0) criteria.push(criteriaObj);
            return;
        }

        // Handle belt criteria — read belt color ranges from the UI
        if (criteriaType === 'belt') {
            item.querySelectorAll('.belt-range-item').forEach(rangeItem => {
                const minSel   = rangeItem.querySelector('.belt-min-select');
                const maxSel   = rangeItem.querySelector('.belt-max-select');
                const labelInp = rangeItem.querySelector('.belt-label');
                if (minSel && maxSel && minSel.value && maxSel.value) {
                    criteriaObj.ranges.push({
                        beltMin: minSel.value,
                        beltMax: maxSel.value,
                        label: labelInp?.value.trim() || `${minSel.value}–${maxSel.value}`
                    });
                }
            });
            if (criteriaObj.ranges.length > 0) criteria.push(criteriaObj);
            return;
        }

        // Get ranges for numeric criteria (age, weight, experience)
        const rangeItems = item.querySelectorAll('.range-item');
        rangeItems.forEach(rangeItem => {
            const inputs = rangeItem.querySelectorAll('input');
            if (inputs.length >= 2) {
                const min = parseFloat(inputs[0].value);
                const max = parseFloat(inputs[1].value);
                const label = inputs[2]?.value.trim() || `${min}-${max}`;

                if (!isNaN(min) && !isNaN(max)) {
                    criteriaObj.ranges.push({ min, max, label });
                }
            }
        });

        if (criteriaObj.ranges.length > 0) {
            criteria.push(criteriaObj);
        }
    });

    if (criteria.length === 0) {
        showMessage('Please add at least one criteria', 'error');
        return;
    }

    // Read match duration (stored in seconds, input in minutes)
    const matchDurationMinutes = parseFloat(document.getElementById('template-match-duration').value);

    const bracketType = document.getElementById('template-bracket-type')?.value || null;

    // Create template object
    const template = {
        id: currentTemplateId || generateUniqueId(),
        name: templateName,
        criteria: criteria,
        matchDuration: matchDurationMinutes ? Math.round(matchDurationMinutes * 60) : null,
        bracketType: bracketType || undefined,
        createdAt: currentTemplateId ? undefined : new Date().toISOString(),
        updatedAt: new Date().toISOString()
    };

    // Save template for this event
    const divisions = db.load('divisions');

    // Initialize event data if it doesn't exist
    if (!divisions[eventId]) {
        divisions[eventId] = {
            templates: [],
            generated: {}
        };
    }

    // Ensure templates array exists
    if (!divisions[eventId].templates) {
        divisions[eventId].templates = [];
    }

    if (currentTemplateId) {
        // Update existing template
        const index = divisions[eventId].templates.findIndex(t => t.id === currentTemplateId);
        if (index !== -1) {
            // Preserve createdAt
            template.createdAt = divisions[eventId].templates[index].createdAt;
            divisions[eventId].templates[index] = template;
        }
    } else {
        // Add new template
        divisions[eventId].templates.push(template);
    }

    _msSet(_scopedKey('divisions'), JSON.stringify(divisions));

    // Sync templates to server (debounced)
    const syncEventId = eventId;
    const syncTemplates = divisions[eventId]?.templates || [];
    _debouncedSync(`templates_${syncEventId}`, () => _syncTemplateToServer(syncEventId, syncTemplates), 1000);

    showMessage(currentTemplateId ? 'Template updated successfully!' : 'Template created successfully!');

    if (_currentBuilderEventId) {
        // Opened from the Events tab — close modal, refresh cards, auto-open accordion
        const eid = _currentBuilderEventId;
        hideDivisionBuilder();           // clears _currentBuilderEventId; explicit display:none
        loadEventTypes();                // re-render all cards with updated badge count
        _toggleEventTemplates(eid);     // auto-open this event's accordion so template is visible
        return;
    }

    hideDivisionBuilder();
    loadTemplatesList();
}

// ── Server-side Division Auto-Assign ─────────────────────────────────────────

// Mutex: prevents a save and a generate from overlapping and clobbering each other.
// Set to true at the start of either operation; cleared when it completes or errors.
let _divisionOpInProgress = false;

/**
 * Call the server's auto-assign endpoint and broadcast results to all devices.
 * This replaces the client-side autoAssignToDivisions() trigger on the "Generate Divisions" button.
 */
/**
 * Re-sync Divisions button handler.
 * Blocked if any brackets exist for the selected event (director must delete them first).
 * Requires two confirmations. Warns that manually moved competitors will be re-assigned.
 */
async function syncAllDivisions() {
    if (!currentTournamentId) return;
    const btn = document.getElementById('sync-divisions-btn');
    if (btn) { btn.disabled = true; btn.textContent = 'Syncing…'; }
    try {
        const res = await fetch(`/api/tournaments/${currentTournamentId}/divisions/auto-assign`, {
            method: 'POST', credentials: 'include',
        });
        const data = await res.json();
        if (!res.ok) throw new Error(data.error || 'Sync failed');
        await _loadDivisionsFromServer();
        if (typeof loadDivisionsView === 'function') loadDivisionsView();
        showMessage('Competitors synced to divisions.', 'success');
    } catch (err) {
        showMessage(err.message || 'Could not sync divisions.', 'error');
    } finally {
        if (btn) { btn.disabled = false; btn.textContent = '↻ Sync Competitors → Divisions'; }
    }
}

async function resyncDivisions() {
    if (!currentTournamentId) return;

    const eventSelector = document.getElementById('division-event-selector');
    const eventId = eventSelector?.value;

    // Check whether any brackets exist for this event
    const brackets = JSON.parse(_msGet(_scopedKey('brackets')) || '{}');
    const eventBrackets = Object.values(brackets).filter(b => String(b.eventId) === String(eventId));
    if (eventBrackets.length > 0) {
        showMessage(
            `This event has ${eventBrackets.length} bracket(s). Delete all brackets for this event before re-syncing divisions.`,
            'error'
        );
        return;
    }

    // Warning 1
    const confirmed1 = await showConfirm(
        `<strong>Re-sync Divisions</strong><br><br>` +
        `This will rebuild all divisions from the current tree criteria. ` +
        `<strong>Competitors that were manually moved to different divisions will be returned to their tree-assigned positions.</strong> ` +
        `All manual changes will be lost.<br><br>Continue?`,
        { confirmText: 'Continue', danger: true }
    );
    if (!confirmed1) return;

    // Warning 2
    const confirmed2 = await showConfirm(
        `<strong>Are you sure?</strong><br><br>This cannot be undone.`,
        { confirmText: 'Yes, Re-sync', danger: true }
    );
    if (!confirmed2) return;

    await triggerServerAutoAssign();
}

async function triggerServerAutoAssign() {
    if (!currentTournamentId) return;
    if (_divisionOpInProgress) {
        showMessage('A division operation is already in progress — please wait.', 'error');
        return;
    }
    _divisionOpInProgress = true;
    setSyncIndicator('syncing');
    try {
        const res = await fetch(`/api/tournaments/${currentTournamentId}/divisions/auto-assign`, {
            method: 'POST',
            credentials: 'include',
        });
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        const { generatedDivisions } = await res.json();
        // Normalize: server stores each division as {name, competitors, createdAt};
        // client expects plain arrays of competitors.
        const normalized = {};
        for (const [evId, evData] of Object.entries(generatedDivisions || {})) {
            const rawGen = evData?.generated || evData || {};
            const normGen = {};
            for (const [divName, divData] of Object.entries(rawGen)) {
                normGen[divName] = Array.isArray(divData) ? divData : (divData?.competitors || []);
            }
            normalized[evId] = { ...evData, generated: normGen };
        }
        _msSet(_scopedKey('divisions'), JSON.stringify(normalized));
        setSyncIndicator('ok');
        showMessage('Divisions updated.', 'success');
        if (typeof loadDivisionsView === 'function') loadDivisionsView();
    } catch (e) {
        setSyncIndicator('error');
        showMessage('Auto-assign failed — please try again.', 'error');
    } finally {
        _divisionOpInProgress = false;
    }
}

// Division Generation
function generateDivisions() {

    const eventSelector = document.getElementById('division-event-selector');
    const eventId = eventSelector?.value;

    if (!eventId) {
        console.error('No event ID');
        showMessage('⚠️ Please select an event type from the dropdown above first', 'error');
        // Highlight the dropdown to draw attention
        eventSelector.style.border = '2px solid #ef4444';
        setTimeout(() => {
            eventSelector.style.border = '';
        }, 2000);
        return;
    }

    // Get the division template for this event
    const allDivisions = JSON.parse(_msGet(_scopedKey('divisions')) || '{}');

    const eventData = allDivisions[eventId];

    if (!eventData || !eventData.templates || eventData.templates.length === 0) {
        console.error('No templates configured');
        showMessage('Please configure division criteria first (click "Configure Division Criteria")', 'error');
        return;
    }


    // Get tournament-scoped competitors registered for this specific event
    // Use string comparison — IDs may be numbers (CSV/director) or strings (registrations)
    const allCompetitors = db.load('competitors');
    const competitors = (currentTournamentId
        ? allCompetitors.filter(c => c.tournamentId === currentTournamentId)
        : allCompetitors
    ).filter(c => c.events && c.events.some(id => String(id) === String(eventId)));

    // Detect tree-style templates early so we can skip the "no competitors"
    // guard — tree templates create empty division slots even with 0 competitors.
    const isTreeTemplate = eventData.templates.length > 0
        && typeof eventData.templates[0].name === 'string'
        && typeof eventData.templates[0].id   === 'string';

    if (!isTreeTemplate && competitors.length === 0) {
        showMessage('No competitors registered for this tournament yet!', 'error');
        return;
    }

    // Calculate age for each competitor based on tournament settings
    const tournaments = db.load('tournaments');
    const currentTournament = tournaments.find(t => t.id === currentTournamentId);
    const ageCalculationMethod = currentTournament?.ageCalculationMethod || 'aau-standard';
    const eventDate = currentTournament?.date || new Date();

    // Add calculated age to each competitor (for division filtering)
    const competitorsWithAge = competitors.map(comp => ({
        ...comp,
        age: comp.dateOfBirth ? calculateAge(comp.dateOfBirth, ageCalculationMethod, eventDate) : (comp.age || 0)
    }));

    // Warn about competitors with invalid/missing DOB that won't match any age range
    const invalidAgeComps = competitorsWithAge.filter(c => isNaN(c.age) || c.age < 0);
    if (invalidAgeComps.length > 0) {
        const names = invalidAgeComps.map(c => `${c.firstName} ${c.lastName}`).join(', ');
        showMessage(`⚠️ ${invalidAgeComps.length} competitor(s) have an invalid date of birth and won't be placed in age-based divisions: ${names}. Please fix their DOB.`, 'error');
    }

    // Generate divisions for each template.
    // Tree-builder templates have { id, name, criteria } per leaf — use the pre-computed
    // name directly and pre-seed every leaf so empty divisions still appear in the list.
    // Legacy templates (old wizard) use the cross-product buildDivisions() path.
    // (isTreeTemplate already declared above)
    const generatedDivisions = {};

    if (isTreeTemplate) {
        eventData.templates.forEach(template => {
            const divName = template.name;
            // Always create the key so the division appears even when no one is placed yet
            generatedDivisions[divName] = [];
            if (!template.criteria || template.criteria.length === 0) return;
            generatedDivisions[divName] = competitorsWithAge.filter(comp =>
                template.criteria.every(c => _matchesLeafCriterion(comp, c))
            );
        });
    } else {
        // Legacy cross-product builder (old event-type wizard)
        eventData.templates.forEach(template => {
            const result = buildDivisions(competitorsWithAge, template.criteria || template);
            Object.assign(generatedDivisions, result);
        });
    }


    // Validate division sizes and warn user
    validateDivisionSizes(generatedDivisions, eventData.templates[0]);

    // Store the generated divisions under this event (preserve templates)
    allDivisions[eventId] = {
        templates: eventData.templates, // Preserve templates
        generated: generatedDivisions,
        updatedAt: new Date().toISOString()
    };

    _msSet(_scopedKey('divisions'), JSON.stringify(allDivisions));

    // Immediately persist to server — no debounce, director action should be atomic
    _syncDivisionsToServer().catch(e => console.warn('[divisions] generate sync failed:', e.message));

    loadDivisions();
    loadDashboard();
    showMessage('Divisions generated successfully!');
}

/**
 * _matchesLeafCriterion — checks whether a single competitor satisfies one
 * criterion from a tree-builder leaf template (each criterion has exactly one
 * range since the tree already split each level into individual nodes).
 */
function _matchesLeafCriterion(comp, criterion) {
    const ranges = criterion.ranges || [];
    if (ranges.length === 0) return true;
    const r = ranges[0]; // tree leaves always have one range per criterion level

    const RANK_ORD = [
        '10th kyu','9th kyu','8th kyu','7th kyu','6th kyu','5th kyu',
        '4th kyu','3rd kyu','2nd kyu','1st kyu',
        '1st dan','2nd dan','3rd dan','4th dan','5th dan',
        '6th dan','7th dan','8th dan','9th dan','10th dan',
    ];
    const normRank = s => {
        const t = (s || '').toLowerCase().replace(/ belt$/i, '').trim();
        const map = { white:'10th kyu', yellow:'9th kyu', orange:'8th kyu',
                      green:'7th kyu', blue:'6th kyu', purple:'5th kyu',
                      brown:'3rd kyu', black:'1st dan' };
        return map[t] || t;
    };

    switch (criterion.type) {
        case 'gender': {
            // Normalise common variations so "Boys"/"Girls"/"Men"/"Women" all
            // match the canonical "Male"/"Female" stored on the competitor record.
            const _gNorm = g => {
                const t = (g || '').toLowerCase().trim();
                if (['male','boys','boy','men','man','m'].includes(t)) return 'male';
                if (['female','girls','girl','women','woman','f'].includes(t)) return 'female';
                return t;
            };
            return _gNorm(comp.gender) === _gNorm(r.value || r.label);
        }
        case 'age':
            return (comp.age || 0) >= r.min && (comp.age || 0) <= _ageRangeMax(r);
        case 'rank':
            if (r.rankMin !== undefined && r.rankMax !== undefined) {
                const lo = RANK_ORD.indexOf(normRank(r.rankMin));
                const hi = RANK_ORD.indexOf(normRank(r.rankMax));
                const ci = RANK_ORD.indexOf(normRank(comp.rank));
                return ci !== -1 && ci >= lo && ci <= hi;
            }
            return normRank(comp.rank) === normRank(r.value);
        case 'weight': {
            const compW = _normaliseWeightForComparison(
                comp.weight || 0,
                getTournamentWeightUnit(),
                criterion.weightUnit || getTournamentWeightUnit()
            );
            return compW >= r.min && compW <= r.max;
        }
        case 'experience':
            return typeof comp.experience === 'string'
                ? (comp.experience || '').toLowerCase() === (r.label || '').toLowerCase()
                : (comp.experience || 0) >= r.min && (comp.experience || 0) <= r.max;
        case 'custom':
            return false; // custom = manual placement only, never auto-matched
        default:
            return true;
    }
}

function buildDivisions(competitors, criteria, prefix = '', index = 0) {

    if (index >= criteria.length) {
        return { [prefix.trim()]: competitors };
    }

    let currentCriteria = criteria[index];
    // Normalise legacy format: { type:"gender", options:["Male","Female"] }
    // → { type:"gender", ranges:[{ value:"Male", label:"Male" },...] }
    // Old division builder versions saved gender as `options` (string array) instead of `ranges`.
    if (!currentCriteria.ranges && Array.isArray(currentCriteria.options)) {
        currentCriteria = {
            ...currentCriteria,
            ranges: currentCriteria.options.map(o => ({ value: o, label: o })),
        };
    }

    const divisions = {};

    (currentCriteria.ranges || []).forEach((range, rangeIdx) => {
        let filtered;

        switch(currentCriteria.type) {
            case 'age':
                filtered = competitors.filter(c => c.age >= range.min && c.age <= _ageRangeMax(range));
                break;
            case 'gender':
                filtered = competitors.filter(c => (c.gender || '').toLowerCase() === (range.value || '').toLowerCase());
                if (filtered.length === 0 && competitors.length > 0) {
                }
                break;
            case 'weight':
                filtered = competitors.filter(c => c.weight >= range.min && c.weight <= range.max);
                break;
            case 'rank':
                // Normalize rank values from both old (belt colors) and new (Kyu/Dan) formats
                // to match RANK_ORDER entries (lowercase, e.g. '10th kyu', '1st dan').
                const normalizeRank = r => {
                    const s = (r || '').toLowerCase().replace(/ belt$/i, '').trim();
                    // Map old belt-color values → Kyu equivalents for backwards compatibility
                    const colorToKyu = {
                        'white': '10th kyu', 'yellow': '9th kyu', 'orange': '8th kyu',
                        'green': '7th kyu',  'blue':   '6th kyu', 'purple': '5th kyu',
                        'brown': '3rd kyu',  'black':  '1st dan',
                    };
                    return colorToKyu[s] || s;
                };
                if (range.rankMin !== undefined && range.rankMax !== undefined) {
                    // Grouped belt range (WKF/AAU style)
                    const minIdx = RANK_ORDER.indexOf(normalizeRank(range.rankMin));
                    const maxIdx = RANK_ORDER.indexOf(normalizeRank(range.rankMax));
                    filtered = competitors.filter(c => {
                        const cIdx = RANK_ORDER.indexOf(normalizeRank(c.rank));
                        return cIdx >= minIdx && cIdx <= maxIdx;
                    });
                } else {
                    filtered = competitors.filter(c => normalizeRank(c.rank) === normalizeRank(range.value));
                }
                break;
            case 'belt': {
                const BELT_ORDER = ['white','yellow','orange','green','blue','purple','brown','red','black'];
                const normBelt = r => (r || '').toLowerCase().replace(/ belt$/i, '').trim();
                const beltMinIdx = BELT_ORDER.indexOf(normBelt(range.beltMin));
                const beltMaxIdx = BELT_ORDER.indexOf(normBelt(range.beltMax));
                filtered = competitors.filter(c => {
                    const cIdx = BELT_ORDER.indexOf(normBelt(c.rank || c.belt_rank));
                    return cIdx !== -1 && cIdx >= beltMinIdx && cIdx <= beltMaxIdx;
                });
                break;
            }
            case 'experience':
                filtered = competitors.filter(c => c.experience >= range.min && c.experience <= range.max);
                if (filtered.length === 0 && competitors.length > 0) {
                }
                break;
        }

        if (filtered.length > 0) {
            const newPrefix = prefix ? `${prefix} | ${range.label}` : range.label;
            const subDivisions = buildDivisions(filtered, criteria, newPrefix, index + 1);
            Object.assign(divisions, subDivisions);
        } else {
        }
    });

    return divisions;
}

function renderDivisions() {
    loadDivisions();
}

function loadDivisions() {

    const allDivisions = JSON.parse(_msGet(_scopedKey('divisions')) || '{}');

    const container = document.getElementById('divisions-container');

    const hideEmpty = document.getElementById('hide-empty-divisions')?.checked || false;

    const eventSelector = document.getElementById('division-event-selector');
    const eventId = eventSelector?.value;

    if (!container) {
        console.error('Container not found!');
        return;
    }

    container.innerHTML = '';

    if (!eventId) {
        container.innerHTML = '<p style="color: var(--text-secondary);">Select an event type to view divisions.</p>';
        return;
    }

    const eventData = allDivisions[eventId];

    if (!eventData || !eventData.generated) {
        // Auto-generate from existing competitors before giving up
        const allCompetitors = db.load('competitors');
        const competitors = currentTournamentId
            ? allCompetitors.filter(c => c.tournamentId === currentTournamentId && c.events && c.events.some(id => String(id) === String(eventId)))
            : allCompetitors.filter(c => c.events && c.events.some(id => String(id) === String(eventId)));

        if (competitors.length > 0) {
            const tournaments = db.load('tournaments');
            const currentTournament = tournaments.find(t => t.id === currentTournamentId);
            const ageCalc = currentTournament?.ageCalculationMethod || 'aau-standard';
            const eventDate = currentTournament?.date || new Date();
            const freshDivisions = JSON.parse(_msGet(_scopedKey('divisions')) || '{}');
            if (!freshDivisions[eventId]) freshDivisions[eventId] = { templates: [], generated: {} };
            if (!freshDivisions[eventId].generated) freshDivisions[eventId].generated = {};

            competitors.forEach(comp => {
                const age = comp.dateOfBirth ? calculateAge(comp.dateOfBirth, ageCalc, eventDate) : (comp.age || 0);
                const divName = buildAutoSingleDivisionName(comp, age);
                if (!freshDivisions[eventId].generated[divName]) freshDivisions[eventId].generated[divName] = [];
                if (!freshDivisions[eventId].generated[divName].find(c => c.id === comp.id)) {
                    freshDivisions[eventId].generated[divName].push(comp);
                }
            });
            _msSet(_scopedKey('divisions'), JSON.stringify(freshDivisions));
            // Re-read
            const updated = freshDivisions[eventId];
            if (updated && updated.generated && Object.keys(updated.generated).length > 0) {
                const divisions = updated.generated;
                const divisionKeys = Object.keys(divisions).sort();
                const clubsFallback = db.load('clubs');
                const getCountryFallback = (comp) => {
                    if (comp.country) return comp.country;
                    const club = clubsFallback.find(c => c.name === comp.club);
                    return club?.country || '-';
                };
                divisionKeys.forEach(divisionName => {
                    const divCompetitors = divisions[divisionName];
                    if (!Array.isArray(divCompetitors) || (hideEmpty && divCompetitors.length === 0)) return;
                    const sheet = document.createElement('div');
                    sheet.className = 'division-sheet';
                    const cId = (c) => c.id || c._id || `${c.firstName}_${c.lastName}_${c.dateOfBirth}`;
                const tableRows = divCompetitors.map(comp => {
                    const isPending = comp.approved === false;
                    const pendingBadge = isPending ? ' <span style="background:#f59e0b;color:#fff;font-size:10px;padding:1px 5px;border-radius:8px;vertical-align:middle;">Pending</span>' : '';
                    return `
                        <tr style="${isPending ? 'opacity:0.7;' : ''}">
                            <td>${comp.firstName || '?'} ${comp.lastName || '?'}${pendingBadge}</td>
                            <td>${getDisplayAge(comp)}</td>
                            <td>${comp.gender || '-'}</td>
                            <td>${comp.weight != null ? comp.weight + ' ' + getTournamentWeightUnit() : '-'}</td>
                            <td>${comp.rank || '-'}</td>
                            <td>${comp.club || '-'}</td>
                            <td>${getCountryFallback(comp)}</td>
                            <td style="white-space:nowrap;">
                                <button class="btn btn-small" onclick="showMoveCompetitorModal('${_escapeHtml(divisionName)}','${cId(comp)}')" title="Move to another division">Move</button>
                                <button class="btn btn-small btn-secondary" onclick="showCopyCompetitorModal('${_escapeHtml(divisionName)}','${cId(comp)}')" title="Copy to another division" style="margin-left:4px;">Copy</button>
                                <button class="btn btn-small btn-danger" onclick="removeCompetitorFromDivision('${_escapeHtml(divisionName)}','${cId(comp)}')" title="Remove from this division" style="margin-left:4px;">Remove</button>
                            </td>
                        </tr>`;
                }).join('');
                    sheet.innerHTML = `
                        <div class="division-header">${divisionName} (${divCompetitors.length} competitor${divCompetitors.length !== 1 ? 's' : ''})</div>
                        <div class="division-content">
                            <table class="division-table">
                                <colgroup><col style="width:22%"><col style="width:6%"><col style="width:8%"><col style="width:9%"><col style="width:10%"><col style="width:20%"><col style="width:10%"><col style="width:15%"></colgroup>
                                <thead><tr><th>Name</th><th>Age</th><th>Gender</th><th>Weight</th><th>Rank</th><th>Dojo</th><th>Country</th><th></th></tr></thead>
                                <tbody>${tableRows}</tbody>
                            </table>
                        </div>`;
                    container.appendChild(sheet);
                });
                return;
            }
        }

        container.innerHTML = '<p style="color: var(--text-secondary);">No competitors registered for this event yet.</p>';
        return;
    }

    // Work on a shallow copy so we can safely inject empty slots without
    // mutating what is stored in localStorage.
    const divisions = { ...eventData.generated };

    // When the director unchecks "show only divisions with competitors", fill in
    // any tree-template leaf divisions that were never stored because they were
    // empty at generate-time (or pre-date the empty-seeding fix).
    const isTreeTpl = eventData.templates && eventData.templates.length > 0
        && typeof eventData.templates[0].name === 'string'
        && typeof eventData.templates[0].id   === 'string';

    if (!hideEmpty && isTreeTpl) {
        eventData.templates.forEach(t => {
            if (!(t.name in divisions)) divisions[t.name] = [];
        });
    }

    // Unassigned always at top, then sorted alphabetically
    const divisionKeys = [
        ...( '__unassigned__' in divisions ? ['__unassigned__'] : [] ),
        ...Object.keys(divisions).filter(k => k !== '__unassigned__').sort(),
    ];

    if (divisionKeys.length === 0) {
        container.innerHTML = '<p style="color: var(--text-secondary);">No divisions yet. Build a division tree for this event to set up your division structure.</p>';
        return;
    }

    // Load clubs once for live country lookup
    const clubsForDivision = db.load('clubs');
    const getCompetitorCountry = (comp) => {
        if (comp.country) return comp.country;
        const club = clubsForDivision.find(c => c.name === comp.club);
        return club?.country || '-';
    };

    let displayedCount = 0;

    divisionKeys.forEach((divisionName, index) => {
        const competitors = divisions[divisionName];

        if (!Array.isArray(competitors)) {
            return; // Skip if not an array
        }

        if (hideEmpty && competitors.length === 0) {
            return;
        }

        displayedCount++;

        const sheet = document.createElement('div');
        sheet.className = 'division-sheet';

        const compId = (comp) => comp.id || comp._id || `${comp.firstName}_${comp.lastName}_${comp.dateOfBirth}`;
        let tableRows = competitors.map(comp => {
            const isPending = comp.approved === false;
            const pendingBadge = isPending ? ' <span style="background:#f59e0b;color:#fff;font-size:10px;padding:1px 5px;border-radius:8px;vertical-align:middle;">Pending</span>' : '';
            return `
            <tr style="${isPending ? 'opacity:0.7;' : ''}">
                <td>${comp.firstName || '?'} ${comp.lastName || '?'}${pendingBadge}</td>
                <td>${getDisplayAge(comp)}</td>
                <td>${comp.gender || '-'}</td>
                <td>${comp.weight != null ? comp.weight + ' ' + getTournamentWeightUnit() : '-'}</td>
                <td>${comp.rank || '-'}</td>
                <td>${comp.club || '-'}</td>
                <td>${getCompetitorCountry(comp)}</td>
                <td style="white-space:nowrap;">
                    <button class="btn btn-small" onclick="showMoveCompetitorModal('${_escapeHtml(divisionName)}','${compId(comp)}')" title="Move to another division">Move</button>
                    <button class="btn btn-small btn-secondary" onclick="showCopyCompetitorModal('${_escapeHtml(divisionName)}','${compId(comp)}')" title="Copy to another division" style="margin-left:4px;">Copy</button>
                    <button class="btn btn-small btn-danger" onclick="removeCompetitorFromDivision('${_escapeHtml(divisionName)}','${compId(comp)}')" title="Remove from this division" style="margin-left:4px;">Remove</button>
                </td>
            </tr>`;
        }).join('');

        const isUnassigned = divisionName === '__unassigned__';
        const displayName = isUnassigned ? 'Unassigned' : divisionName;
        const headerStyle = isUnassigned
            ? 'background:var(--warning,#f59e0b);color:#fff;'
            : '';
        sheet.innerHTML = `
            <div class="division-header" style="${headerStyle}">
                ${isUnassigned ? '⚠ ' : ''}${displayName} (${competitors.length} competitor${competitors.length !== 1 ? 's' : ''})
                ${isUnassigned ? '<span style="font-size:12px;font-weight:400;margin-left:8px;">These competitors did not match any division criteria — move them manually.</span>' : ''}
            </div>
            <div class="division-content">
                <table class="division-table">
                    <colgroup><col style="width:22%"><col style="width:6%"><col style="width:8%"><col style="width:9%"><col style="width:10%"><col style="width:20%"><col style="width:10%"><col style="width:15%"></colgroup>
                    <thead>
                        <tr>
                            <th>Name</th>
                            <th>Age</th>
                            <th>Gender</th>
                            <th>Weight</th>
                            <th>Rank</th>
                            <th>Dojo</th>
                            <th>Country</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        ${tableRows}
                    </tbody>
                </table>
            </div>
        `;
        container.appendChild(sheet);
    });


    if (displayedCount === 0 && hideEmpty) {
        container.innerHTML = '<p style="color: var(--text-secondary);">All divisions are empty. Uncheck "Show only divisions with competitors" to see all divisions.</p>';
    }

}

/* ── Move Competitor Between Divisions ────────────────── */
function showMoveCompetitorModal(fromDivision, competitorId) {
    const eventSelector = document.getElementById('division-event-selector');
    const eventId = eventSelector?.value;
    if (!eventId) return;

    const allDivisions = JSON.parse(_msGet(_scopedKey('divisions')) || '{}');
    const eventData = allDivisions[eventId];
    if (!eventData || !eventData.generated) return;

    const divisions = eventData.generated;
    const divisionKeys = Object.keys(divisions).sort();

    // Find the competitor
    const fromComps = divisions[fromDivision];
    if (!Array.isArray(fromComps)) return;
    const comp = fromComps.find(c => {
        const cid = c.id || c._id || `${c.firstName}_${c.lastName}_${c.dateOfBirth}`;
        return String(cid) === String(competitorId);
    });
    if (!comp) { showToast('Competitor not found', 'error'); return; }

    // Build target division options (exclude current)
    const otherDivs = divisionKeys.filter(d => d !== fromDivision);
    if (otherDivs.length === 0) { showToast('No other divisions to move to', 'error'); return; }

    const compName = `${comp.firstName || '?'} ${comp.lastName || '?'}`;

    // Create modal overlay
    let overlay = document.getElementById('move-comp-overlay');
    if (overlay) overlay.remove();
    overlay = document.createElement('div');
    overlay.id = 'move-comp-overlay';
    overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.6);z-index:10000;display:flex;align-items:center;justify-content:center;';
    overlay.innerHTML = `
        <div style="background:var(--bg-secondary,#1a1a24);border:1px solid var(--glass-border,#333);border-radius:12px;padding:24px;max-width:420px;width:90%;color:var(--text-primary,#fff);">
            <h3 style="margin:0 0 8px 0;font-size:16px;">Move Competitor</h3>
            <p style="margin:0 0 16px 0;font-size:14px;color:var(--text-secondary,#aaa);">
                Move <strong>${_escapeHtml(compName)}</strong> from <em>${_escapeHtml(fromDivision)}</em>
            </p>
            <div style="margin-bottom:16px;">
                <label style="display:block;margin-bottom:6px;font-size:13px;">Target Division</label>
                <select id="move-comp-target" class="form-input" style="width:100%;">
                    ${otherDivs.map(d => {
                        const cnt = (divisions[d] || []).length;
                        return `<option value="${_escapeHtml(d)}">${_escapeHtml(d)} (${cnt})</option>`;
                    }).join('')}
                </select>
            </div>
            <div style="display:flex;gap:10px;justify-content:flex-end;">
                <button class="btn btn-secondary" onclick="document.getElementById('move-comp-overlay').remove()">Cancel</button>
                <button class="btn btn-primary" onclick="executeCompetitorMove('${_escapeHtml(fromDivision)}','${competitorId}')">Move</button>
            </div>
        </div>
    `;
    document.body.appendChild(overlay);
    overlay.addEventListener('click', (e) => { if (e.target === overlay) overlay.remove(); });
}

function executeCompetitorMove(fromDivision, competitorId) {
    const target = document.getElementById('move-comp-target')?.value;
    if (!target) return;

    const eventSelector = document.getElementById('division-event-selector');
    const eventId = eventSelector?.value;
    if (!eventId) return;

    const allDivisions = JSON.parse(_msGet(_scopedKey('divisions')) || '{}');
    const eventData = allDivisions[eventId];
    if (!eventData || !eventData.generated) return;

    const divisions = eventData.generated;
    const fromComps = divisions[fromDivision];
    if (!Array.isArray(fromComps)) return;

    // Find and remove from source
    const idx = fromComps.findIndex(c => {
        const cid = c.id || c._id || `${c.firstName}_${c.lastName}_${c.dateOfBirth}`;
        return cid === competitorId;
    });
    if (idx === -1) { showToast('Competitor not found', 'error'); return; }
    const [moved] = fromComps.splice(idx, 1);

    // Add to target
    if (!Array.isArray(divisions[target])) divisions[target] = [];
    divisions[target].push(moved);

    // Save back and immediately sync to server — manual moves must be atomic
    _msSet(_scopedKey('divisions'), JSON.stringify(allDivisions));
    _syncDivisionsToServer().catch(e => console.warn('[divisions] move-competitor sync failed:', e.message));

    // Close modal and refresh
    const overlay = document.getElementById('move-comp-overlay');
    if (overlay) overlay.remove();

    showToast(`Moved ${moved.firstName} ${moved.lastName} → ${target}`, 'success');
    loadDivisions();
}

