// ── Badge Printing ─────────────────────────────────────────────────────────────
function _getBadgePrintCSS() {
    return `
        @page { size: letter portrait; margin: 0.4in; }
        * { box-sizing: border-box; margin: 0; padding: 0; }
        body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #f0f0f0; color: #111; }
        .badge-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 0.25in; }

        /* Card shell */
        .badge-card {
            width: 3.4in; height: 4.3in;
            border: 2px solid #111; border-radius: 12px;
            display: flex; flex-direction: column;
            page-break-inside: avoid; break-inside: avoid;
            overflow: hidden; background: #fff;
        }

        /* ── Role headline (top) ── */
        .badge-headline {
            padding: 14px 12px 12px;
            text-align: center;
            font-size: 1.15rem;
            font-weight: 900;
            letter-spacing: 0.06em;
            text-transform: uppercase;
            color: #111;
            border-bottom: 2px solid #e8e8e8;
            line-height: 1.2;
        }

        /* ── Body: photo + person info ── */
        .badge-body {
            flex: 1;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            padding: 14px 12px 10px;
            text-align: center;
            gap: 5px;
        }
        .badge-photo {
            width: 82px; height: 82px; border-radius: 50%;
            object-fit: cover; border: 2px solid #222;
            background: #ddd; margin-bottom: 8px;
        }
        .badge-photo-placeholder {
            width: 82px; height: 82px; border-radius: 50%;
            background: #ddd; display: flex; align-items: center;
            justify-content: center; font-size: 1.8rem; color: #aaa;
            margin-bottom: 8px;
        }
        .badge-name  { font-size: 0.95rem; font-weight: 700; line-height: 1.25; }
        .badge-level { font-size: 0.72rem; color: #555; margin-top: 1px; }
        .badge-dojo  { font-size: 0.72rem; color: #555; }

        /* ── QR + tournament name row ── */
        .badge-qr-row {
            display: flex;
            align-items: center;
            gap: 10px;
            padding: 10px 14px;
            border-top: 1px solid #e8e8e8;
        }
        .badge-qr { width: 54px; height: 54px; flex-shrink: 0; }
        .badge-tournament {
            flex: 1;
            font-size: 0.78rem;
            font-weight: 700;
            line-height: 1.35;
            color: #111;
        }

        /* ── Black footer with logo ── */
        .badge-footer-black {
            background: #111;
            -webkit-print-color-adjust: exact;
            print-color-adjust: exact;
            padding: 9px 14px;
            display: flex;
            justify-content: center;
            align-items: center;
        }
        .badge-logo { height: 26px; width: auto; }
    `;
}

function _generateBadgeCardHTML(person, roleLabel, tournamentName, memberId) {
    const fullName = `${person.firstName} ${person.lastName}`;
    // If member has a server ID (from tournament_members), encode machine-readable QR for scanner
    const qrPayload = (memberId || person.memberId)
        ? `checkin:member:${memberId || person.memberId}:${currentTournamentId || ''}`
        : `${fullName} | ${roleLabel} | ${tournamentName}`;
    const qrData   = encodeURIComponent(qrPayload);
    const qrSrc    = `https://api.qrserver.com/v1/create-qr-code/?size=80x80&data=${qrData}`;

    // Embed logo src directly — works in any popup/blob context
    const logoSrc = (typeof window !== 'undefined' && window.TAIKAI_LOGO)
        ? window.TAIKAI_LOGO
        : '/assets/taikai-logo.png';

    const photoHTML = person.photo
        ? `<img class="badge-photo" src="${person.photo}" alt="${fullName}">`
        : `<div class="badge-photo-placeholder">👤</div>`;

    return `<div class="badge-card">
        <!-- Role headline at top -->
        <div class="badge-headline">${roleLabel || 'Official'}</div>

        <!-- Photo + person info -->
        <div class="badge-body">
            ${photoHTML}
            <div class="badge-name">${fullName}</div>
            ${person.certificationLevel ? `<div class="badge-level">${person.certificationLevel}</div>` : ''}
            ${person.position           ? `<div class="badge-level">${person.position}</div>`           : ''}
            ${person.dojo ? `<div class="badge-dojo">${person.dojo}</div>` : ''}
        </div>

        <!-- QR + tournament name -->
        <div class="badge-qr-row">
            <img class="badge-qr" src="${qrSrc}" alt="QR">
            <div class="badge-tournament">${tournamentName}</div>
        </div>

        <!-- Black footer with Taikai logo -->
        <div class="badge-footer-black">
            <img class="badge-logo" src="${logoSrc}" alt="Taikai">
        </div>
    </div>`;
}

function _openBadgePrintWindow(cardsHTML, tournamentName) {
    const html = `<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>Badges \u2014 ${tournamentName}</title>
    <style>${_getBadgePrintCSS()}</style>
</head>
<body>
    <div class="badge-grid">${cardsHTML}</div>
    <script>
        window.addEventListener('load', function() {
            setTimeout(function() { window.print(); }, 800);
        });
    <\/script>
</body>
</html>`;

    // Use Blob URL — avoids document.write limits and encoding issues
    try {
        const blob = new Blob([html], { type: 'text/html; charset=utf-8' });
        const blobUrl = URL.createObjectURL(blob);
        const w = window.open(blobUrl, '_blank', 'width=900,height=700');
        if (!w) { showToast('Allow popups to print badges', 'warning'); return; }
        setTimeout(() => URL.revokeObjectURL(blobUrl), 10000);
    } catch (err) {
        console.error('Badge print error:', err);
        showToast('Could not open print window', 'error');
    }
}

function _getTournamentName() {
    const tournaments = db.load ? db.load('tournaments') : [];
    const t = (tournaments || []).find(t => t.id === currentTournamentId);
    return t ? t.name : 'Tournament';
}

function printOfficialBadge(id) {
    const official = db.load('officials').find(o => o.id == id);
    if (!official) return;
    const card = _generateBadgeCardHTML(official, 'Official', _getTournamentName());
    _openBadgePrintWindow(card, _getTournamentName());
}

function printAllOfficialBadges() {
    const officials = db.load('officials').filter(o => !currentTournamentId || o.tournamentId === currentTournamentId);
    if (officials.length === 0) { showToast('No officials to print', 'warning'); return; }
    const tName = _getTournamentName();
    const cards = officials.map(o => _generateBadgeCardHTML(o, 'Official', tName)).join('');
    _openBadgePrintWindow(cards, tName);
}

function printStaffBadge(id) {
    const member = db.load('staffMembers').find(s => s.id == id);
    if (!member) return;
    const card = _generateBadgeCardHTML(member, 'Staff', _getTournamentName());
    _openBadgePrintWindow(card, _getTournamentName());
}

function printAllStaffBadges() {
    const members = db.load('staffMembers').filter(s => !currentTournamentId || s.tournamentId === currentTournamentId);
    if (members.length === 0) { showToast('No staff to print', 'warning'); return; }
    const tName = _getTournamentName();
    const cards = members.map(s => _generateBadgeCardHTML(s, 'Staff', tName)).join('');
    _openBadgePrintWindow(cards, tName);
}

