// ═══════════════════════════════════════════════════════════════════════════════
// CHECK-IN SYSTEM
// ═══════════════════════════════════════════════════════════════════════════════

let _checkinScanner      = null;   // Html5Qrcode instance
let _checkinData         = [];     // loaded competitor registrations (from registrations table)
let _checkinDirectorData = [];     // loaded director-added competitors (from director_competitors JSONB)
let _checkinMembers      = [];     // loaded approved members
let _checkinTab          = 'competitors'; // active tab

/**
 * Compute combined check-in stats covering both registered and director-added competitors.
 */
function _computeCheckinStats() {
    const total     = _checkinData.length + _checkinDirectorData.length;
    const checkedIn = _checkinData.filter(c => c.checkin_id).length
                    + _checkinDirectorData.filter(c => c.checkedIn).length;
    const onMat     = _checkinData.filter(c => c.mat_called_at).length;
    const missing   = total - checkedIn;
    return { total, checked_in: checkedIn, missing, on_mat: onMat };
}

async function _refreshCheckinStatus() {
    if (!currentTournamentId) return;
    try {
        const res = await fetch(`/api/tournaments/${currentTournamentId}/checkin`, { credentials: 'include' });
        if (res.ok) {
            const data = await res.json();
            _checkinData = data.competitors || [];
            _renderCheckinStats(_computeCheckinStats());
            _renderCheckinList();
            // Update "last refreshed" timestamp
            const ts = document.getElementById('ci-last-updated');
            if (ts) ts.textContent = `Updated ${new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}`;
        }
    } catch(e) { /* silent — next poll will retry */ }
}

async function loadCheckinView() {
    if (!currentTournamentId) {
        document.getElementById('ci-list-competitors').innerHTML = '<p class="hint" style="padding:16px;">No tournament selected.</p>';
        return;
    }

    // Restart auto-refresh polling (20 s) whenever the check-in view opens
    clearInterval(_checkinPollInterval);
    _checkinPollInterval = setInterval(_refreshCheckinStatus, 20000);

    // Reset stale state from any previous tournament before loading fresh data
    _checkinData = [];
    _checkinDirectorData = [];
    _checkinMembers = [];
    // Reset detail panel
    document.getElementById('checkin-detail-panel').style.display = 'none';

    // Fetch registered competitors (from checkins table)
    try {
        const res = await fetch(`/api/tournaments/${currentTournamentId}/checkin`, { credentials: 'include' });
        if (res.ok) {
            const data = await res.json();
            _checkinData = data.competitors || [];
        }
    } catch(e) {
        _checkinData = [];
    }

    // Fetch director-added competitors (from director_competitors JSONB)
    try {
        const res = await fetch(`/api/tournaments/${currentTournamentId}/competitors`, { credentials: 'include' });
        if (res.ok) {
            const data = await res.json();
            _checkinDirectorData = data.competitors || [];
        }
    } catch(e) {
        _checkinDirectorData = [];
    }

    // Fetch approved members (self-registered via public page)
    try {
        const res = await fetch(`/api/tournament-members/${currentTournamentId}`, { credentials: 'include' });
        if (res.ok) {
            const data = await res.json();
            _checkinMembers = (data.members || []).filter(m => m.status === 'approved' && ['judge','staff','coach'].includes(m.role));
        }
    } catch(e) {
        _checkinMembers = [];
    }

    // Also include director-added officials (not in tournament_members table)
    // Deduplicate by name to avoid showing duplicates when the same person self-registered AND was added manually.
    const dirOfficials = db.load('officials').filter(o => !currentTournamentId || o.tournamentId === currentTournamentId);
    if (dirOfficials.length > 0) {
        const memberNames = new Set(_checkinMembers.map(m => `${m.first_name} ${m.last_name}`.toLowerCase().trim()));
        for (const o of dirOfficials) {
            const fullName = `${o.firstName || ''} ${o.lastName || ''}`.toLowerCase().trim();
            if (fullName && !memberNames.has(fullName)) {
                _checkinMembers.push({
                    id: `director_${o.id}`,
                    first_name: o.firstName || '',
                    last_name: o.lastName || '',
                    role: 'judge',
                    staff_role: null,
                    email: o.email || null,
                    checked_in_at: null,
                    _director_added: true,
                });
            }
        }
    }

    _renderCheckinStats(_computeCheckinStats());
    _renderCheckinList();
}

function _renderCheckinStats(stats) {
    const set = (id, val) => { const el = document.getElementById(id); if (el) el.textContent = val ?? '—'; };
    set('ci-stat-total', stats.total);
    set('ci-stat-checked', stats.checked_in);
    set('ci-stat-missing', stats.missing);
    set('ci-stat-mat', stats.on_mat);
}

function _renderCheckinList() {
    const search = (document.getElementById('ci-search')?.value || '').toLowerCase();
    // Competitors (registered + director-added)
    const compList = document.getElementById('ci-list-competitors');
    if (compList) {
        // Registered competitors (from registrations table)
        const filteredReg = _checkinData.filter(c => {
            const name = `${c.first_name} ${c.last_name}`.toLowerCase();
            return !search || name.includes(search);
        });
        // Director-added competitors only — registration-sourced ones are already
        // shown in filteredReg from _checkinData, so exclude them here to prevent
        // duplicates when the UNION query includes both sources.
        const filteredDir = _checkinDirectorData.filter(c => {
            if (c.source !== 'director') return false;
            const name = `${c.firstName} ${c.lastName}`.toLowerCase();
            return !search || name.includes(search);
        });

        const regHTML = filteredReg.map(c => {
            const checked = !!c.checkin_id;
            return `<div class="checkin-list-item" onclick="renderCheckinDetail('${c.registration_id}', 'competitor')">
                <span>${_escapeHtml(c.first_name)} ${_escapeHtml(c.last_name)}<br><small style="color:var(--text-secondary);">${_escapeHtml(c.academy_name || '')}</small></span>
                <span class="${checked ? 'ci-checked-badge' : 'ci-missing-badge'}">${checked ? '✓ In' : 'Missing'}</span>
            </div>`;
        }).join('');

        const dirHTML = filteredDir.map(c => {
            const checked = !!c.checkedIn;
            return `<div class="checkin-list-item" onclick="renderDirectorCompetitorCheckinDetail('${c.id}')">
                <span>${_escapeHtml(c.firstName)} ${_escapeHtml(c.lastName)}<br><small style="color:var(--text-secondary);">${_escapeHtml(c.club || '')}</small></span>
                <span class="${checked ? 'ci-checked-badge' : 'ci-missing-badge'}">${checked ? '✓ In' : 'Missing'}</span>
            </div>`;
        }).join('');

        const totalFiltered = filteredReg.length + filteredDir.length;
        compList.innerHTML = totalFiltered === 0
            ? '<p class="hint" style="padding:16px;">No competitors found.</p>'
            : regHTML + dirHTML;
    }
    // Members
    const memList = document.getElementById('ci-list-members');
    if (memList) {
        const filtered = _checkinMembers.filter(m => {
            const name = `${m.first_name} ${m.last_name}`.toLowerCase();
            return !search || name.includes(search);
        });
        memList.innerHTML = filtered.length === 0
            ? '<p class="hint" style="padding:16px;">No personnel found.</p>'
            : filtered.map(m => {
                const checked = !!m.checked_in_at;
                const roleLabel = m._director_added ? 'Official (Director Added)' : m.role === 'judge' ? 'Official' : m.role === 'coach' ? 'Coach' : 'Staff';
                return `<div class="checkin-list-item" onclick="renderMemberCheckinDetail('${m.id}')">
                    <span>${_escapeHtml(m.first_name)} ${_escapeHtml(m.last_name)}<br><small style="color:var(--text-secondary);">${_escapeHtml(roleLabel)}${m.staff_role ? ' · ' + _escapeHtml(m.staff_role) : ''}</small></span>
                    <span class="${m._director_added ? 'ci-missing-badge' : checked ? 'ci-checked-badge' : 'ci-missing-badge'}" style="${m._director_added ? 'opacity:0.5;' : ''}">${m._director_added ? 'Director' : checked ? '✓ Present' : 'Not In'}</span>
                </div>`;
            }).join('');
    }
}

function filterCheckinList() {
    _renderCheckinList();
}

function switchCheckinTab(tab) {
    _checkinTab = tab;
    const compList = document.getElementById('ci-list-competitors');
    const memList  = document.getElementById('ci-list-members');
    const tComp    = document.getElementById('ci-tab-competitors');
    const tMem     = document.getElementById('ci-tab-members');
    if (tab === 'competitors') {
        compList.style.display = '';
        memList.style.display  = 'none';
        if (tComp) { tComp.style.borderBottomColor = 'var(--accent)'; tComp.style.color = 'var(--text-primary)'; }
        if (tMem)  { tMem.style.borderBottomColor  = 'transparent';   tMem.style.color  = 'var(--text-secondary)'; }
    } else {
        compList.style.display = 'none';
        memList.style.display  = '';
        if (tMem)  { tMem.style.borderBottomColor  = 'var(--accent)'; tMem.style.color  = 'var(--text-primary)'; }
        if (tComp) { tComp.style.borderBottomColor = 'transparent';   tComp.style.color = 'var(--text-secondary)'; }
    }
}

// ── QR Scanner ──────────────────────────────────────────────────────────────

function startQRScanner() {
    if (!window.Html5Qrcode) {
        showToast('QR scanner library not loaded yet — please wait a moment and try again', 'warning');
        return;
    }
    if (_checkinScanner) { stopQRScanner(); }
    _checkinScanner = new Html5Qrcode('qr-reader');
    _checkinScanner.start(
        { facingMode: 'environment' },
        { fps: 10, qrbox: { width: 250, height: 250 } },
        (decodedText) => { handleQRScan(decodedText); },
        () => {}
    ).then(() => {
        document.getElementById('ci-start-scan-btn').style.display = 'none';
        document.getElementById('ci-stop-scan-btn').style.display  = '';
    }).catch(err => {
        showToast(`Camera error: ${err}`, 'error');
        _checkinScanner = null;
    });
}

function stopQRScanner() {
    if (_checkinScanner) {
        _checkinScanner.stop().catch(() => {});
        _checkinScanner.clear();
        _checkinScanner = null;
    }
    document.getElementById('ci-start-scan-btn').style.display = '';
    document.getElementById('ci-stop-scan-btn').style.display  = 'none';
}

function handleQRScan(text) {
    // Pause scanner briefly to avoid double-scans
    if (_checkinScanner) { _checkinScanner.pause(true); setTimeout(() => { if (_checkinScanner) _checkinScanner.resume(); }, 3000); }

    // Parse QR formats
    if (text.startsWith('checkin:registrant:')) {
        const parts = text.split(':');
        const rid = parts[2];
        renderCheckinDetail(rid, 'competitor');
        return;
    }
    if (text.startsWith('checkin:member:')) {
        const parts = text.split(':');
        const mid = parts[2];
        renderMemberCheckinDetail(mid);
        return;
    }
    // Fallback: fuzzy name search (registered competitors, then director-added, then members)
    const lower = text.toLowerCase();
    const match = _checkinData.find(c => `${c.first_name} ${c.last_name}`.toLowerCase().includes(lower));
    if (match) { renderCheckinDetail(match.registration_id, 'competitor'); return; }
    const dirMatch = _checkinDirectorData.find(c => `${c.firstName} ${c.lastName}`.toLowerCase().includes(lower));
    if (dirMatch) { renderDirectorCompetitorCheckinDetail(dirMatch.id); return; }
    const mMatch = _checkinMembers.find(m => `${m.first_name} ${m.last_name}`.toLowerCase().includes(lower));
    if (mMatch) { renderMemberCheckinDetail(mMatch.id); return; }
    showToast('QR code not recognized — try searching by name', 'warning');
}

