async function saveTournamentEdit() {
    if (!currentTournamentId) return;

    const name = document.getElementById('ti-edit-name')?.value.trim();
    const date = document.getElementById('ti-edit-date')?.value || undefined;
    const location = document.getElementById('ti-edit-location')?.value.trim();
    const sanctioningBody = document.getElementById('ti-edit-sanctioning')?.value || undefined;
    const timezone = document.getElementById('ti-edit-timezone')?.value || undefined;
    const currency = document.getElementById('ti-edit-currency')?.value || undefined;
    const weightUnit = document.getElementById('ti-edit-weight-unit')?.value || undefined;
    const published = document.getElementById('ti-edit-published')?.value === 'true';
    const allowPayLater = document.getElementById('ti-edit-allow-pay-later')?.checked || false;

    // Merge allowPayLater into existing registration_settings
    const tournaments = db.load('tournaments');
    const existingT = tournaments.find(t => String(t.id) === String(currentTournamentId));
    const existingRegSettings = existingT?.registration_settings || {};
    const registrationSettings = { ...existingRegSettings, allowPayLater };

    if (!name) { showToast('Tournament name is required', 'error'); return; }

    const saveBtn = document.querySelector('#tournament-info-content .btn-primary');
    if (saveBtn) { saveBtn.disabled = true; saveBtn.textContent = 'Saving…'; }

    try {
        const res = await fetch(`/api/tournaments/${currentTournamentId}`, {
            method: 'PUT',
            credentials: 'include',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ name, date, location, sanctioningBody, timezone, currency, weightUnit, published, registrationSettings }),
        });
        if (!res.ok) {
            const data = await res.json().catch(() => ({}));
            throw new Error(data.error || 'Failed to save changes');
        }
        const { tournament: saved } = await res.json();

        // Update in-memory store with server-confirmed values
        const savedTournaments = db.load('tournaments');
        const idx = savedTournaments.findIndex(t => String(t.id) === String(currentTournamentId));
        if (idx >= 0) {
            savedTournaments[idx] = {
                ...savedTournaments[idx],
                name: saved.name,
                date: saved.date,
                location: saved.location,
                sanctioningBody: saved.sanctioning_body,
                timezone: saved.timezone,
                currency: saved.currency,
                weightUnit: saved.weight_unit,
                weight_unit: saved.weight_unit,
                published: saved.published,
                registration_settings: saved.registration_settings || {},
            };
            db.save('tournaments', savedTournaments);
        }

        // Refresh the tournament selector in case the name changed
        loadTournamentSelector();

        showToast('Tournament updated successfully', 'success');
        loadTournamentInfoView();
    } catch (err) {
        showToast(err.message || 'Failed to save', 'error');
        if (saveBtn) { saveBtn.disabled = false; saveBtn.textContent = 'Save Changes'; }
    }
}

async function toggleRegistrationOpen(currentlyOpen) {
    if (!currentTournamentId) return;
    const newVal = !currentlyOpen;

    // Gate: require every non-default event to have a division tree before opening
    if (newVal) {
        const eventTypes = db.load('eventTypes') || [];
        const nonDefault = eventTypes.filter(et => !et.isDefault);
        const missing = nonDefault.filter(et =>
            _msGet(_scopedKey(`divTreeBuilt_${et.id}`)) !== '1'
        );
        if (missing.length > 0) {
            const names = missing.map(e => e.name).join(', ');
            alert(
                `Cannot open registration yet.\n\n` +
                `The following event${missing.length !== 1 ? 's are' : ' is'} missing a division tree:\n${names}\n\n` +
                `Go to Divisions \u2192 Edit Divisions to build them first.`
            );
            return;
        }
    }

    const label = newVal ? 'open' : 'close';
    if (!confirm(`Are you sure you want to ${label} registration for this tournament?`)) return;

    try {
        const res = await fetch(`/api/tournaments/${currentTournamentId}`, {
            method: 'PATCH',
            credentials: 'include',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ registrationOpen: newVal }),
        });
        if (!res.ok) {
            const data = await res.json().catch(() => ({}));
            throw new Error(data.error || 'Failed to update registration status');
        }
        showToast(`Registration is now ${newVal ? 'open' : 'closed'}`, 'success');
        // Re-render with updated state
        const tournaments = db.load('tournaments');
        const t = tournaments.find(t => String(t.id) === String(currentTournamentId));
        if (t) _renderTournamentInfoContent(t, newVal);
    } catch (err) {
        showToast(err.message || 'Failed to update', 'error');
    }
}

function loadCertificatesView() {
    const template = JSON.parse(_msGet(_scopedKey('certificateTemplate')) || 'null');
    if (template && template.data) {
        const previewImg = document.getElementById('certificate-preview-img');
        const previewDiv = document.getElementById('certificate-template-preview');
        if (previewImg && previewDiv) {
            previewImg.src = template.data;
            previewDiv.style.display = 'block';
            // Init chips once image dimensions are known
            if (previewImg.complete && previewImg.naturalWidth) {
                _initCertDragUI();
            } else {
                previewImg.onload = _initCertDragUI;
            }
        }
        const mergePanel = document.getElementById('merge-tag-config-panel');
        if (mergePanel) mergePanel.style.display = 'block';
        loadMergeTagEditors();
        setTimeout(_initCertDragUI, 150); // fallback if already cached
    }
}

/** Render draggable {{Tag}} chips over the certificate preview image.
 *  Dragging a chip updates the X/Y number inputs in real time. */
function _initCertDragUI() {
    const zone = document.getElementById('cert-drag-zone');
    const img  = document.getElementById('certificate-preview-img');
    if (!zone || !img || !img.naturalWidth) return;

    const SHORT    = { name:'Name', place:'Place', division:'Division', tournament:'Tournament', date:'Date', club:'Club' };
    const tagNames = ['name', 'place', 'division', 'tournament', 'date', 'club'];

    // Remove stale chips
    zone.querySelectorAll('.cert-tag-chip').forEach(el => el.remove());

    for (const tag of tagNames) {
        const enabledEl = document.getElementById(`tag-${tag}-enabled`);
        if (!enabledEl?.checked) continue;

        const xPct = parseFloat(document.getElementById(`tag-${tag}-x`)?.value) || 50;
        const yPct = parseFloat(document.getElementById(`tag-${tag}-y`)?.value) || 50;

        const chip = document.createElement('div');
        chip.className = 'cert-tag-chip';
        chip.dataset.tag = tag;
        chip.textContent = `{{${SHORT[tag]}}}`;
        chip.style.left = `${xPct}%`;
        chip.style.top  = `${yPct}%`;

        chip.addEventListener('pointerdown', e => {
            e.preventDefault();
            chip.setPointerCapture(e.pointerId);
            chip.classList.add('dragging');

            const onMove = ev => {
                const rect = img.getBoundingClientRect();
                const x = Math.max(0, Math.min(100, ((ev.clientX - rect.left) / rect.width)  * 100));
                const y = Math.max(0, Math.min(100, ((ev.clientY - rect.top)  / rect.height) * 100));
                chip.style.left = `${x}%`;
                chip.style.top  = `${y}%`;
            };

            const onUp = ev => {
                chip.classList.remove('dragging');
                chip.removeEventListener('pointermove', onMove);
                chip.removeEventListener('pointerup',   onUp);

                const rect = img.getBoundingClientRect();
                const x = Math.round(Math.max(0, Math.min(100, ((ev.clientX - rect.left) / rect.width)  * 100)) * 10) / 10;
                const y = Math.round(Math.max(0, Math.min(100, ((ev.clientY - rect.top)  / rect.height) * 100)) * 10) / 10;

                const xEl = document.getElementById(`tag-${tag}-x`);
                const yEl = document.getElementById(`tag-${tag}-y`);
                if (xEl) xEl.value = x;
                if (yEl) yEl.value = y;
                updateCertificatePreview();
            };

            chip.addEventListener('pointermove', onMove);
            chip.addEventListener('pointerup',   onUp);
        });

        zone.appendChild(chip);
    }
}

function loadSettingsEvents() {
    const container = document.getElementById('settings-events-list');
    if (!container) return;

    const eventTypes = db.load('eventTypes');
    if (!eventTypes || eventTypes.length === 0) {
        container.innerHTML = '<p class="hint">No event types configured for this tournament.</p>';
        return;
    }

    container.innerHTML = eventTypes.map(ev => `
        <div style="display: flex; align-items: center; justify-content: space-between; padding: 10px 12px; background: var(--glass-bg); border: 1px solid var(--glass-border); border-radius: 8px; margin-bottom: 8px;">
            <div>
                <strong>${ev.name}</strong>
                ${ev.eventType ? `<span style="margin-left: 8px; opacity: 0.6; font-size: 0.85em;">${ev.eventType}</span>` : ''}
            </div>
            <button class="btn btn-small btn-danger" onclick="deleteEventFromServer(${ev.id})">Delete</button>
        </div>
    `).join('');
}

async function deleteEventFromServer(eventId) {
    if (!currentTournamentId) {
        showMessage('No tournament selected', 'error');
        return;
    }
    if (!confirm('Are you sure you want to delete this event type? This will also remove its divisions and brackets.')) {
        return;
    }

    try {
        const res = await fetch(`/api/tournaments/${currentTournamentId}/events/${eventId}`, {
            method: 'DELETE',
            credentials: 'include',
        });

        if (!res.ok) {
            const data = await res.json().catch(() => ({}));
            throw new Error(data.error || 'Failed to delete event');
        }

        // Remove from localStorage
        db.delete('eventTypes', eventId);

        // Remove associated divisions
        const allDivisions = JSON.parse(_msGet(_scopedKey('divisions')) || '{}');
        delete allDivisions[eventId];
        _msSet(_scopedKey('divisions'), JSON.stringify(allDivisions));

        // Refresh UI
        loadSettingsEvents();
        loadEventTypes();
        loadEventTypeSelector();
        showMessage('Event deleted successfully');
    } catch (err) {
        showMessage(err.message, 'error');
    }
}

async function deleteTournamentFromServer() {
    if (!currentTournamentId) {
        showMessage('No tournament selected', 'error');
        return;
    }

    // Look up tournament name for the confirmation dialog
    const tournaments = db.load('tournaments');
    const tournament = tournaments.find(t => String(t.id) === String(currentTournamentId));
    const tournamentName = tournament ? tournament.name : 'this tournament';

    if (!confirm(`Are you sure you want to permanently delete "${tournamentName}"?\n\nThis will remove all events, registrations, and brackets. This cannot be undone.`)) {
        return;
    }

    try {
        const res = await fetch(`/api/tournaments/${currentTournamentId}`, {
            method: 'DELETE',
            credentials: 'include',
        });

        // 404 means it's already gone from the server — still clean up locally
        if (!res.ok && res.status !== 404) {
            const data = await res.json().catch(() => ({}));
            throw new Error(data.error || 'Failed to delete tournament');
        }

        // Clear scoped localStorage keys
        _msRemove(_scopedKey('eventTypes'));
        _msRemove(_scopedKey('divisions'));
        _msRemove(_scopedKey('scoreboardConfig'));

        // Remove from the in-memory tournaments array so it disappears from dropdown
        const remaining = tournaments.filter(t => String(t.id) !== String(currentTournamentId));
        _msSet('tournaments', JSON.stringify(remaining));

        currentTournamentId = null;

        // Update UI immediately
        loadTournamentSelector();
        document.getElementById('main-nav').classList.add('hidden');
        const nameEl = document.getElementById('delete-tournament-name');
        if (nameEl) nameEl.textContent = '';

        showToast(`Tournament "${tournamentName}" deleted`, 'success');

        // Stay on page if there are more tournaments to delete, otherwise redirect
        const leftover = JSON.parse(_msGet('tournaments') || '[]');
        if (leftover.length === 0) {
            setTimeout(() => {
                window.location.href = '/account.html#tournaments';
            }, 1200);
        }
    } catch (err) {
        showToast(err.message || 'Failed to delete tournament', 'error');
    }
}

async function cloneTournamentFromManage() {
    if (!currentTournamentId) {
        showToast('No tournament selected', 'error');
        return;
    }
    if (!confirm('Clone this tournament? A new draft copy will be created with all events, pricing periods, and staff roles.')) return;

    const btn = document.getElementById('clone-tournament-btn');
    if (btn) { btn.disabled = true; btn.textContent = 'Cloning...'; }

    try {
        const res = await fetch(`/api/tournaments/${currentTournamentId}/clone`, {
            method: 'POST',
            credentials: 'include',
        });
        if (!res.ok) {
            const data = await res.json().catch(() => ({}));
            throw new Error(data.error || 'Failed to clone tournament');
        }
        const data = await res.json();
        showToast('Tournament cloned successfully!', 'success');
        if (data.tournament && data.tournament.id) {
            setTimeout(() => {
                window.location.href = `/director/tournaments/${data.tournament.id}/manage`;
            }, 1000);
        }
    } catch (err) {
        showToast(err.message || 'Failed to clone tournament', 'error');
        if (btn) { btn.disabled = false; btn.textContent = 'Clone This Tournament'; }
    }
}

function previewCertificateTemplate() {
    const fileInput = document.getElementById('settings-certificate-template');
    if (!fileInput || !fileInput.files || fileInput.files.length === 0) return;

    const reader = new FileReader();
    reader.onload = function(e) {
        const previewImg = document.getElementById('certificate-preview-img');
        const previewDiv = document.getElementById('certificate-template-preview');
        previewImg.src = e.target.result;
        previewDiv.style.display = 'block';
        document.getElementById('merge-tag-config-panel').style.display = 'block';
        loadMergeTagEditors();
    };
    reader.readAsDataURL(fileInput.files[0]);
}

function clearCertificateTemplate() {
    _msRemove(_scopedKey('certificateTemplate'));
    const previewDiv = document.getElementById('certificate-template-preview');
    if (previewDiv) previewDiv.style.display = 'none';
    document.getElementById('merge-tag-config-panel').style.display = 'none';
    document.getElementById('certificate-live-preview-panel').style.display = 'none';
    const fileInput = document.getElementById('settings-certificate-template');
    if (fileInput) fileInput.value = '';
    showMessage('Certificate template removed');
}

function saveCertificateTemplate() {
    const fileInput = document.getElementById('settings-certificate-template') || document.getElementById('certificate-template');

    if (!fileInput || !fileInput.files || fileInput.files.length === 0) {
        showMessage('Please select a certificate template file', 'error');
        return;
    }

    const file = fileInput.files[0];
    const reader = new FileReader();

    reader.onload = function(e) {
        const template = {
            fileName: file.name,
            fileType: file.type,
            data: e.target.result,
            uploadedAt: new Date().toISOString()
        };

        _msSet(_scopedKey('certificateTemplate'), JSON.stringify(template));

        // Show merge tag config
        document.getElementById('merge-tag-config-panel').style.display = 'block';
        loadMergeTagEditors();

        // Show image and init drag chips
        const previewImg = document.getElementById('certificate-preview-img');
        const previewDiv = document.getElementById('certificate-template-preview');
        if (previewImg && previewDiv) {
            previewImg.src = template.data;
            previewDiv.style.display = 'block';
            previewImg.onload = _initCertDragUI;
        }

        // Auto-upload to server so the template survives page reloads.
        // _msData is in-memory only — without a server copy the template is
        // lost as soon as the page is refreshed.
        if (currentTournamentId) {
            const statusEl = document.getElementById('cert-sync-status');
            if (statusEl) statusEl.textContent = 'Saving to server…';

            const formData = new FormData();
            formData.append('template', file);

            fetch(`/api/tournaments/${currentTournamentId}/certificate-template`, {
                method: 'POST',
                credentials: 'include',
                body: formData,
            })
            .then(async res => {
                if (!res.ok) {
                    const d = await res.json().catch(() => ({}));
                    throw new Error(d.error || 'Upload failed');
                }
                if (statusEl) statusEl.textContent = 'Template saved & synced to server.';
                showMessage('Certificate template saved & uploaded to server!');
                // Also sync the merge-tag config if already configured
                syncCertificateConfigToServerSilent().catch(() => {});
            })
            .catch(err => {
                if (statusEl) statusEl.textContent = 'Saved locally (server sync failed: ' + err.message + ')';
                showMessage('Certificate template saved locally. Server sync failed: ' + err.message, 'warning');
            });
        } else {
            showMessage('Certificate template saved successfully!');
        }
    };

    reader.readAsDataURL(file);
}

